/// Previously used to look up import/export/symbol names from the Survey.
/// Since Survey no longer holds the full BinaryImage, this always returns None.
/// Callers should query SQLite for symbol information instead.
fn persist_binary_imports_on_conn(
    conn: &Connection,
    binary_id: &str,
    imports: &[revx_core::Import],
) -> Result<()> {
    if imports.is_empty() {
        return Ok(());
    }
    const CHUNK: usize = 8000;
    for chunk in imports.chunks(CHUNK) {
        let mut sql = String::with_capacity(80 + chunk.len() * 28);
        sql.push_str("INSERT INTO binary_imports(binary_id, name, address, library) VALUES");
        let mut params_vec: Vec<Box<dyn rusqlite::types::ToSql>> =
            Vec::with_capacity(1 + chunk.len() * 3);
        params_vec.push(Box::new(binary_id));
        let mut next_param = 2usize;
        for (i, import) in chunk.iter().enumerate() {
            if i > 0 {
                sql.push(',');
            }
            sql.push_str("(?1,?");
            sql.push_str(&next_param.to_string());
            sql.push_str(",?");
            sql.push_str(&(next_param + 1).to_string());
            sql.push_str(",?");
            sql.push_str(&(next_param + 2).to_string());
            sql.push(')');
            next_param += 3;
            params_vec.push(Box::new(import.name.as_str()));
            params_vec.push(Box::new(import.address.map(|v| v as i64)));
            params_vec.push(Box::new(import.library.as_deref()));
        }
        let param_refs: Vec<&dyn rusqlite::types::ToSql> =
            params_vec.iter().map(|p| p.as_ref()).collect();
        conn.execute(&sql, param_refs.as_slice())?;
    }
    Ok(())
}


fn function_range_for_address<'a>(
    ranges: &'a [(u64, u64, String)],
    address: u64,
) -> Option<&'a (u64, u64, String)> {
    let index = ranges.partition_point(|(start, _, _)| *start <= address);
    if index == 0 {
        return None;
    }
    let candidate = &ranges[index - 1];
    (address >= candidate.0 && address < candidate.1).then_some(candidate)
}

fn map_evidence_row(row: &rusqlite::Row<'_>) -> rusqlite::Result<Evidence> {
    Ok(Evidence {
        id: row.get(0)?,
        subject: row.get(1)?,
        kind: row.get(2)?,
        summary: row.get(3)?,
        details: serde_json::from_str::<serde_json::Value>(&row.get::<_, String>(4)?)
            .unwrap_or(serde_json::Value::Null),
        provenance: serde_json::from_str(&row.get::<_, String>(5)?).unwrap_or_default(),
    })
}

fn evidence_search_predicate() -> &'static str {
    "id LIKE ?1 OR subject LIKE ?1 OR kind LIKE ?1 OR summary LIKE ?1 OR details_json LIKE ?1 OR provenance_json LIKE ?1"
}

fn map_object_row(row: &rusqlite::Row<'_>) -> rusqlite::Result<UniversalObject> {
    Ok(UniversalObject {
        id: row.get(0)?,
        path: row.get(1)?,
        display_name: row.get(2)?,
        kind: serde_json::from_str(&row.get::<_, String>(3)?).unwrap_or(ObjectKind::Unknown),
        format: row.get(4)?,
        size: row.get::<_, i64>(5)? as u64,
        hash_blake3: row.get(6)?,
        media_type: row.get(7)?,
        entropy: row.get(8)?,
        depth: row.get::<_, i64>(9)? as usize,
        flags: serde_json::from_str(&row.get::<_, String>(10)?).unwrap_or_default(),
        metadata: serde_json::from_str(&row.get::<_, String>(11)?)
            .unwrap_or(serde_json::Value::Null),
        analyses: serde_json::from_str(&row.get::<_, String>(12)?).unwrap_or_default(),
        evidence_ids: serde_json::from_str(&row.get::<_, String>(13)?).unwrap_or_default(),
    })
}

fn map_object_hit_row(row: &rusqlite::Row<'_>) -> rusqlite::Result<ObjectSearchHit> {
    let analyses: Vec<ObjectAnalysisSummary> =
        serde_json::from_str(&row.get::<_, String>(8)?).unwrap_or_default();
    let mut evidence_ids: Vec<String> =
        serde_json::from_str(&row.get::<_, String>(9)?).unwrap_or_default();
    for analysis in &analyses {
        evidence_ids.extend(analysis.evidence_ids.iter().cloned());
    }
    evidence_ids.sort();
    evidence_ids.dedup();
    Ok(ObjectSearchHit {
        id: row.get(0)?,
        path: row.get(1)?,
        display_name: row.get(2)?,
        kind: serde_json::from_str(&row.get::<_, String>(3)?).unwrap_or(ObjectKind::Unknown),
        format: row.get(4)?,
        size: row.get::<_, i64>(5)? as u64,
        hash_blake3: row.get(6)?,
        flags: serde_json::from_str(&row.get::<_, String>(7)?).unwrap_or_default(),
        analyzer_names: analyses
            .into_iter()
            .map(|analysis| analysis.analyzer)
            .collect(),
        evidence_ids,
    })
}

fn map_object_edge_record_row(row: &rusqlite::Row<'_>) -> rusqlite::Result<ObjectEdgeRecord> {
    Ok(ObjectEdgeRecord {
        graph_root_id: row.get(0)?,
        edge: ObjectEdge {
            from: row.get(1)?,
            to: row.get(2)?,
            kind: serde_json::from_str(&row.get::<_, String>(3)?)
                .unwrap_or(ObjectEdgeKind::Contains),
            metadata: serde_json::from_str(&row.get::<_, String>(4)?)
                .unwrap_or(serde_json::Value::Null),
        },
    })
}

struct EvidenceGraphBuilder {
    limit: usize,
    nodes: BTreeMap<String, EvidenceGraphNode>,
    edges: BTreeMap<String, EvidenceGraphEdge>,
    evidence_ids: BTreeSet<String>,
}

impl EvidenceGraphBuilder {
    fn new(limit: usize) -> Self {
        Self {
            limit,
            nodes: BTreeMap::new(),
            edges: BTreeMap::new(),
            evidence_ids: BTreeSet::new(),
        }
    }

    fn has_node_room(&self) -> bool {
        self.nodes.len() < self.limit
    }

    fn has_existing_node(&self, id: &str) -> bool {
        self.nodes.contains_key(id)
    }

    fn add_node(&mut self, node: EvidenceGraphNode) -> Option<String> {
        if self.nodes.contains_key(&node.id) {
            return Some(node.id);
        }
        if !self.has_node_room() {
            return None;
        }
        let id = node.id.clone();
        self.nodes.insert(id.clone(), node);
        Some(id)
    }

    fn add_edge(&mut self, from: &str, to: &str, kind: &str, label: &str, data: serde_json::Value) {
        if !self.nodes.contains_key(from) || !self.nodes.contains_key(to) {
            return;
        }
        let key = format!("{from}\u{1f}{kind}\u{1f}{to}");
        self.edges.entry(key).or_insert_with(|| EvidenceGraphEdge {
            from: from.to_string(),
            to: to.to_string(),
            kind: kind.to_string(),
            label: label.to_string(),
            data,
        });
    }

    fn add_evidence(&mut self, evidence: &Evidence) -> Option<String> {
        let id = evidence_graph_evidence_node_id(&evidence.id);
        let node_id = self.add_node(EvidenceGraphNode {
            id,
            kind: "evidence".to_string(),
            label: evidence.id.clone(),
            summary: Some(evidence.summary.clone()),
            data: serde_json::to_value(evidence).unwrap_or(serde_json::Value::Null),
        })?;
        self.evidence_ids.insert(evidence.id.clone());
        Some(node_id)
    }

    fn add_source(&mut self, source: &str) -> String {
        let id = evidence_graph_source_node_id(source);
        self.add_node(EvidenceGraphNode {
            id: id.clone(),
            kind: "source".to_string(),
            label: source.to_string(),
            summary: Some("Evidence provenance source".to_string()),
            data: serde_json::json!({ "source": source }),
        });
        id
    }

    fn add_artifact(&mut self, artifact: &ArtifactHandle) -> String {
        let id = evidence_graph_artifact_node_id(artifact);
        self.add_node(EvidenceGraphNode {
            id: id.clone(),
            kind: "artifact".to_string(),
            label: artifact.relative_path.clone(),
            summary: Some(format!("{} bytes {}", artifact.size, artifact.content_type)),
            data: serde_json::to_value(artifact).unwrap_or(serde_json::Value::Null),
        });
        id
    }

    fn add_binary(&mut self, binary: &BinaryRecord) -> String {
        let id = evidence_graph_binary_node_id(&binary.id);
        self.add_node(EvidenceGraphNode {
            id: id.clone(),
            kind: "binary".to_string(),
            label: binary.path.clone(),
            summary: Some(format!(
                "{:?}/{:?}, functions={}",
                binary.format, binary.architecture, binary.function_count
            )),
            data: serde_json::to_value(binary).unwrap_or(serde_json::Value::Null),
        });
        id
    }

    fn add_missing_binary(&mut self, binary_id: &str) -> String {
        let id = evidence_graph_binary_node_id(binary_id);
        self.add_node(EvidenceGraphNode {
            id: id.clone(),
            kind: "binary".to_string(),
            label: binary_id.to_string(),
            summary: Some("Binary referenced by evidence but not present in registry".to_string()),
            data: serde_json::json!({ "binary_id": binary_id, "missing": true }),
        });
        id
    }

    fn add_object(&mut self, object: &UniversalObject) -> String {
        let id = evidence_graph_object_node_id(&object.id);
        self.add_node(EvidenceGraphNode {
            id: id.clone(),
            kind: "object".to_string(),
            label: object.display_name.clone(),
            summary: Some(format!(
                "{:?}/{} {} bytes",
                object.kind,
                object.format.as_deref().unwrap_or("unknown"),
                object.size
            )),
            data: serde_json::to_value(object).unwrap_or(serde_json::Value::Null),
        });
        id
    }

    fn add_missing_object(&mut self, object_id: &str) -> String {
        let id = evidence_graph_object_node_id(object_id);
        self.add_node(EvidenceGraphNode {
            id: id.clone(),
            kind: "object".to_string(),
            label: object_id.to_string(),
            summary: Some("Object referenced by evidence but not present in registry".to_string()),
            data: serde_json::json!({ "object_id": object_id, "missing": true }),
        });
        id
    }

    fn add_function(
        &mut self,
        conn: &Connection,
        binary_id: Option<&str>,
        address: u64,
    ) -> Result<String> {
        let locator = if let Some(binary_id) = binary_id {
            let mut stmt = conn.prepare(
                "SELECT binary_id, name, address, size
                 FROM functions
                 WHERE binary_id = ?1 AND address = ?2
                 LIMIT 1",
            )?;
            stmt.query_row(params![binary_id, address as i64], map_function_locator_row)
                .optional()?
        } else {
            let mut stmt = conn.prepare(
                "SELECT binary_id, name, address, size
                 FROM functions
                 WHERE address = ?1
                 ORDER BY binary_id ASC
                 LIMIT 1",
            )?;
            stmt.query_row([address as i64], map_function_locator_row)
                .optional()?
        };

        let (node_id, label, data) = if let Some(locator) = locator {
            (
                evidence_graph_function_node_id(&locator.binary_id, locator.address),
                format!("{}@0x{:x}", locator.name, locator.address),
                serde_json::json!({
                    "binary_id": locator.binary_id,
                    "name": locator.name,
                    "address": locator.address,
                    "size": locator.size,
                }),
            )
        } else {
            let binary_id = binary_id.unwrap_or("unknown");
            (
                evidence_graph_function_node_id(binary_id, address),
                format!("0x{address:x}"),
                serde_json::json!({
                    "binary_id": binary_id,
                    "address": address,
                    "missing": true,
                }),
            )
        };

        self.add_node(EvidenceGraphNode {
            id: node_id.clone(),
            kind: "function".to_string(),
            label,
            summary: Some("Function referenced by evidence provenance".to_string()),
            data,
        });
        Ok(node_id)
    }

    fn add_trace_event(&mut self, trace: &TraceEventRecord) -> Option<String> {
        let id = evidence_graph_trace_node_id(trace.row_id);
        self.add_node(EvidenceGraphNode {
            id,
            kind: "trace_event".to_string(),
            label: format!(
                "{} {}:{}",
                trace.event.kind, trace.event.process, trace.event.thread
            ),
            summary: Some(trace_event_summary(&trace.event)),
            data: serde_json::json!({
                "row_id": trace.row_id,
                "event": trace.event,
                "artifact": trace.artifact,
            }),
        })
    }

    fn add_process(&mut self, process: &str) -> String {
        let id = evidence_graph_process_node_id(process);
        self.add_node(EvidenceGraphNode {
            id: id.clone(),
            kind: "process".to_string(),
            label: process.to_string(),
            summary: Some("Runtime trace process".to_string()),
            data: serde_json::json!({ "process": process }),
        });
        id
    }

    fn add_thread(&mut self, process: &str, thread: &str) -> String {
        let id = evidence_graph_thread_node_id(process, thread);
        self.add_node(EvidenceGraphNode {
            id: id.clone(),
            kind: "thread".to_string(),
            label: format!("{process}:{thread}"),
            summary: Some("Runtime trace thread".to_string()),
            data: serde_json::json!({ "process": process, "thread": thread }),
        });
        id
    }

    fn add_symbolic_case(&mut self, symbolic_case: &serde_json::Value) -> String {
        let case_id = symbolic_case
            .get("case_id")
            .and_then(|value| value.as_str())
            .unwrap_or("unknown");
        let status = symbolic_case
            .get("status")
            .and_then(|value| value.as_str())
            .unwrap_or("unknown");
        let id = evidence_graph_symbolic_case_node_id(case_id);
        self.add_node(EvidenceGraphNode {
            id: id.clone(),
            kind: "symbolic_case".to_string(),
            label: case_id.to_string(),
            summary: Some(format!("Symbolic case status={status}")),
            data: symbolic_case.clone(),
        });
        id
    }

    fn add_symbolic_case_members(&mut self, case_node_id: &str, symbolic_case: &serde_json::Value) {
        if let Some(variables) = symbolic_case
            .get("variables")
            .and_then(|value| value.as_array())
        {
            for variable in variables {
                let name = variable
                    .get("name")
                    .and_then(|value| value.as_str())
                    .unwrap_or("unknown");
                let variable_node_id = evidence_graph_symbolic_variable_node_id(case_node_id, name);
                self.add_node(EvidenceGraphNode {
                    id: variable_node_id.clone(),
                    kind: "symbolic_variable".to_string(),
                    label: name.to_string(),
                    summary: Some("Symbolic variable domain".to_string()),
                    data: variable.clone(),
                });
                self.add_edge(
                    case_node_id,
                    &variable_node_id,
                    "has_variable",
                    "has_variable",
                    serde_json::json!({ "variable": name }),
                );
            }
        }

        if let Some(constraints) = symbolic_case
            .get("constraints")
            .and_then(|value| value.as_array())
        {
            for (index, constraint) in constraints.iter().enumerate() {
                let label = constraint
                    .get("id")
                    .and_then(|value| value.as_str())
                    .map(str::to_string)
                    .unwrap_or_else(|| format!("constraint:{index}"));
                let constraint_node_id =
                    evidence_graph_symbolic_constraint_node_id(case_node_id, &label);
                self.add_node(EvidenceGraphNode {
                    id: constraint_node_id.clone(),
                    kind: "symbolic_constraint".to_string(),
                    label,
                    summary: Some("Symbolic path constraint".to_string()),
                    data: constraint.clone(),
                });
                self.add_edge(
                    case_node_id,
                    &constraint_node_id,
                    "has_constraint",
                    "has_constraint",
                    serde_json::json!({ "index": index }),
                );
            }
        }

        if let Some(solutions) = symbolic_case
            .get("solutions")
            .and_then(|value| value.as_array())
        {
            for (index, solution) in solutions.iter().enumerate() {
                let solution_node_id =
                    evidence_graph_symbolic_solution_node_id(case_node_id, index);
                self.add_node(EvidenceGraphNode {
                    id: solution_node_id.clone(),
                    kind: "symbolic_solution".to_string(),
                    label: format!("solution:{index}"),
                    summary: Some("Satisfying assignment".to_string()),
                    data: solution.clone(),
                });
                self.add_edge(
                    case_node_id,
                    &solution_node_id,
                    "has_solution",
                    "has_solution",
                    serde_json::json!({ "index": index }),
                );
            }
        }
    }

    fn nodes(&self) -> Vec<EvidenceGraphNode> {
        self.nodes.values().cloned().collect()
    }

    fn edges(&self) -> Vec<EvidenceGraphEdge> {
        self.edges.values().cloned().collect()
    }

    fn evidence_count(&self) -> usize {
        self.evidence_ids.len()
    }
}

