fn text_preview(bytes: &[u8]) -> Option<String> {
    if bytes.is_empty() || bytes.iter().any(|byte| *byte == 0) {
        return None;
    }
    let text = std::str::from_utf8(bytes).ok()?;
    if text
        .chars()
        .any(|ch| ch.is_control() && ch != '\n' && ch != '\r' && ch != '\t')
    {
        return None;
    }
    Some(text.chars().take(512).collect())
}

fn text_preview_for_analysis(bytes: &[u8], max_bytes: usize) -> Option<String> {
    if bytes.is_empty() || bytes.iter().any(|byte| *byte == 0) {
        return None;
    }
    let capped = &bytes[..bytes.len().min(max_bytes)];
    let text = std::str::from_utf8(capped).ok()?;
    if text
        .chars()
        .any(|ch| ch.is_control() && ch != '\n' && ch != '\r' && ch != '\t')
    {
        return None;
    }
    Some(text.to_string())
}

fn should_run_structured_text_analyzer(object: &UniversalObject, bytes: &[u8]) -> bool {
    if text_preview_for_analysis(bytes, 8192).is_none() {
        return false;
    }
    matches!(
        object.format.as_deref(),
        Some(
            "json"
                | "safetensors_index"
                | "toml"
                | "yaml"
                | "yml"
                | "xml"
                | "html"
                | "htm"
                | "txt"
                | "text"
                | "markdown"
                | "md"
                | "csv"
                | "ini"
                | "properties"
                | "plist"
                | "pem"
        )
    ) || object.kind == ObjectKind::Text
        || object.flags.iter().any(|flag| flag == "text_like")
}

