fn select_object_analyzers(
    object: &UniversalObject,
    bytes: &[u8],
    requested: Option<&[ObjectAnalyzerKind]>,
) -> Vec<ObjectAnalyzerKind> {
    let mut analyzers = requested
        .map(|items| {
            items
                .iter()
                .copied()
                .filter(|kind| *kind != ObjectAnalyzerKind::Auto)
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();

    if analyzers.is_empty()
        || requested.is_some_and(|items| items.contains(&ObjectAnalyzerKind::Auto))
    {
        analyzers.push(ObjectAnalyzerKind::ByteHistogram);
        if bytes
            .iter()
            .any(|byte| byte.is_ascii_graphic() || *byte == b' ')
        {
            analyzers.push(ObjectAnalyzerKind::Strings);
            if should_run_structured_text_analyzer(object, bytes) {
                analyzers.push(ObjectAnalyzerKind::StructuredText);
            }
        }
        if matches!(
            object.format.as_deref(),
            Some(
                "zip" | "apk" | "ipa" | "jar" | "docx" | "docm" | "xlsx" | "xlsm" | "pptx" | "pptm"
            )
        ) {
            analyzers.push(ObjectAnalyzerKind::ZipListing);
        }
        if should_run_android_package_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::AndroidPackage);
        }
        if should_run_dex_bytecode_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::DexBytecode);
        }
        if should_run_ios_package_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::IosPackage);
        }
        if should_run_java_archive_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::JavaArchive);
        }
        if should_run_jvm_class_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::JvmClass);
        }
        if should_run_python_bytecode_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::PythonBytecode);
        }
        if should_run_shell_link_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::ShellLink);
        }
        if should_run_portable_executable_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::PortableExecutable);
        }
        if should_run_dotnet_metadata_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::DotnetMetadata);
        }
        if should_run_elf_binary_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::ElfBinary);
        }
        if should_run_macho_binary_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::MachOBinary);
        }
        if should_run_open_xml_document_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::OpenXmlDocument);
        }
        if should_run_sqlite_schema_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::SqliteSchema);
        }
        if should_run_wasm_module_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::WasmModule);
        }
        if should_run_pdf_document_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::PdfDocument);
        }
        if should_run_png_image_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::PngImage);
        }
        if should_run_jpeg_image_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::JpegImage);
        }
        if should_run_gif_image_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::GifImage);
        }
        if should_run_bmp_image_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::BmpImage);
        }
        if should_run_riff_container_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::RiffContainer);
        }
        if should_run_pcap_capture_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::PcapCapture);
        }
        if should_run_ole_compound_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::OleCompound);
        }
        if should_run_safetensors_model_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::SafeTensorsModel);
        }
        if should_run_gguf_model_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::GgufModel);
        }
        if should_run_pytorch_model_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::PyTorchModel);
        }
        if should_run_iso_bmff_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::IsoBmff);
        }
        if should_run_cab_archive_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::CabArchive);
        }
        if should_run_ar_archive_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::ArArchive);
        }
        if should_run_seven_zip_archive_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::SevenZipArchive);
        }
        if should_run_rar_archive_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::RarArchive);
        }
        if should_run_font_file_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::FontFile);
        }
        if should_run_tiff_image_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::TiffImage);
        }
        if should_run_audio_media_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::AudioMedia);
        }
        if should_run_disk_image_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::DiskImage);
        }
        if should_run_unknown_blob_analyzer(object, bytes) {
            analyzers.push(ObjectAnalyzerKind::UnknownBlob);
        }
    }

    analyzers.sort_by_key(|kind| match kind {
        ObjectAnalyzerKind::Auto => 0,
        ObjectAnalyzerKind::ByteHistogram => 1,
        ObjectAnalyzerKind::Strings => 2,
        ObjectAnalyzerKind::StructuredText => 3,
        ObjectAnalyzerKind::ZipListing => 4,
        ObjectAnalyzerKind::AndroidPackage => 5,
        ObjectAnalyzerKind::DexBytecode => 6,
        ObjectAnalyzerKind::IosPackage => 7,
        ObjectAnalyzerKind::JavaArchive => 8,
        ObjectAnalyzerKind::JvmClass => 9,
        ObjectAnalyzerKind::PythonBytecode => 10,
        ObjectAnalyzerKind::ShellLink => 11,
        ObjectAnalyzerKind::PortableExecutable => 12,
        ObjectAnalyzerKind::DotnetMetadata => 13,
        ObjectAnalyzerKind::ElfBinary => 14,
        ObjectAnalyzerKind::MachOBinary => 15,
        ObjectAnalyzerKind::OpenXmlDocument => 16,
        ObjectAnalyzerKind::SqliteSchema => 17,
        ObjectAnalyzerKind::WasmModule => 18,
        ObjectAnalyzerKind::PdfDocument => 19,
        ObjectAnalyzerKind::PngImage => 20,
        ObjectAnalyzerKind::JpegImage => 21,
        ObjectAnalyzerKind::GifImage => 22,
        ObjectAnalyzerKind::BmpImage => 23,
        ObjectAnalyzerKind::RiffContainer => 24,
        ObjectAnalyzerKind::PcapCapture => 25,
        ObjectAnalyzerKind::OleCompound => 26,
        ObjectAnalyzerKind::SafeTensorsModel => 27,
        ObjectAnalyzerKind::GgufModel => 28,
        ObjectAnalyzerKind::PyTorchModel => 29,
        ObjectAnalyzerKind::IsoBmff => 30,
        ObjectAnalyzerKind::CabArchive => 31,
        ObjectAnalyzerKind::ArArchive => 32,
        ObjectAnalyzerKind::SevenZipArchive => 33,
        ObjectAnalyzerKind::RarArchive => 34,
        ObjectAnalyzerKind::FontFile => 35,
        ObjectAnalyzerKind::TiffImage => 36,
        ObjectAnalyzerKind::AudioMedia => 37,
        ObjectAnalyzerKind::DiskImage => 38,
        ObjectAnalyzerKind::UnknownBlob => 39,
    });
    analyzers.dedup();
    analyzers
}

fn run_object_analyzer(
    object: &UniversalObject,
    bytes: &[u8],
    analyzer: ObjectAnalyzerKind,
    workspace_root: &Path,
) -> ObjectAnalysisSummary {
    match analyzer {
        ObjectAnalyzerKind::Auto => ObjectAnalysisSummary {
            analyzer: "auto".to_string(),
            status: ObjectAnalysisStatus::Skipped,
            summary: "Auto analyzer expands to concrete analyzers".to_string(),
            details: serde_json::json!({}),
            evidence_ids: vec![format!("analysis:{}:auto", object.id)],
        },
        ObjectAnalyzerKind::ByteHistogram => analyze_object_byte_histogram(object, bytes),
        ObjectAnalyzerKind::Strings => analyze_object_strings(object, bytes),
        ObjectAnalyzerKind::StructuredText => analyze_object_structured_text(object, bytes),
        ObjectAnalyzerKind::ZipListing => analyze_object_zip_listing(object, bytes),
        ObjectAnalyzerKind::AndroidPackage => analyze_object_android_package(object, bytes),
        ObjectAnalyzerKind::DexBytecode => analyze_object_dex_bytecode(object, bytes),
        ObjectAnalyzerKind::IosPackage => analyze_object_ios_package(object, bytes),
        ObjectAnalyzerKind::JavaArchive => analyze_object_java_archive(object, bytes),
        ObjectAnalyzerKind::JvmClass => analyze_object_jvm_class(object, bytes),
        ObjectAnalyzerKind::PythonBytecode => analyze_object_python_bytecode(object, bytes),
        ObjectAnalyzerKind::ShellLink => analyze_object_shell_link(object, bytes),
        ObjectAnalyzerKind::PortableExecutable => analyze_object_portable_executable(object, bytes),
        ObjectAnalyzerKind::DotnetMetadata => analyze_object_dotnet_metadata(object, bytes),
        ObjectAnalyzerKind::ElfBinary => analyze_object_elf_binary(object, bytes),
        ObjectAnalyzerKind::MachOBinary => analyze_object_macho_binary(object, bytes),
        ObjectAnalyzerKind::OpenXmlDocument => analyze_object_open_xml_document(object, bytes),
        ObjectAnalyzerKind::SqliteSchema => {
            analyze_object_sqlite_schema(object, bytes, workspace_root)
        }
        ObjectAnalyzerKind::WasmModule => analyze_object_wasm_module(object, bytes),
        ObjectAnalyzerKind::PdfDocument => analyze_object_pdf_document(object, bytes),
        ObjectAnalyzerKind::PngImage => analyze_object_png_image(object, bytes),
        ObjectAnalyzerKind::JpegImage => analyze_object_jpeg_image(object, bytes),
        ObjectAnalyzerKind::GifImage => analyze_object_gif_image(object, bytes),
        ObjectAnalyzerKind::BmpImage => analyze_object_bmp_image(object, bytes),
        ObjectAnalyzerKind::RiffContainer => analyze_object_riff_container(object, bytes),
        ObjectAnalyzerKind::PcapCapture => analyze_object_pcap_capture(object, bytes),
        ObjectAnalyzerKind::OleCompound => analyze_object_ole_compound(object, bytes),
        ObjectAnalyzerKind::SafeTensorsModel => analyze_object_safetensors_model(object, bytes),
        ObjectAnalyzerKind::GgufModel => analyze_object_gguf_model(object, bytes),
        ObjectAnalyzerKind::PyTorchModel => analyze_object_pytorch_model(object, bytes),
        ObjectAnalyzerKind::IsoBmff => analyze_object_iso_bmff(object, bytes),
        ObjectAnalyzerKind::CabArchive => analyze_object_cab_archive(object, bytes),
        ObjectAnalyzerKind::ArArchive => analyze_object_ar_archive(object, bytes),
        ObjectAnalyzerKind::SevenZipArchive => analyze_object_seven_zip_archive(object, bytes),
        ObjectAnalyzerKind::RarArchive => analyze_object_rar_archive(object, bytes),
        ObjectAnalyzerKind::FontFile => analyze_object_font_file(object, bytes),
        ObjectAnalyzerKind::TiffImage => analyze_object_tiff_image(object, bytes),
        ObjectAnalyzerKind::AudioMedia => analyze_object_audio_media(object, bytes),
        ObjectAnalyzerKind::DiskImage => analyze_object_disk_image(object, bytes),
        ObjectAnalyzerKind::UnknownBlob => analyze_object_unknown_blob(object, bytes),
    }
}


fn analyze_object_iso_bmff(object: &UniversalObject, bytes: &[u8]) -> ObjectAnalysisSummary {
    if bytes.len() < 12 || &bytes[4..8] != b"ftyp" {
        return ObjectAnalysisSummary {
            analyzer: "iso_bmff".to_string(),
            status: ObjectAnalysisStatus::Skipped,
            summary: "Object is not an ISO BMFF/ftyp container".to_string(),
            details: serde_json::json!({ "reason": "missing_ftyp" }),
            evidence_ids: vec![format!("analysis:{}:iso_bmff", object.id)],
        };
    }
    match extract_iso_bmff_summary(bytes) {
        Ok(details) => {
            let brand = details
                .get("major_brand")
                .and_then(|v| v.as_str())
                .unwrap_or("unknown");
            let box_count = details
                .get("box_count")
                .and_then(|v| v.as_u64())
                .unwrap_or(0);
            ObjectAnalysisSummary {
                analyzer: "iso_bmff".to_string(),
                status: if details
                    .get("warnings")
                    .and_then(|v| v.as_array())
                    .is_some_and(|items| !items.is_empty())
                {
                    ObjectAnalysisStatus::Partial
                } else {
                    ObjectAnalysisStatus::Completed
                },
                summary: format!(
                    "ISO BMFF container brand {brand} with {box_count} top-level boxes"
                ),
                details,
                evidence_ids: vec![format!("analysis:{}:iso_bmff", object.id)],
            }
        }
        Err(err) => ObjectAnalysisSummary {
            analyzer: "iso_bmff".to_string(),
            status: ObjectAnalysisStatus::Failed,
            summary: format!("ISO BMFF analysis failed: {err}"),
            details: serde_json::json!({ "error": err.to_string() }),
            evidence_ids: vec![format!("analysis:{}:iso_bmff", object.id)],
        },
    }
}

fn analyze_object_cab_archive(object: &UniversalObject, bytes: &[u8]) -> ObjectAnalysisSummary {
    if !bytes.starts_with(b"MSCF") {
        return ObjectAnalysisSummary {
            analyzer: "cab_archive".to_string(),
            status: ObjectAnalysisStatus::Skipped,
            summary: "Object is not a Microsoft Cabinet archive".to_string(),
            details: serde_json::json!({ "reason": "missing_mscf" }),
            evidence_ids: vec![format!("analysis:{}:cab_archive", object.id)],
        };
    }
    let cabinet_size = read_le_u32(bytes, 8);
    let files = read_le_u16(bytes, 28);
    let folders = read_le_u16(bytes, 26);
    let set_id = read_le_u16(bytes, 32);
    let set_index = read_le_u16(bytes, 34);
    let flags = read_le_u16(bytes, 30);
    let version_minor = bytes.get(24).copied();
    let version_major = bytes.get(25).copied();
    let valid = cabinet_size.is_some();
    ObjectAnalysisSummary {
        analyzer: "cab_archive".to_string(),
        status: if valid {
            ObjectAnalysisStatus::Completed
        } else {
            ObjectAnalysisStatus::Partial
        },
        summary: format!(
            "Microsoft Cabinet with {} folder(s) and {} file(s)",
            folders.unwrap_or(0),
            files.unwrap_or(0)
        ),
        details: serde_json::json!({
            "cabinet_size": cabinet_size,
            "folder_count": folders,
            "file_count": files,
            "set_id": set_id,
            "set_index": set_index,
            "flags": flags,
            "version": version_major.zip(version_minor).map(|(maj, min)| format!("{maj}.{min}")),
            "actual_size": bytes.len(),
            "magic": "MSCF",
        }),
        evidence_ids: vec![format!("analysis:{}:cab_archive", object.id)],
    }
}

fn analyze_object_ar_archive(object: &UniversalObject, bytes: &[u8]) -> ObjectAnalysisSummary {
    if !bytes.starts_with(b"!<arch>\n") {
        return ObjectAnalysisSummary {
            analyzer: "ar_archive".to_string(),
            status: ObjectAnalysisStatus::Skipped,
            summary: "Object is not a Unix ar archive".to_string(),
            details: serde_json::json!({ "reason": "missing_ar_magic" }),
            evidence_ids: vec![format!("analysis:{}:ar_archive", object.id)],
        };
    }
    let (members, truncated, warnings) = extract_ar_members(bytes, 64);
    ObjectAnalysisSummary {
        analyzer: "ar_archive".to_string(),
        status: if warnings.is_empty() {
            ObjectAnalysisStatus::Completed
        } else {
            ObjectAnalysisStatus::Partial
        },
        summary: format!(
            "Unix ar archive with {} member(s){}",
            members.len(),
            if truncated { " (truncated listing)" } else { "" }
        ),
        details: serde_json::json!({
            "member_count": members.len(),
            "truncated": truncated,
            "members": members,
            "warnings": warnings,
        }),
        evidence_ids: vec![format!("analysis:{}:ar_archive", object.id)],
    }
}

fn analyze_object_seven_zip_archive(object: &UniversalObject, bytes: &[u8]) -> ObjectAnalysisSummary {
    if !bytes.starts_with(b"7z\xbc\xaf'\x1c") {
        return ObjectAnalysisSummary {
            analyzer: "seven_zip_archive".to_string(),
            status: ObjectAnalysisStatus::Skipped,
            summary: "Object is not a 7-Zip archive".to_string(),
            details: serde_json::json!({ "reason": "missing_7z_signature" }),
            evidence_ids: vec![format!("analysis:{}:seven_zip_archive", object.id)],
        };
    }
    let mut warnings = Vec::new();
    let start_header_crc = read_le_u32(bytes, 6);
    let next_header_offset = read_le_u64(bytes, 12);
    let next_header_size = read_le_u64(bytes, 20);
    let next_header_crc = read_le_u32(bytes, 28);
    if start_header_crc.is_none()
        || next_header_offset.is_none()
        || next_header_size.is_none()
        || next_header_crc.is_none()
    {
        warnings.push("7z start header is truncated".to_string());
    }
    let next_header_file_offset =
        next_header_offset.map(|offset| 32usize.saturating_add(offset as usize));
    let next_header_end = next_header_file_offset.and_then(|offset| {
        next_header_size.and_then(|size| offset.checked_add(size as usize))
    });
    let next_header_in_bounds = next_header_end.is_some_and(|end| end <= bytes.len());
    if next_header_file_offset.is_some() && !next_header_in_bounds {
        warnings.push("7z next header extends beyond object bounds".to_string());
    }
    let mut risk_signals = vec!["seven_zip_archive_present".to_string()];
    if next_header_size.unwrap_or(0) == 0 {
        risk_signals.push("empty_next_header".to_string());
        warnings.push("7z next header size is zero".to_string());
    }
    if next_header_offset.unwrap_or(0) > 0 {
        risk_signals.push("packed_streams_present".to_string());
    }
    let status = if warnings.is_empty() {
        ObjectAnalysisStatus::Completed
    } else {
        ObjectAnalysisStatus::Partial
    };
    ObjectAnalysisSummary {
        analyzer: "seven_zip_archive".to_string(),
        status,
        summary: format!(
            "7-Zip archive next header offset={} size={}",
            next_header_offset.unwrap_or(0),
            next_header_size.unwrap_or(0)
        ),
        details: serde_json::json!({
            "magic": "7zBC AF 27 1C",
            "signature_ok": true,
            "start_header_crc": start_header_crc,
            "next_header_offset": next_header_offset,
            "next_header_size": next_header_size,
            "next_header_crc": next_header_crc,
            "next_header_file_offset": next_header_file_offset,
            "next_header_in_bounds": next_header_in_bounds,
            "actual_size": bytes.len(),
            "risk_signals": risk_signals,
            "warnings": warnings,
        }),
        evidence_ids: vec![format!("analysis:{}:seven_zip_archive", object.id)],
    }
}

fn analyze_object_rar_archive(object: &UniversalObject, bytes: &[u8]) -> ObjectAnalysisSummary {
    let is_rar4 = bytes.starts_with(b"Rar!\x1a\x07\x00");
    let is_rar5 = bytes.starts_with(b"Rar!\x1a\x07\x01");
    let is_rar_family = is_rar4 || is_rar5 || bytes.get(..6) == Some(&b"Rar!\x1a\x07"[..]);
    if !is_rar_family {
        return ObjectAnalysisSummary {
            analyzer: "rar_archive".to_string(),
            status: ObjectAnalysisStatus::Skipped,
            summary: "Object is not a RAR archive".to_string(),
            details: serde_json::json!({ "reason": "missing_rar_signature" }),
            evidence_ids: vec![format!("analysis:{}:rar_archive", object.id)],
        };
    }
    let mut warnings = Vec::new();
    let mut risk_signals = vec!["rar_archive_present".to_string()];
    let version = if is_rar5 {
        "5"
    } else if is_rar4 {
        "1.5-4.x"
    } else {
        "unknown"
    };
    let mut archive_flags = None::<u32>;
    let mut encrypted = false;
    let mut solid = false;
    let mut volume = false;
    let mut first_header_type = None::<String>;
    if is_rar4 && bytes.len() >= 13 {
        let head_type = bytes.get(9).copied();
        let head_flags = read_le_u16(bytes, 10);
        archive_flags = head_flags.map(|value| value as u32);
        first_header_type = head_type.map(|value| format!("0x{value:02x}"));
        if let Some(flags) = head_flags {
            encrypted = flags & 0x0080 != 0;
            solid = flags & 0x0008 != 0;
            volume = flags & 0x0001 != 0;
        }
        if head_type != Some(0x73) {
            warnings.push(format!(
                "RAR4 first header type is {:?}, expected 0x73 archive header",
                head_type
            ));
        }
    } else if is_rar5 && bytes.len() >= 12 {
        let mut cursor = 8usize;
        if read_le_u32(bytes, cursor).is_none() {
            warnings.push("RAR5 header CRC is truncated".to_string());
        } else {
            cursor += 4;
            match read_rar5_vint(bytes, cursor) {
                Some((header_size, consumed)) => {
                    cursor += consumed;
                    let header_end = cursor.saturating_add(header_size as usize);
                    if header_end > bytes.len() {
                        warnings.push("RAR5 archive header extends beyond object bounds".to_string());
                    }
                    match read_rar5_vint(bytes, cursor) {
                        Some((header_type, type_consumed)) => {
                            cursor += type_consumed;
                            first_header_type = Some(format!("0x{header_type:x}"));
                            if header_type != 1 {
                                warnings.push(format!(
                                    "RAR5 first header type is {header_type}, expected 1 archive header"
                                ));
                            }
                            if let Some((flags, flags_consumed)) = read_rar5_vint(bytes, cursor) {
                                cursor += flags_consumed;
                                archive_flags = Some(flags as u32);
                                if flags & 0x0001 != 0 {
                                    volume = true;
                                }
                                if flags & 0x0004 != 0 {
                                    if let Some((extra_size, extra_consumed)) =
                                        read_rar5_vint(bytes, cursor)
                                    {
                                        cursor = cursor
                                            .saturating_add(extra_consumed)
                                            .saturating_add(extra_size as usize);
                                    }
                                }
                                if flags & 0x0008 != 0 {
                                    if let Some((_, data_size_consumed)) =
                                        read_rar5_vint(bytes, cursor)
                                    {
                                        cursor = cursor.saturating_add(data_size_consumed);
                                    }
                                }
                                if let Some((arch_flags, _)) = read_rar5_vint(bytes, cursor) {
                                    archive_flags = Some(arch_flags as u32);
                                    if arch_flags & 0x0001 != 0 {
                                        volume = true;
                                    }
                                    if arch_flags & 0x0004 != 0 {
                                        solid = true;
                                    }
                                }
                            } else {
                                warnings.push("RAR5 header flags vint is truncated".to_string());
                            }
                        }
                        None => warnings.push("RAR5 header type vint is truncated".to_string()),
                    }
                }
                None => warnings.push("RAR5 header size vint is truncated".to_string()),
            }
        }
    } else {
        warnings.push("RAR signature recognized but header is truncated".to_string());
    }
    if encrypted {
        risk_signals.push("encrypted_archive".to_string());
    }
    if solid {
        risk_signals.push("solid_archive".to_string());
    }
    if volume {
        risk_signals.push("multi_volume_archive".to_string());
    }
    let status = if warnings.is_empty() {
        ObjectAnalysisStatus::Completed
    } else {
        ObjectAnalysisStatus::Partial
    };
    ObjectAnalysisSummary {
        analyzer: "rar_archive".to_string(),
        status,
        summary: format!(
            "RAR {version} archive{}",
            if encrypted {
                " (encrypted)"
            } else if solid {
                " (solid)"
            } else {
                ""
            }
        ),
        details: serde_json::json!({
            "magic": "Rar!",
            "version": version,
            "signature_ok": true,
            "archive_flags": archive_flags,
            "encrypted": encrypted,
            "solid": solid,
            "volume": volume,
            "first_header_type": first_header_type,
            "actual_size": bytes.len(),
            "risk_signals": risk_signals,
            "warnings": warnings,
        }),
        evidence_ids: vec![format!("analysis:{}:rar_archive", object.id)],
    }
}

fn read_rar5_vint(bytes: &[u8], offset: usize) -> Option<(u64, usize)> {
    let mut value = 0u64;
    let mut shift = 0u32;
    for index in 0..10 {
        let byte = *bytes.get(offset + index)?;
        value |= ((byte & 0x7f) as u64) << shift;
        if byte & 0x80 == 0 {
            return Some((value, index + 1));
        }
        shift += 7;
        if shift > 63 {
            return None;
        }
    }
    None
}


fn analyze_object_font_file(object: &UniversalObject, bytes: &[u8]) -> ObjectAnalysisSummary {
    let kind = if bytes.starts_with(b"wOFF") {
        "woff"
    } else if bytes.starts_with(b"wOF2") {
        "woff2"
    } else if bytes.starts_with(b"OTTO") {
        "otf"
    } else if matches!(
        bytes.get(0..4),
        Some([0x00, 0x01, 0x00, 0x00] | [b't', b'r', b'u', b'e'] | [b't', b'y', b'p', b'1'])
    ) {
        "ttf"
    } else {
        object.format.as_deref().unwrap_or("font")
    };
    let mut details = serde_json::json!({
        "font_kind": kind,
        "size": bytes.len(),
        "magic": bytes.iter().take(8).map(|b| format!("{b:02x}")).collect::<Vec<_>>().join(""),
    });
    if matches!(kind, "ttf" | "otf") && bytes.len() >= 12 {
        if let Some(num_tables) = read_be_u16(bytes, 4) {
            details["num_tables"] = serde_json::json!(num_tables);
            let tables = extract_sfnt_table_tags(bytes, num_tables as usize, 32);
            details["tables"] = serde_json::json!(tables);
            details["table_count"] = serde_json::json!(tables.len());
        }
    }
    if matches!(kind, "woff" | "woff2") && bytes.len() >= 44 {
        details["flavor"] = serde_json::json!(read_be_u32(bytes, 4));
        details["length"] = serde_json::json!(read_be_u32(bytes, 8));
        details["num_tables"] = serde_json::json!(read_be_u16(bytes, 12));
        details["total_sfnt_size"] = serde_json::json!(read_be_u32(bytes, 16));
    }
    ObjectAnalysisSummary {
        analyzer: "font_file".to_string(),
        status: ObjectAnalysisStatus::Completed,
        summary: format!("Font file identified as {kind}"),
        details,
        evidence_ids: vec![format!("analysis:{}:font_file", object.id)],
    }
}

fn analyze_object_tiff_image(object: &UniversalObject, bytes: &[u8]) -> ObjectAnalysisSummary {
    let endian = if bytes.starts_with(b"II") {
        Some("le")
    } else if bytes.starts_with(b"MM") {
        Some("be")
    } else {
        None
    };
    if endian.is_none() {
        return ObjectAnalysisSummary {
            analyzer: "tiff_image".to_string(),
            status: ObjectAnalysisStatus::Skipped,
            summary: "Object is not a TIFF image".to_string(),
            details: serde_json::json!({ "reason": "missing_tiff_header" }),
            evidence_ids: vec![format!("analysis:{}:tiff_image", object.id)],
        };
    }
    let little = endian == Some("le");
    let magic_ok = if little {
        bytes.get(2..4) == Some(&[0x2a, 0x00]) || bytes.get(2..4) == Some(&[0x2b, 0x00])
    } else {
        bytes.get(2..4) == Some(&[0x00, 0x2a]) || bytes.get(2..4) == Some(&[0x00, 0x2b])
    };
    let ifd0 = if little {
        read_le_u32(bytes, 4)
    } else {
        read_be_u32(bytes, 4)
    };
    let bigtiff = bytes.get(2..4)
        == Some(if little { &[0x2b, 0x00] } else { &[0x00, 0x2b] });
    ObjectAnalysisSummary {
        analyzer: "tiff_image".to_string(),
        status: if magic_ok {
            ObjectAnalysisStatus::Completed
        } else {
            ObjectAnalysisStatus::Partial
        },
        summary: format!(
            "TIFF image ({}, {})",
            endian.unwrap_or("unknown"),
            if bigtiff { "BigTIFF" } else { "classic" }
        ),
        details: serde_json::json!({
            "endian": endian,
            "bigtiff": bigtiff,
            "ifd0_offset": ifd0,
            "magic_ok": magic_ok,
            "size": bytes.len(),
        }),
        evidence_ids: vec![format!("analysis:{}:tiff_image", object.id)],
    }
}

fn analyze_object_audio_media(object: &UniversalObject, bytes: &[u8]) -> ObjectAnalysisSummary {
    let kind = if bytes.starts_with(b"fLaC") {
        "flac"
    } else if bytes.starts_with(b"OggS") {
        "ogg"
    } else if bytes.starts_with(b"ID3")
        || (bytes.len() >= 2 && bytes[0] == 0xff && (bytes[1] & 0xe0) == 0xe0)
    {
        "mp3"
    } else {
        object.format.as_deref().unwrap_or("audio")
    };
    let mut details = serde_json::json!({
        "audio_kind": kind,
        "size": bytes.len(),
        "magic": bytes.iter().take(8).map(|b| format!("{b:02x}")).collect::<Vec<_>>().join(""),
    });
    match kind {
        "flac" => {
            details["streaminfo_present"] = serde_json::json!(bytes.len() > 4);
        }
        "ogg" => {
            details["version"] = serde_json::json!(bytes.get(4).copied());
            details["header_type"] = serde_json::json!(bytes.get(5).copied());
            details["page_segments"] = serde_json::json!(bytes.get(26).copied());
        }
        "mp3" => {
            details["id3"] = serde_json::json!(bytes.starts_with(b"ID3"));
            if bytes.starts_with(b"ID3") && bytes.len() >= 10 {
                let size = ((bytes[6] as u32) << 21)
                    | ((bytes[7] as u32) << 14)
                    | ((bytes[8] as u32) << 7)
                    | (bytes[9] as u32);
                details["id3_size"] = serde_json::json!(size);
                details["id3_version"] = serde_json::json!(format!("{}.{}", bytes[3], bytes[4]));
            }
            details["frame_sync"] = serde_json::json!(
                bytes.len() >= 2 && bytes[0] == 0xff && (bytes[1] & 0xe0) == 0xe0
            );
        }
        _ => {}
    }
    ObjectAnalysisSummary {
        analyzer: "audio_media".to_string(),
        status: ObjectAnalysisStatus::Completed,
        summary: format!("Audio media identified as {kind}"),
        details,
        evidence_ids: vec![format!("analysis:{}:audio_media", object.id)],
    }
}

fn analyze_object_disk_image(object: &UniversalObject, bytes: &[u8]) -> ObjectAnalysisSummary {
    let kind = if bytes.starts_with(b"QFI\xfb") {
        "qcow2"
    } else if bytes.starts_with(b"koly")
        || (bytes.len() >= 512 && bytes[bytes.len() - 512..].starts_with(b"koly"))
    {
        "dmg"
    } else if [0x8001usize, 0x8801, 0x9001].iter().any(|offset| {
        bytes
            .get(*offset..*offset + 5)
            .is_some_and(|magic| magic == b"CD001")
    }) {
        "iso"
    } else {
        object.format.as_deref().unwrap_or("disk_image")
    };
    let mut details = serde_json::json!({
        "disk_kind": kind,
        "size": bytes.len(),
        "magic": bytes.iter().take(16).map(|b| format!("{b:02x}")).collect::<Vec<_>>().join(""),
    });
    if kind == "qcow2" {
        details["version"] = serde_json::json!(read_be_u32(bytes, 4));
        details["cluster_bits"] = serde_json::json!(read_be_u32(bytes, 20));
        details["size"] = serde_json::json!(read_be_u64(bytes, 24));
        details["crypt_method"] = serde_json::json!(read_be_u32(bytes, 32));
        details["l1_size"] = serde_json::json!(read_be_u32(bytes, 36));
    }
    if kind == "iso" {
        details["primary_volume_descriptor"] = serde_json::json!(true);
    }
    if kind == "dmg" {
        details["koly_trailer"] = serde_json::json!(
            bytes.len() >= 512 && bytes[bytes.len() - 512..].starts_with(b"koly")
        );
        details["koly_header"] = serde_json::json!(bytes.starts_with(b"koly"));
    }
    ObjectAnalysisSummary {
        analyzer: "disk_image".to_string(),
        status: ObjectAnalysisStatus::Completed,
        summary: format!("Disk/filesystem image identified as {kind}"),
        details,
        evidence_ids: vec![format!("analysis:{}:disk_image", object.id)],
    }
}



const MAX_AUTO_DIG_DEPTH: usize = 2;

fn child_seed_analyzers(object: &UniversalObject, bytes: &[u8]) -> &'static [ObjectAnalyzerKind] {
    match object.format.as_deref() {
        Some("pdf") => &[ObjectAnalyzerKind::PdfDocument, ObjectAnalyzerKind::Strings],
        Some("png") => &[ObjectAnalyzerKind::PngImage, ObjectAnalyzerKind::ByteHistogram],
        Some("jpeg") => &[ObjectAnalyzerKind::JpegImage, ObjectAnalyzerKind::ByteHistogram],
        Some("gif") => &[ObjectAnalyzerKind::GifImage, ObjectAnalyzerKind::ByteHistogram],
        Some("tiff") => &[ObjectAnalyzerKind::TiffImage, ObjectAnalyzerKind::ByteHistogram],
        Some("bmp" | "dib") => &[ObjectAnalyzerKind::BmpImage, ObjectAnalyzerKind::ByteHistogram],
        Some("zip") => &[ObjectAnalyzerKind::ZipListing, ObjectAnalyzerKind::Strings],
        Some("apk") => &[
            ObjectAnalyzerKind::AndroidPackage,
            ObjectAnalyzerKind::ZipListing,
            ObjectAnalyzerKind::Strings,
        ],
        Some("jar") => &[
            ObjectAnalyzerKind::JavaArchive,
            ObjectAnalyzerKind::ZipListing,
            ObjectAnalyzerKind::Strings,
        ],
        Some("ipa") => &[
            ObjectAnalyzerKind::IosPackage,
            ObjectAnalyzerKind::ZipListing,
            ObjectAnalyzerKind::Strings,
        ],
        Some("docx" | "docm" | "xlsx" | "xlsm" | "pptx" | "pptm") => &[
            ObjectAnalyzerKind::OpenXmlDocument,
            ObjectAnalyzerKind::ZipListing,
            ObjectAnalyzerKind::Strings,
        ],
        Some("elf") => &[
            ObjectAnalyzerKind::ElfBinary,
            ObjectAnalyzerKind::Strings,
            ObjectAnalyzerKind::ByteHistogram,
        ],
        Some("pe") => &[
            ObjectAnalyzerKind::PortableExecutable,
            ObjectAnalyzerKind::DotnetMetadata,
            ObjectAnalyzerKind::Strings,
            ObjectAnalyzerKind::ByteHistogram,
        ],
        Some("macho" | "macho_fat") => &[
            ObjectAnalyzerKind::MachOBinary,
            ObjectAnalyzerKind::Strings,
            ObjectAnalyzerKind::ByteHistogram,
        ],
        Some("dex") => &[
            ObjectAnalyzerKind::DexBytecode,
            ObjectAnalyzerKind::Strings,
            ObjectAnalyzerKind::ByteHistogram,
        ],
        Some("jvm_class") => &[
            ObjectAnalyzerKind::JvmClass,
            ObjectAnalyzerKind::Strings,
            ObjectAnalyzerKind::ByteHistogram,
        ],
        Some("pyc" | "pyo") => &[
            ObjectAnalyzerKind::PythonBytecode,
            ObjectAnalyzerKind::Strings,
            ObjectAnalyzerKind::ByteHistogram,
        ],
        Some("lnk") => &[ObjectAnalyzerKind::ShellLink, ObjectAnalyzerKind::Strings],
        Some("ole" | "doc" | "xls" | "ppt" | "msi" | "msg") => &[
            ObjectAnalyzerKind::OleCompound,
            ObjectAnalyzerKind::Strings,
            ObjectAnalyzerKind::ByteHistogram,
        ],
        Some("wasm") => &[ObjectAnalyzerKind::WasmModule, ObjectAnalyzerKind::ByteHistogram],
        Some("sqlite") => &[ObjectAnalyzerKind::SqliteSchema, ObjectAnalyzerKind::Strings],
        Some("cab") => &[ObjectAnalyzerKind::CabArchive, ObjectAnalyzerKind::ByteHistogram],
        Some("ar") => &[ObjectAnalyzerKind::ArArchive, ObjectAnalyzerKind::ByteHistogram],
        Some("mp4" | "m4a" | "m4v" | "mov" | "heif" | "avif") => {
            &[ObjectAnalyzerKind::IsoBmff, ObjectAnalyzerKind::ByteHistogram]
        }
        Some("flac" | "ogg" | "mp3") => {
            &[ObjectAnalyzerKind::AudioMedia, ObjectAnalyzerKind::ByteHistogram]
        }
        Some("riff" | "wav" | "avi" | "webp") => {
            &[ObjectAnalyzerKind::RiffContainer, ObjectAnalyzerKind::ByteHistogram]
        }
        Some("woff" | "woff2" | "ttf" | "otf") => {
            &[ObjectAnalyzerKind::FontFile, ObjectAnalyzerKind::ByteHistogram]
        }
        Some("qcow2" | "iso" | "dmg" | "vmdk" | "img") => {
            &[ObjectAnalyzerKind::DiskImage, ObjectAnalyzerKind::ByteHistogram]
        }
        Some("pcap" | "pcapng") => {
            &[ObjectAnalyzerKind::PcapCapture, ObjectAnalyzerKind::ByteHistogram]
        }
        Some("safetensors") => &[
            ObjectAnalyzerKind::SafeTensorsModel,
            ObjectAnalyzerKind::Strings,
            ObjectAnalyzerKind::ByteHistogram,
        ],
        Some("gguf") => &[
            ObjectAnalyzerKind::GgufModel,
            ObjectAnalyzerKind::Strings,
            ObjectAnalyzerKind::ByteHistogram,
        ],
        Some("pytorch" | "pt" | "pth") => &[
            ObjectAnalyzerKind::PyTorchModel,
            ObjectAnalyzerKind::Strings,
            ObjectAnalyzerKind::ByteHistogram,
        ],
        Some("gzip" | "xz" | "zstd" | "bzip2") => {
            &[ObjectAnalyzerKind::ByteHistogram, ObjectAnalyzerKind::Strings]
        }
        Some("7z") => &[
            ObjectAnalyzerKind::SevenZipArchive,
            ObjectAnalyzerKind::ByteHistogram,
            ObjectAnalyzerKind::Strings,
        ],
        Some("rar") => &[
            ObjectAnalyzerKind::RarArchive,
            ObjectAnalyzerKind::ByteHistogram,
            ObjectAnalyzerKind::Strings,
        ],
        Some("unknown" | "bin" | "raw" | "data") => &[ObjectAnalyzerKind::UnknownBlob],
        _ if bytes.starts_with(b"%PDF-") => {
            &[ObjectAnalyzerKind::PdfDocument, ObjectAnalyzerKind::Strings]
        }
        _ if bytes.starts_with(b"\x89PNG\r\n\x1a\n") => {
            &[ObjectAnalyzerKind::PngImage, ObjectAnalyzerKind::ByteHistogram]
        }
        _ if bytes.starts_with(b"dex\n") => {
            &[ObjectAnalyzerKind::DexBytecode, ObjectAnalyzerKind::Strings]
        }
        _ if bytes.starts_with(b"\xca\xfe\xba\xbe") => {
            &[ObjectAnalyzerKind::JvmClass, ObjectAnalyzerKind::Strings]
        }
        _ => &[
            ObjectAnalyzerKind::ByteHistogram,
            ObjectAnalyzerKind::Strings,
        ],
    }
}

fn agent_next_action(
    tool: &str,
    reason: impl Into<String>,
    priority: u8,
    query: Option<String>,
    label: Option<&str>,
    args: serde_json::Value,
) -> AgentNextAction {
    AgentNextAction {
        tool: tool.to_string(),
        reason: reason.into(),
        priority,
        query,
        label: label.map(ToOwned::to_owned),
        args,
    }
}

fn derive_object_next_actions(
    object: &UniversalObject,
    analyses: &[ObjectAnalysisSummary],
) -> Vec<AgentNextAction> {
    let mut actions = Vec::new();
    let query = object
        .path
        .clone()
        .filter(|value| !value.is_empty())
        .unwrap_or_else(|| object.id.clone());
    let mut seen = BTreeSet::<String>::new();
    let mut push = |action: AgentNextAction| {
        let key = format!("{}|{}|{}", action.tool, action.query.as_deref().unwrap_or(""), action.reason);
        if seen.insert(key) {
            actions.push(action);
        }
    };

    for analysis in analyses {
        let details = &analysis.details;
        match analysis.analyzer.as_str() {
            "auto_expand" => {
                let expanded = details
                    .get("expanded")
                    .and_then(|value| value.as_array())
                    .cloned()
                    .unwrap_or_default();
                for item in expanded.iter().take(4) {
                    let child_id = item
                        .get("child_object_id")
                        .and_then(|value| value.as_str())
                        .unwrap_or_default();
                    if child_id.is_empty() {
                        continue;
                    }
                    let kind = item
                        .get("expand_kind")
                        .and_then(|value| value.as_str())
                        .unwrap_or("expanded");
                    let format = item
                        .get("format")
                        .and_then(|value| value.as_str())
                        .unwrap_or("unknown");
                    push(agent_next_action(
                        "object_analyze",
                        format!("Analyze expanded {kind} child ({format})"),
                        92,
                        Some(child_id.to_string()),
                        Some("inspect expanded child"),
                        serde_json::json!({ "query": child_id, "analyzers": ["auto"] }),
                    ));
                    if matches!(format, "elf" | "pe" | "macho" | "macho_fat") {
                        push(agent_next_action(
                            "object_analyze_binary",
                            format!("Promote native binary candidate from {kind}"),
                            88,
                            Some(child_id.to_string()),
                            Some("binary deep analysis"),
                            serde_json::json!({ "query": child_id, "profile": "fast" }),
                        ));
                    }
                }
            }
            "auto_dig" => {
                let dug = details
                    .get("carved")
                    .or_else(|| details.get("dug"))
                    .or_else(|| details.get("candidates"))
                    .and_then(|value| value.as_array())
                    .map(|items| items.len())
                    .unwrap_or(0);
                if dug > 0 || details.get("child_object_ids").is_some() {
                    push(agent_next_action(
                        "object_carve_identify",
                        "Persist and re-identify carved embedded candidates as first-class objects",
                        84,
                        Some(query.clone()),
                        Some("carve+identify embeds"),
                        serde_json::json!({ "query": query, "limit": 16, "min_confidence": 0.9 }),
                    ));
                }
            }
            "dotnet_metadata" => {
                let risk = details
                    .get("risk_signals")
                    .and_then(|value| value.as_array())
                    .cloned()
                    .unwrap_or_default();
                let has = |name: &str| {
                    risk.iter()
                        .any(|item| item.as_str() == Some(name))
                };
                if has("embedded_manifest_resources_present") || has("manifest_resources_present") {
                    push(agent_next_action(
                        "object_analyze",
                        "Re-run analysis to expand .NET ManifestResource payloads into child objects",
                        90,
                        Some(query.clone()),
                        Some("expand managed resources"),
                        serde_json::json!({ "query": query, "analyzers": ["auto"] }),
                    ));
                }
                if has("impl_maps_present") || has("suspicious_pinvoke_import") {
                    push(agent_next_action(
                        "evidence_pack",
                        "Package P/Invoke and native interop signals for agent follow-up",
                        80,
                        Some(query.clone()),
                        Some("collect interop evidence"),
                        serde_json::json!({ "subject": query, "limit": 50 }),
                    ));
                }
                if has("user_string_url")
                    || has("user_string_secret_like")
                    || has("user_string_command_like")
                {
                    push(agent_next_action(
                        "evidence_search",
                        "Search evidence for high-signal .NET user strings (URL/secret/command)",
                        78,
                        Some(query.clone()),
                        Some("hunt user-string IOCs"),
                        serde_json::json!({ "query": query, "limit": 50 }),
                    ));
                }
            }
            "portable_executable" => {
                if details
                    .get("overlay")
                    .and_then(|value| value.get("present"))
                    .and_then(|value| value.as_bool())
                    .unwrap_or(false)
                {
                    push(agent_next_action(
                        "object_carve_signatures",
                        "Carve PE overlay payload(s) into evidence artifacts",
                        86,
                        Some(query.clone()),
                        Some("carve PE overlay"),
                        serde_json::json!({ "query": query, "limit": 16 }),
                    ));
                }
            }
            "macho_binary" => {
                if details
                    .get("fat")
                    .and_then(|value| value.get("architecture_count"))
                    .and_then(|value| value.as_u64())
                    .unwrap_or(0)
                    > 1
                {
                    push(agent_next_action(
                        "object_analyze",
                        "Expand Mach-O fat slices and analyze architecture-specific thin binaries",
                        89,
                        Some(query.clone()),
                        Some("expand fat binary"),
                        serde_json::json!({ "query": query, "analyzers": ["auto"] }),
                    ));
                }
            }
            "unknown_blob" => {
                for followup in details
                    .get("suggested_followups")
                    .and_then(|value| value.as_array())
                    .into_iter()
                    .flatten()
                    .filter_map(|value| value.as_str())
                    .take(4)
                {
                    match followup {
                        "object_carve_signatures" => push(agent_next_action(
                            "object_carve_signatures",
                            "Carve high-confidence embedded signatures from opaque blob",
                            85,
                            Some(query.clone()),
                            Some("carve embeds"),
                            serde_json::json!({ "query": query, "limit": 16, "min_confidence": 0.9 }),
                        )),
                        "object_scan_signatures" => push(agent_next_action(
                            "object_scan_signatures",
                            "Map embedded signature offsets before carving",
                            70,
                            Some(query.clone()),
                            Some("scan signatures"),
                            serde_json::json!({ "query": query, "limit": 32 }),
                        )),
                        "structured_text" => push(agent_next_action(
                            "object_analyze",
                            "Object looks text-like; run structured text analyzer",
                            72,
                            Some(query.clone()),
                            Some("structured text pass"),
                            serde_json::json!({ "query": query, "analyzers": ["structured_text"] }),
                        )),
                        "entropy_review" => push(agent_next_action(
                            "object_analyze",
                            "High entropy region warrants histogram/strings review",
                            60,
                            Some(query.clone()),
                            Some("entropy review"),
                            serde_json::json!({
                                "query": query,
                                "analyzers": ["byte_histogram", "strings"]
                            }),
                        )),
                        "object_analyze"
                        | "object_carve_identify"
                        | "object_analyze_binary"
                        | "object_pipeline"
                        | "evidence_pack"
                        | "evidence_graph"
                        | "string_search"
                        | "function_search"
                        | "trace_query" => push(agent_next_action(
                            followup,
                            format!("Suggested follow-up from unknown_blob: {followup}"),
                            55,
                            Some(query.clone()),
                            Some("follow suggested path"),
                            serde_json::json!({ "query": query, "subject": query }),
                        )),
                        _ => {}
                    }
                }
            }
            "android_package" | "java_archive" | "ios_package" | "zip_listing" => {
                if details
                    .get("native_lib_count")
                    .and_then(|value| value.as_u64())
                    .unwrap_or(0)
                    > 0
                    || details
                        .get("native_libs")
                        .and_then(|value| value.as_array())
                        .is_some_and(|items| !items.is_empty())
                {
                    push(agent_next_action(
                        "object_analyze",
                        "Expand package and analyze native library members",
                        87,
                        Some(query.clone()),
                        Some("expand native libs"),
                        serde_json::json!({ "query": query, "analyzers": ["auto"] }),
                    ));
                }
            }
            "seven_zip_archive" | "rar_archive" | "cab_archive" | "ar_archive" => {
                push(agent_next_action(
                    "object_scan_signatures",
                    "Archive structural parse completed; scan for nested high-value payloads",
                    68,
                    Some(query.clone()),
                    Some("scan archive embeds"),
                    serde_json::json!({ "query": query }),
                ));
            }
            _ => {}
        }
        if analysis.status == ObjectAnalysisStatus::Partial {
            push(agent_next_action(
                "object_analyze",
                format!(
                    "{} returned partial results; re-run or deepen analysis if needed",
                    analysis.analyzer
                ),
                50,
                Some(query.clone()),
                Some("revisit partial analysis"),
                serde_json::json!({ "query": query, "analyzers": ["auto"] }),
            ));
        }
    }

    drop(push);
    if actions.is_empty() {
        actions.push(agent_next_action(
            "evidence_graph",
            "No high-priority object action; review evidence graph for lateral findings",
            40,
            Some(query.clone()),
            Some("review evidence graph"),
            serde_json::json!({ "subject": query, "depth": 2, "limit": 100 }),
        ));
    }

    actions.sort_by(|left, right| {
        right
            .priority
            .cmp(&left.priority)
            .then_with(|| left.tool.cmp(&right.tool))
    });
    actions.truncate(8);
    actions
}

fn derive_object_agent_brief(
    object: &UniversalObject,
    analyses: &[ObjectAnalysisSummary],
    next_actions: &[AgentNextAction],
) -> AgentInteractionBrief {
    let mut risk_findings = Vec::new();
    let mut base_findings = Vec::new();
    let mut open_questions = Vec::new();
    for analysis in analyses.iter().take(12) {
        if analysis.status == ObjectAnalysisStatus::Skipped {
            continue;
        }
        base_findings.push(format!("{}: {}", analysis.analyzer, analysis.summary));
        if analysis.status == ObjectAnalysisStatus::Partial {
            open_questions.push(format!(
                "{} is partial; confirm whether deeper parse is needed",
                analysis.analyzer
            ));
        }
        if let Some(risks) = analysis
            .details
            .get("risk_signals")
            .and_then(|value| value.as_array())
        {
            for risk in risks.iter().filter_map(|value| value.as_str()).take(4) {
                risk_findings.push(format!("risk/{}/{}", analysis.analyzer, risk));
            }
        }
        if analysis.analyzer == "auto_expand" {
            if let Some(count) = analysis
                .details
                .get("expanded_count")
                .and_then(|value| value.as_u64())
                .or_else(|| {
                    analysis
                        .details
                        .get("expanded")
                        .and_then(|value| value.as_array())
                        .map(|items| items.len() as u64)
                })
            {
                if count > 0 {
                    open_questions.push(format!(
                        "{count} expanded child object(s) are ready; analyze top child before sibling breadth"
                    ));
                }
            }
        }
    }
    let mut key_findings = risk_findings;
    key_findings.extend(base_findings);
    key_findings.truncate(8);
    open_questions.truncate(5);
    if open_questions.is_empty() {
        if let Some(top) = next_actions.first().filter(|action| action.priority >= 80) {
            open_questions.push(format!(
                "Execute top action `{}` before opening parallel tool calls",
                top.tool
            ));
        }
    }
    let headline = if let Some(top) = next_actions.first() {
        format!(
            "{} [{}] p{} → {} (`{}`)",
            object.display_name,
            object.format.as_deref().unwrap_or("unknown"),
            top.priority,
            top.label.as_deref().unwrap_or(top.tool.as_str()),
            top.tool
        )
    } else {
        format!(
            "{} [{}] ready; no high-value follow-up",
            object.display_name,
            object.format.as_deref().unwrap_or("unknown")
        )
    };
    AgentInteractionBrief {
        headline,
        key_findings,
        open_questions,
        next_actions: next_actions.to_vec(),
        stop_conditions: vec![
            "Execute exactly one top next_action, then reassess with the new response".to_string(),
            "Stop when top priority < 60 and no new child objects/evidence appear".to_string(),
            "Do not re-analyze the same object without a new child/evidence edge".to_string(),
            "Prefer args from next_actions[0].args over inventing parameters".to_string(),
        ],
        semantic_lattice: None,
    }
}

fn should_auto_expand_object(
    object: &UniversalObject,
    selected: &[ObjectAnalyzerKind],
    analyses: &[ObjectAnalysisSummary],
) -> bool {
    if matches!(object.kind, ObjectKind::Directory) || object.size == 0 {
        return false;
    }
    if compressed_format_for_object(object, &[]).is_some()
        || matches!(
            object.format.as_deref(),
            Some(
                "gzip"
                    | "xz"
                    | "zstd"
                    | "bzip2"
                    | "tar"
                    | "tar.gz"
                    | "tar.bz2"
                    | "tar.xz"
                    | "tar.zst"
                    | "apk"
                    | "ipa"
                    | "jar"
                    | "aar"
                    | "pe"
                    | "dll"
                    | "exe"
                    | "sys"
                    | "ar"
                    | "macho"
                    | "macho_fat"
            )
        )
    {
        return true;
    }
    if selected.iter().any(|kind| {
        matches!(
            kind,
            ObjectAnalyzerKind::AndroidPackage
                | ObjectAnalyzerKind::JavaArchive
                | ObjectAnalyzerKind::IosPackage
                | ObjectAnalyzerKind::PortableExecutable
                | ObjectAnalyzerKind::ArArchive
                | ObjectAnalyzerKind::MachOBinary
        )
    }) {
        return true;
    }
    analyses.iter().any(|analysis| {
        matches!(
            analysis.analyzer.as_str(),
            "android_package" | "java_archive" | "ios_package" | "zip_listing"
        ) || analysis
            .details
            .get("native_lib_count")
            .and_then(|value| value.as_u64())
            .unwrap_or(0)
            > 0
            || analysis
                .details
                .get("native_libs")
                .and_then(|value| value.as_array())
                .is_some_and(|items| !items.is_empty())
    })
}

fn compressed_format_for_object(
    object: &UniversalObject,
    bytes: &[u8],
) -> Option<CompressedFormat> {
    if let Some(format) = object.format.as_deref() {
        if let Some(parsed) = compressed_format(format).or_else(|| compressed_tar_format(format)) {
            return Some(parsed);
        }
    }
    if bytes.starts_with(&[0x1f, 0x8b, 0x08]) {
        return Some(CompressedFormat::Gzip);
    }
    if bytes.starts_with(b"BZh") {
        return Some(CompressedFormat::Bzip2);
    }
    if bytes.starts_with(b"\xfd7zXZ\0") {
        return Some(CompressedFormat::Xz);
    }
    if bytes.starts_with(&[0x28, 0xb5, 0x2f, 0xfd]) {
        return Some(CompressedFormat::Zstd);
    }
    None
}

fn high_value_zip_member_priority(name: &str, parent_format: Option<&str>) -> Option<u8> {
    high_value_archive_member_priority(name, parent_format)
}

fn high_value_archive_member_priority(name: &str, parent_format: Option<&str>) -> Option<u8> {
    let lower = name.to_ascii_lowercase();
    if lower.ends_with('/') {
        return None;
    }
    if android_native_lib_entry(name).is_some() || lower.ends_with(".so") {
        return Some(100);
    }
    if is_android_dex_entry(name) || lower.ends_with(".dex") {
        return Some(95);
    }
    if lower.ends_with(".dll")
        || lower.ends_with(".exe")
        || lower.ends_with(".sys")
        || lower.ends_with(".ocx")
        || lower.ends_with(".drv")
    {
        return Some(90);
    }
    if lower.ends_with(".dylib")
        || lower.ends_with(".framework")
        || lower.contains(".framework/")
        || lower.ends_with("/framework")
    {
        return Some(88);
    }
    if lower.contains("payload/") && (lower.ends_with(".app/") || lower.contains(".app/")) {
        // keep scanning nested members via extension rules
    }
    if lower.ends_with(".class") {
        return Some(80);
    }
    if lower.ends_with(".wasm") {
        return Some(78);
    }
    if lower.ends_with(".o") || lower.ends_with(".a") || lower.ends_with(".rlib") {
        return Some(72);
    }
    if lower.ends_with(".pdf")
        || lower.ends_with(".sqlite")
        || lower.ends_with(".db")
        || lower.ends_with(".realm")
    {
        return Some(60);
    }
    if lower.ends_with(".plist")
        || lower.ends_with("info.plist")
        || lower.ends_with("mobileprovision")
        || lower.ends_with(".mobileprovision")
    {
        return Some(55);
    }
    if matches!(parent_format, Some("apk" | "ipa" | "jar" | "aar" | "zip"))
        && (lower.starts_with("assets/") || lower.starts_with("res/raw/") || lower.contains("/assets/"))
        && (lower.ends_with(".so")
            || lower.ends_with(".dex")
            || lower.ends_with(".bin")
            || lower.ends_with(".dat")
            || lower.ends_with(".wasm"))
    {
        return Some(70);
    }
    if matches!(parent_format, Some("ipa"))
        && (lower.contains("payload/") || lower.contains(".app/"))
        && (lower.ends_with(".dylib")
            || !lower.contains('.')
            || lower.ends_with(".bin")
            || lower.ends_with(".dat"))
    {
        // Mach-O main executable often has no extension.
        return Some(85);
    }
    if matches!(parent_format, Some("jar" | "aar"))
        && (lower.ends_with(".class") || lower.ends_with(".so") || lower.ends_with(".dll"))
    {
        return Some(82);
    }
    if lower.ends_with(".elf") {
        return Some(50);
    }
    None
}

fn is_tar_bytes(bytes: &[u8]) -> bool {
    if bytes.len() < 512 {
        return false;
    }
    if bytes.get(257..262) == Some(b"ustar") {
        return true;
    }
    // POSIX tar: checksum field at 148..156 is ASCII octal and header checksum matches.
    let checksum_field = &bytes[148..156];
    if !checksum_field
        .iter()
        .all(|b| b.is_ascii_digit() || *b == b' ' || *b == 0)
    {
        return false;
    }
    let mut sum = 0u32;
    for (index, byte) in bytes.iter().take(512).enumerate() {
        if (148..156).contains(&index) {
            sum += b' ' as u32;
        } else {
            sum += *byte as u32;
        }
    }
    let text = std::str::from_utf8(checksum_field)
        .unwrap_or("")
        .trim_matches(|c: char| c == '␀' || c.is_whitespace());
    let Ok(declared) = u32::from_str_radix(text, 8) else {
        return false;
    };
    declared == sum
}

fn classify_expanded_bytes(bytes: &[u8], entry_name: &str) -> (ObjectKind, &'static str, &'static str) {
    let lower = entry_name.to_ascii_lowercase();
    if bytes.starts_with(b"\x7fELF") {
        return (ObjectKind::Binary, "elf", "application/x-elf");
    }
    if validate_pe_signature(bytes, 0) {
        return (
            ObjectKind::Binary,
            "pe",
            "application/vnd.microsoft.portable-executable",
        );
    }
    if matches!(
        bytes.get(..4),
        Some(b"\xcf\xfa\xed\xfe" | b"\xce\xfa\xed\xfe" | b"\xfe\xed\xfa\xcf" | b"\xfe\xed\xfa\xce")
    ) {
        return (ObjectKind::Binary, "macho", "application/x-mach-binary");
    }
    if bytes.get(..4) == Some(b"\xca\xfe\xba\xbe") {
        if bytes.len() >= 8 {
            let nfat = u32::from_be_bytes([bytes[4], bytes[5], bytes[6], bytes[7]]);
            if (1..=32).contains(&nfat) {
                return (ObjectKind::Binary, "macho_fat", "application/x-mach-binary");
            }
            let major = u16::from_be_bytes([bytes[6], bytes[7]]);
            if (45..=70).contains(&major) {
                return (ObjectKind::Binary, "jvm_class", "application/java-vm");
            }
        }
    }
    if bytes.starts_with(b"dex\n") {
        return (ObjectKind::Binary, "dex", "application/vnd.android.dex");
    }
    if bytes.starts_with(b"\0asm") {
        return (ObjectKind::Binary, "wasm", "application/wasm");
    }
    if bytes.starts_with(b"%PDF-") {
        return (ObjectKind::Document, "pdf", "application/pdf");
    }
    if bytes.starts_with(b"PK\x03\x04") {
        if lower.ends_with(".apk") {
            return (ObjectKind::Package, "apk", "application/vnd.android.package-archive");
        }
        if lower.ends_with(".jar") {
            return (ObjectKind::Archive, "jar", "application/java-archive");
        }
        return (ObjectKind::Archive, "zip", "application/zip");
    }
    if lower.ends_with(".so") || lower.ends_with(".elf") {
        return (ObjectKind::Binary, "elf", "application/x-elf");
    }
    if lower.ends_with(".dex") {
        return (ObjectKind::Binary, "dex", "application/vnd.android.dex");
    }
    if lower.ends_with(".class") {
        return (ObjectKind::Binary, "jvm_class", "application/java-vm");
    }
    if lower.ends_with(".dll") || lower.ends_with(".exe") {
        return (
            ObjectKind::Binary,
            "pe",
            "application/vnd.microsoft.portable-executable",
        );
    }
    if lower.ends_with(".dylib") {
        return (ObjectKind::Binary, "macho", "application/x-mach-binary");
    }
    if lower.contains("payload/") && lower.contains(".app/") && !lower.contains('.') {
        if matches!(
            bytes.get(..4),
            Some(
                b"\xcf\xfa\xed\xfe"
                    | b"\xce\xfa\xed\xfe"
                    | b"\xfe\xed\xfa\xcf"
                    | b"\xfe\xed\xfa\xce"
                    | b"\xca\xfe\xba\xbe"
            )
        ) {
            return (ObjectKind::Binary, "macho", "application/x-mach-binary");
        }
    }
    (
        ObjectKind::File,
        "unknown",
        "application/octet-stream",
    )
}

fn should_auto_dig_object(
    object: &UniversalObject,
    selected: &[ObjectAnalyzerKind],
    analyses: &[ObjectAnalysisSummary],
) -> bool {
    if matches!(object.kind, ObjectKind::Directory) {
        return false;
    }
    if selected.contains(&ObjectAnalyzerKind::UnknownBlob) {
        return true;
    }
    let has_embedded_hits = analyses.iter().any(|analysis| {
        analysis
            .details
            .get("embedded_signature_count")
            .and_then(|value| value.as_u64())
            .unwrap_or(0)
            > 0
            || analysis
                .details
                .get("suggested_followups")
                .and_then(|value| value.as_array())
                .is_some_and(|items| {
                    items.iter().any(|item| {
                        item.as_str()
                            .is_some_and(|text| text.contains("object_carve_signatures"))
                    })
                })
    });
    if has_embedded_hits {
        return true;
    }
    if matches!(object.kind, ObjectKind::Text) {
        return false;
    }
    matches!(
        object.format.as_deref(),
        Some(
            "unknown"
                | "bin"
                | "raw"
                | "data"
                | "7z"
                | "rar"
                | "pe"
                | "dll"
                | "exe"
                | "sys"
                | "ar"
        ) | None
    )
}

fn lightweight_carved_object(
    parent: &UniversalObject,
    hit: &ObjectSignatureHit,
    bytes: &[u8],
    artifact: &ArtifactHandle,
) -> UniversalObject {
    let hash = artifact.hash_blake3.clone();
    let id = format!("obj:{hash}");
    let (kind, format, media_type) = classify_carved_format(&hit.format, bytes);
    let display_name = format!(
        "{parent_name}!/{format}@{offset:#x}",
        parent_name = parent.display_name,
        format = format,
        offset = hit.offset
    );
    let mut flags = vec![
        "carved".to_string(),
        "auto_dig".to_string(),
        format!("from:{parent_format}", parent_format = parent.format.as_deref().unwrap_or("unknown")),
    ];
    if matches!(format, "elf" | "pe" | "macho" | "macho_fat") {
        flags.push("native_binary_candidate".to_string());
    }
    if is_probably_text_bytes(bytes) {
        flags.push("text_like".to_string());
    }
    UniversalObject {
        id: id.clone(),
        path: None,
        display_name,
        kind,
        format: Some(format.to_string()),
        size: bytes.len() as u64,
        hash_blake3: Some(hash),
        media_type: Some(media_type.to_string()),
        entropy: (!bytes.is_empty()).then(|| {
            let mut histogram = [0usize; 256];
            for byte in bytes {
                histogram[*byte as usize] += 1;
            }
            shannon_entropy_from_histogram(&histogram, bytes.len())
        }),
        depth: parent.depth.saturating_add(1),
        flags,
        metadata: serde_json::json!({
            "carved_from": parent.id,
            "carve_offset": hit.offset,
            "carve_length": bytes.len(),
            "signature": hit.signature,
            "confidence": hit.confidence,
            "artifact": artifact,
            "magic": bytes.iter().take(16).map(|byte| format!("{byte:02x}")).collect::<Vec<_>>().join(""),
        }),
        analyses: Vec::new(),
        evidence_ids: vec![format!("object:{id}:identity")],
    }
}

fn classify_carved_format(format: &str, bytes: &[u8]) -> (ObjectKind, &'static str, &'static str) {
    match format {
        "elf" => (ObjectKind::Binary, "elf", "application/x-elf"),
        "pe" => (
            ObjectKind::Binary,
            "pe",
            "application/vnd.microsoft.portable-executable",
        ),
        "macho" => (ObjectKind::Binary, "macho", "application/x-mach-binary"),
        "macho_fat" => (ObjectKind::Binary, "macho_fat", "application/x-mach-binary"),
        "zip" => (ObjectKind::Archive, "zip", "application/zip"),
        "pdf" => (ObjectKind::Document, "pdf", "application/pdf"),
        "png" => (ObjectKind::Image, "png", "image/png"),
        "jpeg" => (ObjectKind::Image, "jpeg", "image/jpeg"),
        "gif" => (ObjectKind::Image, "gif", "image/gif"),
        "tiff" => (ObjectKind::Image, "tiff", "image/tiff"),
        "riff" => (ObjectKind::File, "riff", "application/octet-stream"),
        "pcap" | "pcapng" => (
            ObjectKind::NetworkCapture,
            if format == "pcapng" { "pcapng" } else { "pcap" },
            "application/vnd.tcpdump.pcap",
        ),
        "gzip" => (ObjectKind::Archive, "gzip", "application/gzip"),
        "bzip2" => (ObjectKind::Archive, "bzip2", "application/x-bzip2"),
        "xz" => (ObjectKind::Archive, "xz", "application/x-xz"),
        "zstd" => (ObjectKind::Archive, "zstd", "application/zstd"),
        "7z" => (ObjectKind::Archive, "7z", "application/x-7z-compressed"),
        "cab" => (
            ObjectKind::Archive,
            "cab",
            "application/vnd.ms-cab-compressed",
        ),
        "rar" => (ObjectKind::Archive, "rar", "application/vnd.rar"),
        "dex" => (ObjectKind::Binary, "dex", "application/vnd.android.dex"),
        "jvm_class" => (ObjectKind::Binary, "jvm_class", "application/java-vm"),
        "pyc" => (ObjectKind::Binary, "pyc", "application/x-python-bytecode"),
        "ole" => (ObjectKind::Document, "ole", "application/x-ole-storage"),
        "ar" => (ObjectKind::Archive, "ar", "application/x-archive"),
        "wasm" => (ObjectKind::Binary, "wasm", "application/wasm"),
        "sqlite" => (ObjectKind::Database, "sqlite", "application/vnd.sqlite3"),
        "flac" => (ObjectKind::File, "flac", "audio/flac"),
        "ogg" => (ObjectKind::File, "ogg", "application/ogg"),
        "mp4" => (ObjectKind::File, "mp4", "video/mp4"),
        "qcow2" => (
            ObjectKind::FilesystemImage,
            "qcow2",
            "application/x-qemu-disk",
        ),
        "woff" => (ObjectKind::File, "woff", "font/woff"),
        "woff2" => (ObjectKind::File, "woff2", "font/woff2"),
        _ if bytes.starts_with(b"%PDF-") => (ObjectKind::Document, "pdf", "application/pdf"),
        _ if bytes.starts_with(b"\x89PNG\r\n\x1a\n") => (ObjectKind::Image, "png", "image/png"),
        _ => (
            ObjectKind::File,
            "unknown",
            "application/octet-stream",
        ),
    }
}

fn is_probably_text_bytes(bytes: &[u8]) -> bool {
    if bytes.is_empty() {
        return true;
    }
    let sample = &bytes[..bytes.len().min(4096)];
    let suspicious = sample
        .iter()
        .filter(|byte| !(byte.is_ascii_graphic() || byte.is_ascii_whitespace() || **byte == 0))
        .count();
    suspicious * 100 / sample.len() < 5
        && sample.iter().filter(|byte| **byte == 0).count() * 100 / sample.len() < 1
}

fn analyze_object_unknown_blob(object: &UniversalObject, bytes: &[u8]) -> ObjectAnalysisSummary {
    let mut histogram = [0usize; 256];
    for byte in bytes {
        histogram[*byte as usize] += 1;
    }
    let entropy = shannon_entropy_from_histogram(&histogram, bytes.len());
    let ascii_printable = bytes
        .iter()
        .filter(|b| b.is_ascii_graphic() || **b == b' ')
        .count();
    let unique = histogram.iter().filter(|c| **c > 0).count();
    let signatures = scan_embedded_signatures(bytes, 24);
    let signature_preview = signatures
        .iter()
        .take(16)
        .map(|hit| {
            serde_json::json!({
                "offset": hit.offset,
                "format": hit.format,
                "signature": hit.signature,
                "confidence": hit.confidence,
                "suggested_length": hit.suggested_length,
            })
        })
        .collect::<Vec<_>>();
    let content_class = if bytes.is_empty() {
        "empty"
    } else if ascii_printable * 100 / bytes.len().max(1) >= 90 {
        "text_like"
    } else if entropy >= 7.5 {
        "compressed_or_encrypted_like"
    } else if !signatures.is_empty() {
        "container_or_embedded_payload"
    } else if unique <= 24 {
        "low_alphabet"
    } else {
        "opaque_binary"
    };
    let mut followups = Vec::new();
    if !signatures.is_empty() {
        followups.push("object_carve_signatures");
        followups.push("object_scan_signatures");
    }
    if content_class == "text_like" {
        followups.push("structured_text");
    }
    if entropy >= 7.2 {
        followups.push("entropy_review");
    }
    ObjectAnalysisSummary {
        analyzer: "unknown_blob".to_string(),
        status: ObjectAnalysisStatus::Completed,
        summary: format!(
            "Unknown blob class {content_class}: entropy {entropy:.3}, {} embedded signature hit(s)",
            signatures.len()
        ),
        details: serde_json::json!({
            "size": bytes.len(),
            "entropy": entropy,
            "unique_bytes": unique,
            "ascii_printable_count": ascii_printable,
            "ascii_printable_ratio": ratio(ascii_printable, bytes.len()),
            "content_class": content_class,
            "magic": bytes.iter().take(16).map(|b| format!("{b:02x}")).collect::<Vec<_>>().join(""),
            "embedded_signature_count": signatures.len(),
            "embedded_signatures": signature_preview,
            "suggested_followups": followups,
        }),
        evidence_ids: vec![format!("analysis:{}:unknown_blob", object.id)],
    }
}

fn extract_iso_bmff_summary(bytes: &[u8]) -> Result<serde_json::Value> {
    let mut warnings = Vec::new();
    let mut boxes = Vec::new();
    let mut cursor = 0usize;
    let mut major_brand = None;
    let mut minor_version = None;
    let mut compatible_brands = Vec::new();
    while cursor + 8 <= bytes.len() && boxes.len() < 128 {
        let size32 = read_be_u32(bytes, cursor).context("missing ISO BMFF box size")?;
        let kind = std::str::from_utf8(&bytes[cursor + 4..cursor + 8])
            .unwrap_or("????")
            .to_string();
        let (header_size, size) = if size32 == 1 {
            if cursor + 16 > bytes.len() {
                warnings.push(format!("truncated 64-bit box header for {kind} at {cursor}"));
                break;
            }
            let size64 = read_be_u64(bytes, cursor + 8).context("missing ISO BMFF largesize")?;
            (16usize, size64 as usize)
        } else if size32 == 0 {
            (8usize, bytes.len() - cursor)
        } else {
            (8usize, size32 as usize)
        };
        if size < header_size {
            warnings.push(format!("invalid box size {size} for {kind} at {cursor}"));
            break;
        }
        let end = cursor.saturating_add(size);
        if end > bytes.len() {
            warnings.push(format!(
                "box {kind} at {cursor} declares end {end} beyond object size {}",
                bytes.len()
            ));
        }
        let data_end = end.min(bytes.len());
        if kind == "ftyp" && data_end >= cursor + header_size + 8 {
            let brand_start = cursor + header_size;
            major_brand = std::str::from_utf8(&bytes[brand_start..brand_start + 4])
                .ok()
                .map(str::to_string);
            minor_version = read_be_u32(bytes, brand_start + 4);
            let mut brand_cursor = brand_start + 8;
            while brand_cursor + 4 <= data_end && compatible_brands.len() < 16 {
                if let Ok(brand) = std::str::from_utf8(&bytes[brand_cursor..brand_cursor + 4]) {
                    compatible_brands.push(brand.to_string());
                }
                brand_cursor += 4;
            }
        }
        let box_offset = cursor;
        boxes.push(serde_json::json!({
            "offset": box_offset,
            "type": kind,
            "size": size,
            "header_size": header_size,
            "truncated": end > bytes.len(),
        }));
        if size == 0 {
            break;
        }
        let next = end.max(cursor + header_size);
        if next <= cursor {
            warnings.push("ISO BMFF parser failed to advance".to_string());
            break;
        }
        cursor = next;
    }
    Ok(serde_json::json!({
        "major_brand": major_brand,
        "minor_version": minor_version,
        "compatible_brands": compatible_brands,
        "box_count": boxes.len(),
        "boxes": boxes,
        "warnings": warnings,
        "actual_size": bytes.len(),
    }))
}

fn extract_ar_members(
    bytes: &[u8],
    limit: usize,
) -> (Vec<serde_json::Value>, bool, Vec<String>) {
    let mut members = Vec::new();
    let mut warnings = Vec::new();
    let mut cursor = 8usize;
    let mut truncated = false;
    while cursor + 60 <= bytes.len() {
        if members.len() >= limit {
            truncated = true;
            break;
        }
        let header = &bytes[cursor..cursor + 60];
        let name = String::from_utf8_lossy(&header[0..16]).trim().to_string();
        let size_text = String::from_utf8_lossy(&header[48..58]).trim().to_string();
        let Ok(size) = size_text.parse::<usize>() else {
            warnings.push(format!("invalid ar member size at {cursor}: {size_text}"));
            break;
        };
        let data_offset = cursor + 60;
        let data_end = data_offset.saturating_add(size);
        if data_end > bytes.len() {
            warnings.push(format!(
                "ar member {name} at {cursor} truncated: need {size}, have {}",
                bytes.len().saturating_sub(data_offset)
            ));
            members.push(serde_json::json!({
                "name": name,
                "offset": cursor,
                "data_offset": data_offset,
                "size": size,
                "truncated": true,
            }));
            break;
        }
        members.push(serde_json::json!({
            "name": name,
            "offset": cursor,
            "data_offset": data_offset,
            "size": size,
            "truncated": false,
        }));
        cursor = data_end + (data_end % 2);
    }
    (members, truncated, warnings)
}

fn extract_sfnt_table_tags(bytes: &[u8], num_tables: usize, limit: usize) -> Vec<String> {
    let mut tables = Vec::new();
    let mut cursor = 12usize;
    for _ in 0..num_tables.min(limit) {
        if cursor + 16 > bytes.len() {
            break;
        }
        let tag = std::str::from_utf8(&bytes[cursor..cursor + 4])
            .unwrap_or("????")
            .to_string();
        tables.push(tag);
        cursor += 16;
    }
    tables
}

fn analyze_object_byte_histogram(object: &UniversalObject, bytes: &[u8]) -> ObjectAnalysisSummary {
    let mut histogram = [0usize; 256];
    for byte in bytes {
        histogram[*byte as usize] += 1;
    }
    let zero_count = histogram[0];
    let ascii_printable_count = bytes
        .iter()
        .filter(|byte| byte.is_ascii_graphic() || **byte == b' ')
        .count();
    let ascii_control_count = bytes
        .iter()
        .filter(|byte| byte.is_ascii_control() && **byte != b'\t' && **byte != b'\n' && **byte != b'\r')
        .count();
    let high_bit_count = bytes.iter().filter(|byte| **byte >= 0x80).count();
    let unique_bytes = histogram.iter().filter(|count| **count > 0).count();
    let entropy = shannon_entropy_from_histogram(&histogram, bytes.len());
    let null_runs = count_null_runs(bytes);
    let content_class = classify_byte_content(
        bytes.len(),
        ascii_printable_count,
        zero_count,
        high_bit_count,
        unique_bytes,
        entropy,
    );
    let mut tags = Vec::new();
    if entropy >= 7.5 {
        tags.push("high_entropy");
    } else if entropy >= 6.5 {
        tags.push("elevated_entropy");
    } else if entropy <= 3.0 && bytes.len() >= 32 {
        tags.push("low_entropy");
    }
    if ratio(ascii_printable_count, bytes.len()) >= 0.85 {
        tags.push("text_like");
    }
    if ratio(zero_count, bytes.len()) >= 0.25 {
        tags.push("sparse_or_padded");
    }
    if unique_bytes <= 16 && bytes.len() >= 64 {
        tags.push("low_alphabet");
    }
    if content_class == "compressed_or_encrypted_like" {
        tags.push("compressed_or_encrypted_like");
    }
    if content_class == "structured_binary" {
        tags.push("structured_binary");
    }
    if null_runs >= 4 {
        tags.push("null_runs");
    }
    let top_bytes = top_histogram_bytes(&histogram, 16);
    ObjectAnalysisSummary {
        analyzer: "byte_histogram".to_string(),
        status: ObjectAnalysisStatus::Completed,
        summary: format!(
            "Byte histogram over {} bytes: class {}, entropy {:.3}, {} printable ASCII, {} unique bytes",
            bytes.len(),
            content_class,
            entropy,
            ascii_printable_count,
            unique_bytes
        ),
        details: serde_json::json!({
            "size": bytes.len(),
            "zero_count": zero_count,
            "ascii_printable_count": ascii_printable_count,
            "ascii_control_count": ascii_control_count,
            "high_bit_count": high_bit_count,
            "unique_bytes": unique_bytes,
            "entropy": entropy,
            "null_runs": null_runs,
            "content_class": content_class,
            "tags": tags,
            "ascii_printable_ratio": ratio(ascii_printable_count, bytes.len()),
            "zero_ratio": ratio(zero_count, bytes.len()),
            "high_bit_ratio": ratio(high_bit_count, bytes.len()),
            "top_bytes": top_bytes,
            "magic_hex": bytes.iter().take(16).map(|byte| format!("{byte:02x}")).collect::<Vec<_>>().join(""),
        }),
        evidence_ids: vec![format!("analysis:{}:byte_histogram", object.id)],
    }
}

fn analyze_object_strings(object: &UniversalObject, bytes: &[u8]) -> ObjectAnalysisSummary {
    let ascii = extract_ascii_strings(bytes, 4, 160);
    let utf16le = extract_utf16_strings(bytes, true, 4, 80);
    let utf16be = extract_utf16_strings(bytes, false, 4, 40);
    let interesting = score_interesting_strings(&ascii, &utf16le, &utf16be);
    let total = ascii.len() + utf16le.len() + utf16be.len();
    ObjectAnalysisSummary {
        analyzer: "strings".to_string(),
        status: ObjectAnalysisStatus::Completed,
        summary: format!(
            "Extracted {} strings ({} ascii, {} utf16le, {} utf16be, {} interesting)",
            total,
            ascii.len(),
            utf16le.len(),
            utf16be.len(),
            interesting.len()
        ),
        details: serde_json::json!({
            "min_length": 4,
            "limit": {
                "ascii": 160,
                "utf16le": 80,
                "utf16be": 40
            },
            "ascii_count": ascii.len(),
            "utf16le_count": utf16le.len(),
            "utf16be_count": utf16be.len(),
            "interesting_count": interesting.len(),
            "interesting": interesting,
            "strings": ascii,
            "utf16le": utf16le,
            "utf16be": utf16be,
        }),
        evidence_ids: vec![format!("analysis:{}:strings", object.id)],
    }
}

fn analyze_object_structured_text(object: &UniversalObject, bytes: &[u8]) -> ObjectAnalysisSummary {
    let Some(text) = text_preview_for_analysis(bytes, 512 * 1024) else {
        return ObjectAnalysisSummary {
            analyzer: "structured_text".to_string(),
            status: ObjectAnalysisStatus::Skipped,
            summary: "Object is not UTF-8 text or contains control bytes".to_string(),
            details: serde_json::json!({ "reason": "not_text" }),
            evidence_ids: vec![format!("analysis:{}:structured_text", object.id)],
        };
    };

    let format = object.format.as_deref().unwrap_or("unknown");
    let mut paths = Vec::new();
    let mut top_keys = BTreeSet::new();
    let mut interesting = BTreeSet::new();
    let mut warnings = Vec::new();
    let mut parse_status = "heuristic".to_string();
    let mut value_counts = BTreeMap::<String, usize>::new();
    let mut model_index_summary = serde_json::Value::Null;

    match format {
        "json" => match serde_json::from_str::<serde_json::Value>(&text) {
            Ok(value) => {
                parse_status = "parsed_json".to_string();
                collect_json_structure(
                    &value,
                    "$",
                    0,
                    &mut paths,
                    &mut top_keys,
                    &mut interesting,
                    &mut value_counts,
                );
                model_index_summary =
                    summarize_safetensors_index(&value, &mut interesting, &mut warnings);
            }
            Err(err) => warnings.push(format!("json parse failed: {err}")),
        },
        "safetensors_index" => match serde_json::from_str::<serde_json::Value>(&text) {
            Ok(value) => {
                parse_status = "parsed_safetensors_index".to_string();
                collect_json_structure(
                    &value,
                    "$",
                    0,
                    &mut paths,
                    &mut top_keys,
                    &mut interesting,
                    &mut value_counts,
                );
                model_index_summary =
                    summarize_safetensors_index(&value, &mut interesting, &mut warnings);
            }
            Err(err) => warnings.push(format!("SafeTensors index JSON parse failed: {err}")),
        },
        "toml" => match text.parse::<toml::Value>() {
            Ok(value) => {
                parse_status = "parsed_toml".to_string();
                collect_toml_structure(
                    &value,
                    "$",
                    0,
                    &mut paths,
                    &mut top_keys,
                    &mut interesting,
                    &mut value_counts,
                );
            }
            Err(err) => warnings.push(format!("toml parse failed: {err}")),
        },
        _ => {}
    }

    if paths.is_empty() {
        collect_text_structure(
            &text,
            format,
            &mut paths,
            &mut top_keys,
            &mut interesting,
            &mut value_counts,
        );
    }
    collect_interesting_text_signals(&text, &mut interesting);

    let line_count = text.lines().count();
    let truncated = bytes.len() > text.len();
    let path_preview = paths.into_iter().take(200).collect::<Vec<_>>();
    let top_keys = top_keys.into_iter().take(100).collect::<Vec<_>>();
    let interesting = interesting.into_iter().take(100).collect::<Vec<_>>();
    let risk_signal_count = interesting.len();
    let summary = format!(
        "Structured text {} with {} lines, {} paths, {} top-level keys, {} interesting signals",
        parse_status,
        line_count,
        path_preview.len(),
        top_keys.len(),
        risk_signal_count
    );

    ObjectAnalysisSummary {
        analyzer: "structured_text".to_string(),
        status: if warnings.is_empty() {
            ObjectAnalysisStatus::Completed
        } else {
            ObjectAnalysisStatus::Partial
        },
        summary,
        details: serde_json::json!({
            "format": format,
            "parse_status": parse_status,
            "line_count": line_count,
            "truncated": truncated,
            "top_keys": top_keys,
            "paths": path_preview,
            "value_counts": value_counts,
            "interesting_signals": interesting,
            "model_index": model_index_summary,
            "warnings": warnings,
        }),
        evidence_ids: vec![format!("analysis:{}:structured_text", object.id)],
    }
}

fn analyze_object_zip_listing(object: &UniversalObject, bytes: &[u8]) -> ObjectAnalysisSummary {
    let cursor = std::io::Cursor::new(bytes);
    match zip::ZipArchive::new(cursor) {
        Ok(mut archive) => {
            let entry_count = archive.len();
            let mut entries = Vec::new();
            for index in 0..entry_count.min(256) {
                match archive.by_index(index) {
                    Ok(file) => entries.push(serde_json::json!({
                        "index": index,
                        "name": file.name(),
                        "is_dir": file.is_dir(),
                        "compressed_size": file.compressed_size(),
                        "uncompressed_size": file.size(),
                    })),
                    Err(err) => entries.push(serde_json::json!({
                        "index": index,
                        "error": err.to_string(),
                    })),
                }
            }
            let truncated = entry_count > entries.len();
            ObjectAnalysisSummary {
                analyzer: "zip_listing".to_string(),
                status: if truncated {
                    ObjectAnalysisStatus::Partial
                } else {
                    ObjectAnalysisStatus::Completed
                },
                summary: format!("Listed {} of {entry_count} ZIP entries", entries.len()),
                details: serde_json::json!({
                    "entry_count": entry_count,
                    "listed_count": entries.len(),
                    "truncated": truncated,
                    "entries": entries,
                }),
                evidence_ids: vec![format!("analysis:{}:zip_listing", object.id)],
            }
        }
        Err(err) => ObjectAnalysisSummary {
            analyzer: "zip_listing".to_string(),
            status: ObjectAnalysisStatus::Failed,
            summary: format!("ZIP listing failed: {err}"),
            details: serde_json::json!({ "error": err.to_string() }),
            evidence_ids: vec![format!("analysis:{}:zip_listing", object.id)],
        },
    }
}

