#[derive(Debug)]
struct PyTorchModelSummary {
    container: &'static str,
    pickle_count: usize,
    storage_count: usize,
    risk_signal_count: usize,
    truncated: bool,
    warnings: Vec<String>,
    details: serde_json::Value,
}

#[derive(Debug)]
struct PyTorchEntrySummary {
    name: String,
    size: u64,
    compressed_size: u64,
    is_dir: bool,
    role: &'static str,
}

#[derive(Debug)]
struct PickleScanSummary {
    protocol: Option<u8>,
    opcode_count: usize,
    globals: Vec<String>,
    string_hits: Vec<String>,
    risky_opcode_counts: BTreeMap<String, usize>,
    truncated: bool,
    warnings: Vec<String>,
}

const PYTORCH_ZIP_ENTRY_LIMIT: usize = 512;
const PYTORCH_PICKLE_SCAN_LIMIT: usize = 512 * 1024;
const PYTORCH_PICKLE_GLOBAL_LIMIT: usize = 128;
const PYTORCH_PICKLE_STRING_LIMIT: usize = 128;

fn extract_pytorch_model_summary(
    object: &UniversalObject,
    bytes: &[u8],
) -> Result<PyTorchModelSummary> {
    let mut warnings = Vec::new();
    let mut risk_signals = BTreeSet::<String>::new();
    risk_signals.insert("pytorch_model_present".to_string());

    if is_pickle_like_bytes(bytes) {
        let pickle = scan_pickle_bytes(bytes, &mut warnings);
        collect_pickle_risk_signals(&pickle, &mut risk_signals);
        let pickle_values = vec![pickle_scan_json("object", &pickle)];
        let details = serde_json::json!({
            "format": object.format.as_deref().unwrap_or("pytorch"),
            "container": "pickle",
            "entry_count": 0,
            "pickle_count": 1,
            "storage_count": 0,
            "entries": [],
            "pickles": pickle_values,
            "risk_signals": risk_signals.into_iter().collect::<Vec<_>>(),
            "warnings": warnings,
            "truncated": pickle.truncated,
        });
        return Ok(PyTorchModelSummary {
            container: "pickle",
            pickle_count: 1,
            storage_count: 0,
            risk_signal_count: details["risk_signals"].as_array().map_or(0, Vec::len),
            truncated: details["truncated"].as_bool().unwrap_or(false),
            warnings: details["warnings"]
                .as_array()
                .map(|items| {
                    items
                        .iter()
                        .filter_map(|item| item.as_str().map(ToOwned::to_owned))
                        .collect()
                })
                .unwrap_or_default(),
            details,
        });
    }

    let cursor = std::io::Cursor::new(bytes);
    let mut archive =
        zip::ZipArchive::new(cursor).context("failed to parse PyTorch ZIP container")?;
    let entry_count = archive.len();
    let entry_limit = entry_count.min(PYTORCH_ZIP_ENTRY_LIMIT);
    let mut entries = Vec::new();
    let mut pickles = Vec::new();
    let mut storage_count = 0usize;
    let mut has_version = false;
    let mut has_byteorder = false;
    for index in 0..entry_limit {
        let mut file = archive.by_index(index)?;
        let name = file.name().to_string();
        let role = pytorch_entry_role(&name, file.is_dir());
        if role == "storage" {
            storage_count += 1;
        }
        if name.ends_with("version") {
            has_version = true;
        }
        if name.ends_with("byteorder") {
            has_byteorder = true;
        }
        let entry = PyTorchEntrySummary {
            name: name.clone(),
            size: file.size(),
            compressed_size: file.compressed_size(),
            is_dir: file.is_dir(),
            role,
        };
        if role == "pickle" {
            let mut pickle_bytes = Vec::new();
            let read_limit = file.size().min(PYTORCH_PICKLE_SCAN_LIMIT as u64) as usize;
            let mut limited = file.by_ref().take(read_limit as u64);
            limited
                .read_to_end(&mut pickle_bytes)
                .with_context(|| format!("failed to read PyTorch pickle entry {name}"))?;
            let pickle = scan_pickle_bytes(&pickle_bytes, &mut warnings);
            collect_pickle_risk_signals(&pickle, &mut risk_signals);
            pickles.push(pickle_scan_json(&name, &pickle));
        }
        entries.push(entry);
    }
    if entry_count > entry_limit {
        warnings.push(format!(
            "PyTorch ZIP entry listing truncated at {entry_limit} of {entry_count} entries"
        ));
        risk_signals.insert("large_pytorch_archive".to_string());
    }
    if pickles.is_empty() {
        warnings.push("PyTorch archive has no pickle entry".to_string());
        risk_signals.insert("model_without_pickle".to_string());
    }
    if !has_version {
        risk_signals.insert("pytorch_archive_missing_version".to_string());
    }
    if !has_byteorder {
        risk_signals.insert("pytorch_archive_missing_byteorder".to_string());
    }
    if !warnings.is_empty() {
        risk_signals.insert("pytorch_integrity_warnings".to_string());
    }
    let entry_values = entries
        .iter()
        .map(|entry| {
            serde_json::json!({
                "name": entry.name,
                "size": entry.size,
                "compressed_size": entry.compressed_size,
                "is_dir": entry.is_dir,
                "role": entry.role,
            })
        })
        .collect::<Vec<_>>();
    let risk_signal_values = risk_signals.into_iter().take(256).collect::<Vec<_>>();
    let truncated = entry_count > entry_limit;
    let details = serde_json::json!({
        "format": object.format.as_deref().unwrap_or("pytorch"),
        "container": "zip",
        "entry_count": entry_count,
        "listed_entry_count": entries.len(),
        "pickle_count": pickles.len(),
        "storage_count": storage_count,
        "has_version": has_version,
        "has_byteorder": has_byteorder,
        "entries": entry_values,
        "pickles": pickles,
        "risk_signals": risk_signal_values,
        "warnings": warnings,
        "truncated": truncated,
    });

    Ok(PyTorchModelSummary {
        container: "zip",
        pickle_count: details["pickle_count"].as_u64().unwrap_or(0) as usize,
        storage_count,
        risk_signal_count: details["risk_signals"].as_array().map_or(0, Vec::len),
        truncated,
        warnings: details["warnings"]
            .as_array()
            .map(|items| {
                items
                    .iter()
                    .filter_map(|item| item.as_str().map(ToOwned::to_owned))
                    .collect()
            })
            .unwrap_or_default(),
        details,
    })
}

#[derive(Debug)]
struct GgufModelSummary {
    version: u32,
    tensor_count: u64,
    metadata_count: u64,
    tensor_type_count: usize,
    risk_signal_count: usize,
    truncated: bool,
    warnings: Vec<String>,
    details: serde_json::Value,
}

#[derive(Debug)]
struct GgufTensorInfo {
    name: String,
    shape: Vec<u64>,
    tensor_type: u32,
    offset: u64,
    role: &'static str,
}

#[derive(Debug)]
struct GgufParseState<'a> {
    bytes: &'a [u8],
    cursor: usize,
}

const GGUF_MAGIC: &[u8; 4] = b"GGUF";
const GGUF_METADATA_LIMIT: u64 = 2048;
const GGUF_TENSOR_LIMIT: u64 = 4096;
const GGUF_STRING_LIMIT: u64 = 1 * 1024 * 1024;
const GGUF_ARRAY_ITEM_LIMIT: u64 = 64;

fn extract_gguf_model_summary(object: &UniversalObject, bytes: &[u8]) -> Result<GgufModelSummary> {
    let mut parser = GgufParseState { bytes, cursor: 0 };
    parser.expect_magic(GGUF_MAGIC, "GGUF magic")?;
    let version = parser.read_u32("GGUF version")?;
    let tensor_count = parser.read_u64("GGUF tensor count")?;
    let metadata_kv_count = parser.read_u64("GGUF metadata count")?;
    if version == 0 {
        anyhow::bail!("GGUF version is zero");
    }
    if version > 16 {
        anyhow::bail!("GGUF version {version} is outside the parser guardrail");
    }

    let mut warnings = Vec::new();
    let mut risk_signals = BTreeSet::<String>::new();
    risk_signals.insert("gguf_model_present".to_string());
    if metadata_kv_count > GGUF_METADATA_LIMIT {
        warnings.push(format!(
            "GGUF metadata listing truncated at {GGUF_METADATA_LIMIT} of {metadata_kv_count} items"
        ));
        risk_signals.insert("large_gguf_metadata".to_string());
    }
    if tensor_count > GGUF_TENSOR_LIMIT {
        warnings.push(format!(
            "GGUF tensor listing truncated at {GGUF_TENSOR_LIMIT} of {tensor_count} tensors"
        ));
        risk_signals.insert("large_gguf_tensor_table".to_string());
    }

    let mut metadata = BTreeMap::<String, serde_json::Value>::new();
    let metadata_to_read = metadata_kv_count.min(GGUF_METADATA_LIMIT);
    for _ in 0..metadata_to_read {
        let key = parser.read_string("GGUF metadata key")?;
        let value = parser.read_metadata_value(&mut warnings)?;
        collect_gguf_metadata_risk_signals(&key, &value, &mut risk_signals);
        metadata.insert(key, value);
    }
    if metadata_kv_count > metadata_to_read {
        parser.skip_unparsed_metadata(metadata_kv_count - metadata_to_read, &mut warnings);
    }

    let alignment = metadata
        .get("general.alignment")
        .and_then(json_u64_from_value)
        .unwrap_or(32)
        .max(1);
    let mut tensors = Vec::new();
    let mut tensor_type_counts = BTreeMap::<String, usize>::new();
    let mut role_counts = BTreeMap::<String, usize>::new();
    let tensors_to_read = tensor_count.min(GGUF_TENSOR_LIMIT);
    for _ in 0..tensors_to_read {
        let tensor = parser.read_tensor_info(&mut warnings)?;
        *tensor_type_counts
            .entry(gguf_tensor_type_name(tensor.tensor_type).to_string())
            .or_default() += 1;
        *role_counts.entry(tensor.role.to_string()).or_default() += 1;
        collect_gguf_tensor_risk_signals(&tensor, &mut risk_signals);
        tensors.push(tensor);
    }
    if tensor_count > tensors_to_read {
        parser.skip_unparsed_tensors(tensor_count - tensors_to_read, &mut warnings);
    }

    let tensor_info_end = parser.cursor as u64;
    let tensor_data_offset = align_to(tensor_info_end, alignment).unwrap_or(tensor_info_end);
    if tensor_data_offset > bytes.len() as u64 {
        warnings.push("GGUF tensor data offset extends beyond object bounds".to_string());
        risk_signals.insert("gguf_integrity_warnings".to_string());
    }
    let data_bytes =
        (bytes.len() as u64).saturating_sub(tensor_data_offset.min(bytes.len() as u64));
    let max_tensor_offset = tensors
        .iter()
        .map(|tensor| tensor.offset)
        .max()
        .unwrap_or(0);
    if max_tensor_offset > data_bytes {
        warnings.push("GGUF tensor offsets extend past the tensor data section".to_string());
    }
    if tensor_count == 0 {
        risk_signals.insert("model_without_tensors".to_string());
    }
    if !warnings.is_empty() {
        risk_signals.insert("gguf_integrity_warnings".to_string());
    }

    let tensor_values = tensors
        .iter()
        .take(512)
        .map(|tensor| {
            serde_json::json!({
                "name": tensor.name,
                "shape": tensor.shape,
                "rank": tensor.shape.len(),
                "tensor_type": tensor.tensor_type,
                "tensor_type_name": gguf_tensor_type_name(tensor.tensor_type),
                "offset": tensor.offset,
                "role": tensor.role,
            })
        })
        .collect::<Vec<_>>();
    let metadata_values = metadata
        .iter()
        .take(256)
        .map(|(key, value)| {
            serde_json::json!({
                "key": key,
                "value": value,
            })
        })
        .collect::<Vec<_>>();
    let tensor_type_values = tensor_type_counts
        .iter()
        .map(|(tensor_type, count)| {
            serde_json::json!({
                "tensor_type": tensor_type,
                "count": count,
            })
        })
        .collect::<Vec<_>>();
    let role_values = role_counts
        .iter()
        .map(|(role, count)| {
            serde_json::json!({
                "role": role,
                "count": count,
            })
        })
        .collect::<Vec<_>>();
    let risk_signal_values = risk_signals.into_iter().take(256).collect::<Vec<_>>();
    let truncated = metadata_kv_count > metadata_to_read || tensor_count > tensors_to_read;
    let details = serde_json::json!({
        "format": object.format.as_deref().unwrap_or("gguf"),
        "version": version,
        "tensor_count": tensor_count,
        "listed_tensor_count": tensors.len(),
        "metadata_kv_count": metadata_kv_count,
        "listed_metadata_kv_count": metadata.len(),
        "metadata": metadata_values,
        "tensor_type_counts": tensor_type_values,
        "role_counts": role_values,
        "tensors": tensor_values,
        "layout": {
            "alignment": alignment,
            "tensor_info_end": tensor_info_end,
            "tensor_data_offset": tensor_data_offset,
            "tensor_data_size": data_bytes,
            "max_tensor_offset": max_tensor_offset,
        },
        "risk_signals": risk_signal_values,
        "warnings": warnings,
        "truncated": truncated,
    });

    Ok(GgufModelSummary {
        version,
        tensor_count,
        metadata_count: metadata_kv_count,
        tensor_type_count: details["tensor_type_counts"].as_array().map_or(0, Vec::len),
        risk_signal_count: details["risk_signals"].as_array().map_or(0, Vec::len),
        truncated,
        warnings: details["warnings"]
            .as_array()
            .map(|items| {
                items
                    .iter()
                    .filter_map(|item| item.as_str().map(ToOwned::to_owned))
                    .collect()
            })
            .unwrap_or_default(),
        details,
    })
}

impl<'a> GgufParseState<'a> {
    fn expect_magic(&mut self, magic: &[u8], label: &str) -> Result<()> {
        let end = self
            .cursor
            .checked_add(magic.len())
            .context("GGUF cursor overflow")?;
        if self.bytes.get(self.cursor..end) != Some(magic) {
            anyhow::bail!("missing {label}");
        }
        self.cursor = end;
        Ok(())
    }

    fn read_u8(&mut self, label: &str) -> Result<u8> {
        let value = *self
            .bytes
            .get(self.cursor)
            .with_context(|| format!("missing {label}"))?;
        self.cursor += 1;
        Ok(value)
    }

    fn read_i8(&mut self, label: &str) -> Result<i8> {
        Ok(self.read_u8(label)? as i8)
    }

    fn read_u16(&mut self, label: &str) -> Result<u16> {
        let value =
            read_le_u16(self.bytes, self.cursor).with_context(|| format!("missing {label}"))?;
        self.cursor += 2;
        Ok(value)
    }

    fn read_i16(&mut self, label: &str) -> Result<i16> {
        let slice = self.read_bytes(2, label)?;
        Ok(i16::from_le_bytes([slice[0], slice[1]]))
    }

    fn read_u32(&mut self, label: &str) -> Result<u32> {
        let value =
            read_le_u32(self.bytes, self.cursor).with_context(|| format!("missing {label}"))?;
        self.cursor += 4;
        Ok(value)
    }

    fn read_i32(&mut self, label: &str) -> Result<i32> {
        let value =
            read_le_i32(self.bytes, self.cursor).with_context(|| format!("missing {label}"))?;
        self.cursor += 4;
        Ok(value)
    }

    fn read_u64(&mut self, label: &str) -> Result<u64> {
        let value =
            read_le_u64(self.bytes, self.cursor).with_context(|| format!("missing {label}"))?;
        self.cursor += 8;
        Ok(value)
    }

    fn read_i64(&mut self, label: &str) -> Result<i64> {
        let slice = self.read_bytes(8, label)?;
        Ok(i64::from_le_bytes([
            slice[0], slice[1], slice[2], slice[3], slice[4], slice[5], slice[6], slice[7],
        ]))
    }

    fn read_f32(&mut self, label: &str) -> Result<f32> {
        let slice = self.read_bytes(4, label)?;
        Ok(f32::from_le_bytes([slice[0], slice[1], slice[2], slice[3]]))
    }

    fn read_f64(&mut self, label: &str) -> Result<f64> {
        let slice = self.read_bytes(8, label)?;
        Ok(f64::from_le_bytes([
            slice[0], slice[1], slice[2], slice[3], slice[4], slice[5], slice[6], slice[7],
        ]))
    }

    fn read_bool(&mut self, label: &str) -> Result<bool> {
        match self.read_u8(label)? {
            0 => Ok(false),
            1 => Ok(true),
            value => anyhow::bail!("invalid GGUF bool value {value}"),
        }
    }

    fn read_string(&mut self, label: &str) -> Result<String> {
        let len = self.read_u64(label)?;
        if len > GGUF_STRING_LIMIT {
            anyhow::bail!("GGUF string length {len} exceeds parser limit");
        }
        let bytes = self.read_bytes(len as usize, label)?;
        String::from_utf8(bytes.to_vec()).context("GGUF string is not UTF-8")
    }

    fn read_bytes(&mut self, len: usize, label: &str) -> Result<&'a [u8]> {
        let end = self
            .cursor
            .checked_add(len)
            .context("GGUF cursor overflow")?;
        let slice = self
            .bytes
            .get(self.cursor..end)
            .with_context(|| format!("missing {label}"))?;
        self.cursor = end;
        Ok(slice)
    }

    fn read_metadata_value(&mut self, warnings: &mut Vec<String>) -> Result<serde_json::Value> {
        let value_type = self.read_u32("GGUF metadata value type")?;
        self.read_metadata_value_of_type(value_type, warnings)
    }

    fn read_metadata_value_of_type(
        &mut self,
        value_type: u32,
        warnings: &mut Vec<String>,
    ) -> Result<serde_json::Value> {
        let value = match value_type {
            0 => serde_json::json!(self.read_u8("GGUF metadata uint8")?),
            1 => serde_json::json!(self.read_i8("GGUF metadata int8")?),
            2 => serde_json::json!(self.read_u16("GGUF metadata uint16")?),
            3 => serde_json::json!(self.read_i16("GGUF metadata int16")?),
            4 => serde_json::json!(self.read_u32("GGUF metadata uint32")?),
            5 => serde_json::json!(self.read_i32("GGUF metadata int32")?),
            6 => serde_json::json!(self.read_f32("GGUF metadata float32")?),
            7 => serde_json::json!(self.read_bool("GGUF metadata bool")?),
            8 => serde_json::json!(self.read_string("GGUF metadata string")?),
            9 => {
                let item_type = self.read_u32("GGUF metadata array type")?;
                let len = self.read_u64("GGUF metadata array length")?;
                let mut values = Vec::new();
                let read_len = len.min(GGUF_ARRAY_ITEM_LIMIT);
                for _ in 0..read_len {
                    values.push(self.read_metadata_value_of_type(item_type, warnings)?);
                }
                if len > read_len {
                    warnings.push(format!(
                        "GGUF metadata array truncated at {read_len} of {len} item(s)"
                    ));
                    for _ in read_len..len {
                        self.skip_metadata_value_of_type(item_type)?;
                    }
                }
                serde_json::json!({
                    "type": "array",
                    "item_type": gguf_metadata_type_name(item_type),
                    "length": len,
                    "items": values,
                    "truncated": len > read_len,
                })
            }
            10 => serde_json::json!(self.read_u64("GGUF metadata uint64")?),
            11 => serde_json::json!(self.read_i64("GGUF metadata int64")?),
            12 => serde_json::json!(self.read_f64("GGUF metadata float64")?),
            _ => anyhow::bail!("unknown GGUF metadata value type {value_type}"),
        };
        Ok(value)
    }

    fn skip_metadata_value_of_type(&mut self, value_type: u32) -> Result<()> {
        match value_type {
            0 | 1 | 7 => {
                self.read_bytes(1, "GGUF metadata scalar")?;
            }
            2 | 3 => {
                self.read_bytes(2, "GGUF metadata scalar")?;
            }
            4 | 5 | 6 => {
                self.read_bytes(4, "GGUF metadata scalar")?;
            }
            8 => {
                let len = self.read_u64("GGUF metadata string length")?;
                if len > GGUF_STRING_LIMIT {
                    anyhow::bail!("GGUF string length {len} exceeds parser limit");
                }
                self.read_bytes(len as usize, "GGUF metadata string")?;
            }
            9 => {
                let item_type = self.read_u32("GGUF metadata array type")?;
                let len = self.read_u64("GGUF metadata array length")?;
                for _ in 0..len {
                    self.skip_metadata_value_of_type(item_type)?;
                }
            }
            10 | 11 | 12 => {
                self.read_bytes(8, "GGUF metadata scalar")?;
            }
            _ => anyhow::bail!("unknown GGUF metadata value type {value_type}"),
        }
        Ok(())
    }

    fn skip_unparsed_metadata(&mut self, count: u64, warnings: &mut Vec<String>) {
        for _ in 0..count {
            let result = (|| -> Result<()> {
                let _key = self.read_string("GGUF metadata key")?;
                let value_type = self.read_u32("GGUF metadata value type")?;
                self.skip_metadata_value_of_type(value_type)
            })();
            if let Err(err) = result {
                warnings.push(format!("failed to skip GGUF metadata entry: {err}"));
                break;
            }
        }
    }

    fn read_tensor_info(&mut self, warnings: &mut Vec<String>) -> Result<GgufTensorInfo> {
        let name = self.read_string("GGUF tensor name")?;
        let dimension_count = self.read_u32("GGUF tensor dimension count")?;
        if dimension_count > 16 {
            warnings.push(format!(
                "GGUF tensor {name} has unusually high rank {dimension_count}"
            ));
        }
        let dims_to_read = dimension_count.min(16);
        let mut shape = Vec::new();
        for _ in 0..dims_to_read {
            shape.push(self.read_u64("GGUF tensor dimension")?);
        }
        for _ in dims_to_read..dimension_count {
            let _ = self.read_u64("GGUF skipped tensor dimension")?;
        }
        let tensor_type = self.read_u32("GGUF tensor type")?;
        let offset = self.read_u64("GGUF tensor offset")?;
        Ok(GgufTensorInfo {
            role: safetensors_tensor_role(&name),
            name,
            shape,
            tensor_type,
            offset,
        })
    }

    fn skip_unparsed_tensors(&mut self, count: u64, warnings: &mut Vec<String>) {
        for _ in 0..count {
            let result = (|| -> Result<()> {
                let _name = self.read_string("GGUF tensor name")?;
                let dimension_count = self.read_u32("GGUF tensor dimension count")?;
                for _ in 0..dimension_count {
                    let _ = self.read_u64("GGUF tensor dimension")?;
                }
                let _tensor_type = self.read_u32("GGUF tensor type")?;
                let _offset = self.read_u64("GGUF tensor offset")?;
                Ok(())
            })();
            if let Err(err) = result {
                warnings.push(format!("failed to skip GGUF tensor entry: {err}"));
                break;
            }
        }
    }
}

#[derive(Debug)]
struct SafeTensorsModelSummary {
    tensor_count: usize,
    dtype_count: usize,
    parameter_count: u64,
    risk_signal_count: usize,
    truncated: bool,
    warnings: Vec<String>,
    details: serde_json::Value,
}

#[derive(Debug)]
struct SafeTensorRecord {
    name: String,
    dtype: String,
    shape: Vec<u64>,
    data_offsets: (u64, u64),
    element_count: Option<u64>,
    expected_bytes: Option<u64>,
    actual_bytes: u64,
    byte_size_matches_shape: Option<bool>,
    role: &'static str,
}

const SAFETENSORS_HEADER_LIMIT: u64 = 16 * 1024 * 1024;
const SAFETENSORS_TENSOR_LIMIT: usize = 4096;

fn extract_safetensors_model_summary(
    object: &UniversalObject,
    bytes: &[u8],
) -> Result<SafeTensorsModelSummary> {
    if bytes.len() < 8 {
        anyhow::bail!("SafeTensors file is too small for an 8-byte header length");
    }
    let header_len = read_le_u64(bytes, 0).context("missing SafeTensors header length")?;
    if header_len == 0 {
        anyhow::bail!("SafeTensors header length is zero");
    }
    if header_len > SAFETENSORS_HEADER_LIMIT {
        anyhow::bail!("SafeTensors header length {header_len} exceeds the parser limit");
    }
    let header_start = 8usize;
    let header_end = header_start
        .checked_add(header_len as usize)
        .context("SafeTensors header length overflow")?;
    if header_end > bytes.len() {
        anyhow::bail!("SafeTensors header extends beyond object bounds");
    }
    let header_text = std::str::from_utf8(&bytes[header_start..header_end])
        .context("SafeTensors header is not UTF-8 JSON")?;
    let header_value: serde_json::Value =
        serde_json::from_str(header_text).context("failed to parse SafeTensors header JSON")?;
    let header_object = header_value
        .as_object()
        .context("SafeTensors header JSON is not an object")?;
    let metadata = header_object
        .get("__metadata__")
        .cloned()
        .unwrap_or(serde_json::Value::Null);
    let data_bytes = bytes.len().saturating_sub(header_end) as u64;
    let mut warnings = Vec::new();
    let mut tensors = Vec::new();
    let mut dtype_counts = BTreeMap::<String, usize>::new();
    let mut role_counts = BTreeMap::<String, usize>::new();
    let mut total_parameter_count = 0u64;
    let mut declared_tensor_count = 0usize;
    for (name, value) in header_object {
        if name == "__metadata__" {
            continue;
        }
        declared_tensor_count += 1;
        if tensors.len() >= SAFETENSORS_TENSOR_LIMIT {
            continue;
        }
        match parse_safe_tensor_record(name, value, data_bytes, &mut warnings) {
            Some(record) => {
                *dtype_counts.entry(record.dtype.clone()).or_default() += 1;
                *role_counts.entry(record.role.to_string()).or_default() += 1;
                if let Some(elements) = record.element_count {
                    total_parameter_count = total_parameter_count.saturating_add(elements);
                }
                tensors.push(record);
            }
            None => warnings.push(format!("SafeTensors tensor {name} has malformed metadata")),
        }
    }
    if declared_tensor_count > SAFETENSORS_TENSOR_LIMIT {
        warnings.push(format!(
            "SafeTensors tensor listing truncated at {SAFETENSORS_TENSOR_LIMIT} of {declared_tensor_count} tensors"
        ));
    }
    let data_start = header_end as u64;
    let mut ranges = tensors
        .iter()
        .map(|tensor| {
            (
                tensor.data_offsets.0,
                tensor.data_offsets.1,
                tensor.name.as_str(),
            )
        })
        .collect::<Vec<_>>();
    ranges.sort_by_key(|(start, _, _)| *start);
    let mut last_end = 0u64;
    let mut covered_bytes = 0u64;
    for (start, end, name) in &ranges {
        if *start < last_end {
            warnings.push(format!(
                "SafeTensors tensor {name} data range overlaps a previous tensor"
            ));
        }
        if end > start {
            covered_bytes = covered_bytes.saturating_add(end - start);
        }
        last_end = last_end.max(*end);
    }
    if last_end > data_bytes {
        warnings.push("SafeTensors tensor data ranges extend past the data section".to_string());
    }
    if covered_bytes < data_bytes {
        warnings.push(format!(
            "SafeTensors data section has {} unreferenced byte(s)",
            data_bytes - covered_bytes
        ));
    }
    let mut risk_signals = BTreeSet::<String>::new();
    risk_signals.insert("safetensors_model_present".to_string());
    if declared_tensor_count == 0 {
        risk_signals.insert("model_without_tensors".to_string());
    }
    if header_len > 1024 * 1024 {
        risk_signals.insert("large_model_header".to_string());
    }
    if !warnings.is_empty() {
        risk_signals.insert("model_integrity_warnings".to_string());
    }
    for tensor in &tensors {
        collect_safetensors_tensor_risk_signals(tensor, &mut risk_signals);
    }
    collect_safetensors_metadata_risk_signals(&metadata, &mut risk_signals);
    let tensor_values = tensors
        .iter()
        .map(safe_tensor_record_json)
        .collect::<Vec<_>>();
    let dtype_values = dtype_counts
        .iter()
        .map(|(dtype, count)| serde_json::json!({ "dtype": dtype, "count": count }))
        .collect::<Vec<_>>();
    let role_values = role_counts
        .iter()
        .map(|(role, count)| serde_json::json!({ "role": role, "count": count }))
        .collect::<Vec<_>>();
    let risk_signal_values = risk_signals.into_iter().take(256).collect::<Vec<_>>();
    let truncated = declared_tensor_count > tensors.len();
    let details = serde_json::json!({
        "format": object.format.as_deref().unwrap_or("safetensors"),
        "header": {
            "header_length": header_len,
            "header_offset": header_start,
            "header_end": header_end,
            "data_offset": data_start,
            "data_size": data_bytes,
            "metadata_present": !metadata.is_null(),
        },
        "metadata": metadata,
        "tensor_count": declared_tensor_count,
        "listed_tensor_count": tensors.len(),
        "parameter_count": total_parameter_count,
        "dtype_counts": dtype_values,
        "role_counts": role_values,
        "tensors": tensor_values,
        "data_coverage": {
            "covered_bytes": covered_bytes,
            "data_bytes": data_bytes,
            "unreferenced_bytes": data_bytes.saturating_sub(covered_bytes),
            "max_declared_end": last_end,
        },
        "risk_signals": risk_signal_values,
        "warnings": warnings,
        "truncated": truncated,
    });
    Ok(SafeTensorsModelSummary {
        tensor_count: declared_tensor_count,
        dtype_count: details["dtype_counts"].as_array().map_or(0, Vec::len),
        parameter_count: total_parameter_count,
        risk_signal_count: details["risk_signals"].as_array().map_or(0, Vec::len),
        truncated,
        warnings: details["warnings"]
            .as_array()
            .map(|items| {
                items
                    .iter()
                    .filter_map(|item| item.as_str().map(ToOwned::to_owned))
                    .collect()
            })
            .unwrap_or_default(),
        details,
    })
}

fn parse_safe_tensor_record(
    name: &str,
    value: &serde_json::Value,
    data_size: u64,
    warnings: &mut Vec<String>,
) -> Option<SafeTensorRecord> {
    let object = value.as_object()?;
    let dtype = object.get("dtype")?.as_str()?.to_string();
    let shape = object
        .get("shape")?
        .as_array()?
        .iter()
        .map(|item| item.as_u64())
        .collect::<Option<Vec<_>>>()?;
    let offsets = object.get("data_offsets")?.as_array()?;
    if offsets.len() != 2 {
        return None;
    }
    let start = offsets[0].as_u64()?;
    let end = offsets[1].as_u64()?;
    if end < start {
        warnings.push(format!(
            "SafeTensors tensor {name} has inverted data_offsets"
        ));
    }
    let actual_bytes = end.saturating_sub(start);
    let element_count = shape
        .iter()
        .try_fold(1u64, |acc, dim| acc.checked_mul(*dim));
    let expected_bytes = element_count
        .and_then(|count| safetensors_dtype_size(&dtype).and_then(|size| count.checked_mul(size)));
    if expected_bytes.is_none() && safetensors_dtype_size(&dtype).is_none() {
        warnings.push(format!(
            "SafeTensors tensor {name} uses unknown dtype {dtype}"
        ));
    }
    let byte_size_matches_shape = expected_bytes.map(|expected| expected == actual_bytes);
    if byte_size_matches_shape == Some(false) {
        warnings.push(format!(
            "SafeTensors tensor {name} byte range does not match dtype and shape"
        ));
    }
    if end > data_size {
        warnings.push(format!(
            "SafeTensors tensor {name} data_offsets extend beyond the data section"
        ));
    }
    Some(SafeTensorRecord {
        name: name.to_string(),
        dtype,
        shape,
        data_offsets: (start, end),
        element_count,
        expected_bytes,
        actual_bytes,
        byte_size_matches_shape,
        role: safetensors_tensor_role(name),
    })
}

fn safe_tensor_record_json(record: &SafeTensorRecord) -> serde_json::Value {
    serde_json::json!({
        "name": record.name,
        "dtype": record.dtype,
        "shape": record.shape,
        "rank": record.shape.len(),
        "data_offsets": [record.data_offsets.0, record.data_offsets.1],
        "element_count": record.element_count,
        "expected_bytes": record.expected_bytes,
        "actual_bytes": record.actual_bytes,
        "byte_size_matches_shape": record.byte_size_matches_shape,
        "role": record.role,
    })
}

fn safetensors_dtype_size(dtype: &str) -> Option<u64> {
    match dtype {
        "BOOL" | "U8" | "I8" | "F8_E5M2" | "F8_E4M3" => Some(1),
        "F16" | "BF16" | "I16" | "U16" => Some(2),
        "F32" | "I32" | "U32" => Some(4),
        "F64" | "I64" | "U64" => Some(8),
        _ => None,
    }
}

fn safetensors_tensor_role(name: &str) -> &'static str {
    let lower = name.to_ascii_lowercase();
    if lower.contains("embedding")
        || lower.contains("embed_tokens")
        || lower.contains("token_embd")
        || lower.contains("tok_embeddings")
        || lower.contains("word_embeddings")
    {
        "embedding"
    } else if lower.contains("lm_head")
        || lower.contains("output.weight")
        || lower.contains("output_norm")
        || lower.contains("classifier")
        || lower.contains("head")
    {
        "head"
    } else if lower.contains("attention")
        || lower.contains(".attn.")
        || lower.contains("self_attn")
        || lower.contains(".attn_")
        || lower.contains("attn_q")
        || lower.contains("attn_k")
        || lower.contains("attn_v")
        || lower.contains("attn_output")
        || lower.contains("q_proj")
        || lower.contains("k_proj")
        || lower.contains("v_proj")
        || lower.contains("o_proj")
    {
        "attention"
    } else if lower.contains("mlp")
        || lower.contains("feed_forward")
        || lower.contains("ffn")
        || lower.contains("ffn_")
        || lower.contains("gate_proj")
        || lower.contains("up_proj")
        || lower.contains("down_proj")
    {
        "feed_forward"
    } else if lower.contains("norm") || lower.contains("layernorm") {
        "normalization"
    } else if lower.contains("lora") || lower.contains("adapter") {
        "adapter"
    } else {
        "tensor"
    }
}

fn collect_safetensors_tensor_risk_signals(
    tensor: &SafeTensorRecord,
    risk_signals: &mut BTreeSet<String>,
) {
    if tensor.byte_size_matches_shape == Some(false) {
        risk_signals.insert("tensor_shape_size_mismatch".to_string());
    }
    if safetensors_dtype_size(&tensor.dtype).is_none() {
        risk_signals.insert("unknown_tensor_dtype".to_string());
    }
    if tensor.role == "adapter" {
        risk_signals.insert("adapter_or_lora_tensors_present".to_string());
    }
    if tensor.shape.len() > 6 {
        risk_signals.insert("high_rank_tensor_present".to_string());
    }
}

fn collect_safetensors_metadata_risk_signals(
    metadata: &serde_json::Value,
    risk_signals: &mut BTreeSet<String>,
) {
    let Some(object) = metadata.as_object() else {
        return;
    };
    for (key, value) in object {
        let joined = format!(
            "{} {}",
            key.to_ascii_lowercase(),
            value.as_str().unwrap_or_default().to_ascii_lowercase()
        );
        if joined.contains("pickle")
            || joined.contains("unsafe")
            || joined.contains("exec")
            || joined.contains("remote_code")
        {
            risk_signals.insert("suspicious_model_metadata".to_string());
        }
        if joined.contains("lora") || joined.contains("adapter") || joined.contains("peft") {
            risk_signals.insert("adapter_or_lora_metadata".to_string());
        }
    }
}

fn is_safetensors_like_bytes(bytes: &[u8]) -> bool {
    if bytes.len() < 8 {
        return false;
    }
    let Some(header_len) = read_le_u64(bytes, 0) else {
        return false;
    };
    if header_len == 0 || header_len > SAFETENSORS_HEADER_LIMIT {
        return false;
    }
    let Some(header_end) = 8usize.checked_add(header_len as usize) else {
        return false;
    };
    if header_end > bytes.len() {
        return false;
    }
    let Ok(header_text) = std::str::from_utf8(&bytes[8..header_end]) else {
        return false;
    };
    let Ok(value) = serde_json::from_str::<serde_json::Value>(header_text) else {
        return false;
    };
    value.as_object().is_some_and(|object| {
        object.iter().any(|(name, value)| {
            name != "__metadata__"
                && value.get("dtype").and_then(|item| item.as_str()).is_some()
                && value
                    .get("shape")
                    .and_then(|item| item.as_array())
                    .is_some()
                && value
                    .get("data_offsets")
                    .and_then(|item| item.as_array())
                    .is_some_and(|items| items.len() == 2)
        })
    })
}

fn is_gguf_like_bytes(bytes: &[u8]) -> bool {
    bytes.len() >= 24
        && bytes.starts_with(GGUF_MAGIC)
        && read_le_u32(bytes, 4).is_some_and(|version| (1..=16).contains(&version))
        && read_le_u64(bytes, 8).is_some()
        && read_le_u64(bytes, 16).is_some()
}

fn pytorch_zip_markers(bytes: &[u8]) -> Option<(usize, bool)> {
    let cursor = std::io::Cursor::new(bytes);
    let mut archive = zip::ZipArchive::new(cursor).ok()?;
    let entry_count = archive.len();
    let mut pickle_present = false;
    let mut torch_marker_present = false;
    for index in 0..entry_count.min(PYTORCH_ZIP_ENTRY_LIMIT) {
        let file = archive.by_index(index).ok()?;
        let name = file.name().to_ascii_lowercase();
        if name.ends_with("data.pkl") || name.ends_with(".pkl") {
            pickle_present = true;
        }
        if name.ends_with("version")
            || name.ends_with("byteorder")
            || name.contains("/data/")
            || name == "data.pkl"
        {
            torch_marker_present = true;
        }
    }
    (pickle_present && torch_marker_present).then_some((entry_count, pickle_present))
}

fn is_pickle_like_bytes(bytes: &[u8]) -> bool {
    matches!(
        bytes.get(0..2),
        Some([0x80, 0x02..=0x05]) | Some([b'(', _]) | Some([b'c', _])
    )
}

fn pytorch_entry_role(name: &str, is_dir: bool) -> &'static str {
    if is_dir {
        "directory"
    } else if name.ends_with("data.pkl") || name.ends_with(".pkl") {
        "pickle"
    } else if name.contains("/data/") || name.starts_with("data/") {
        "storage"
    } else if name.ends_with("version") {
        "version"
    } else if name.ends_with("byteorder") {
        "byteorder"
    } else {
        "metadata"
    }
}

fn scan_pickle_bytes(bytes: &[u8], warnings: &mut Vec<String>) -> PickleScanSummary {
    let mut cursor = 0usize;
    let scan_len = bytes.len().min(PYTORCH_PICKLE_SCAN_LIMIT);
    let mut protocol = None;
    let mut opcode_count = 0usize;
    let mut globals = Vec::new();
    let mut string_hits = Vec::new();
    let mut risky_opcode_counts = BTreeMap::<String, usize>::new();
    while cursor < scan_len {
        let opcode = bytes[cursor];
        cursor += 1;
        opcode_count += 1;
        match opcode {
            0x80 => {
                if cursor < scan_len {
                    protocol = Some(bytes[cursor]);
                    cursor += 1;
                }
            }
            b'c' => {
                let module = read_pickle_line(bytes, &mut cursor, scan_len);
                let name = read_pickle_line(bytes, &mut cursor, scan_len);
                if let (Some(module), Some(name)) = (module, name)
                    && globals.len() < PYTORCH_PICKLE_GLOBAL_LIMIT
                {
                    globals.push(format!("{module}.{name}"));
                }
            }
            0x93 => {
                *risky_opcode_counts
                    .entry("STACK_GLOBAL".to_string())
                    .or_default() += 1;
            }
            b'R' => {
                *risky_opcode_counts.entry("REDUCE".to_string()).or_default() += 1;
            }
            b'b' => {
                *risky_opcode_counts.entry("BUILD".to_string()).or_default() += 1;
            }
            b'i' => {
                *risky_opcode_counts.entry("INST".to_string()).or_default() += 1;
                let _ = read_pickle_line(bytes, &mut cursor, scan_len);
                let _ = read_pickle_line(bytes, &mut cursor, scan_len);
            }
            b'o' => {
                *risky_opcode_counts.entry("OBJ".to_string()).or_default() += 1;
            }
            b'U' => {
                if cursor < scan_len {
                    let len = bytes[cursor] as usize;
                    cursor += 1;
                    collect_pickle_string_hit(bytes, &mut cursor, scan_len, len, &mut string_hits);
                }
            }
            b'X' => {
                if cursor + 4 <= scan_len {
                    let len = u32::from_le_bytes([
                        bytes[cursor],
                        bytes[cursor + 1],
                        bytes[cursor + 2],
                        bytes[cursor + 3],
                    ]) as usize;
                    cursor += 4;
                    collect_pickle_string_hit(bytes, &mut cursor, scan_len, len, &mut string_hits);
                }
            }
            b'T' => {
                if cursor + 4 <= scan_len {
                    let len = i32::from_le_bytes([
                        bytes[cursor],
                        bytes[cursor + 1],
                        bytes[cursor + 2],
                        bytes[cursor + 3],
                    ]);
                    cursor += 4;
                    if len > 0 {
                        collect_pickle_string_hit(
                            bytes,
                            &mut cursor,
                            scan_len,
                            len as usize,
                            &mut string_hits,
                        );
                    }
                }
            }
            b'V' | b'S' => {
                if let Some(text) = read_pickle_line(bytes, &mut cursor, scan_len)
                    && string_hits.len() < PYTORCH_PICKLE_STRING_LIMIT
                {
                    string_hits.push(text);
                }
            }
            b'B' => {
                if cursor + 4 <= scan_len {
                    let len = u32::from_le_bytes([
                        bytes[cursor],
                        bytes[cursor + 1],
                        bytes[cursor + 2],
                        bytes[cursor + 3],
                    ]) as usize;
                    cursor = cursor.saturating_add(4).saturating_add(len).min(scan_len);
                }
            }
            b'C' => {
                if cursor < scan_len {
                    let len = bytes[cursor] as usize;
                    cursor = cursor.saturating_add(1).saturating_add(len).min(scan_len);
                }
            }
            b'M' => cursor = cursor.saturating_add(2).min(scan_len),
            b'J' | b'F' => cursor = cursor.saturating_add(4).min(scan_len),
            b'I' | b'L' | b'P' => {
                let _ = read_pickle_line(bytes, &mut cursor, scan_len);
            }
            b'G' => cursor = cursor.saturating_add(8).min(scan_len),
            b'.' => break,
            _ => {}
        }
    }
    let truncated = bytes.len() > scan_len;
    if truncated {
        warnings.push(format!(
            "PyTorch pickle scan truncated at {scan_len} of {} bytes",
            bytes.len()
        ));
    }
    PickleScanSummary {
        protocol,
        opcode_count,
        globals,
        string_hits,
        risky_opcode_counts,
        truncated,
        warnings: Vec::new(),
    }
}

fn read_pickle_line(bytes: &[u8], cursor: &mut usize, scan_len: usize) -> Option<String> {
    if *cursor >= scan_len {
        return None;
    }
    let start = *cursor;
    while *cursor < scan_len && bytes[*cursor] != b'\n' {
        *cursor += 1;
    }
    let end = *cursor;
    if *cursor < scan_len {
        *cursor += 1;
    }
    Some(String::from_utf8_lossy(&bytes[start..end]).into_owned())
}

fn collect_pickle_string_hit(
    bytes: &[u8],
    cursor: &mut usize,
    scan_len: usize,
    len: usize,
    string_hits: &mut Vec<String>,
) {
    let end = cursor.saturating_add(len).min(scan_len);
    if string_hits.len() < PYTORCH_PICKLE_STRING_LIMIT
        && let Ok(text) = std::str::from_utf8(&bytes[*cursor..end])
        && text
            .chars()
            .all(|ch| !ch.is_control() || matches!(ch, '\n' | '\r' | '\t'))
    {
        string_hits.push(text.chars().take(256).collect());
    }
    *cursor = end;
}

fn collect_pickle_risk_signals(pickle: &PickleScanSummary, risk_signals: &mut BTreeSet<String>) {
    if !pickle.globals.is_empty() {
        risk_signals.insert("pickle_globals_present".to_string());
    }
    if !pickle.risky_opcode_counts.is_empty() {
        risk_signals.insert("pickle_callable_opcodes_present".to_string());
    }
    for global in &pickle.globals {
        let lower = global.to_ascii_lowercase();
        if lower.contains("os.")
            || lower.contains("posix.")
            || lower.contains("subprocess")
            || lower.contains("eval")
            || lower.contains("exec")
            || lower.contains("system")
        {
            risk_signals.insert("suspicious_pickle_global".to_string());
        }
        if lower.contains("torch.") || lower.contains("torch._utils") {
            risk_signals.insert("torch_pickle_globals_present".to_string());
        }
    }
    for hit in &pickle.string_hits {
        let lower = hit.to_ascii_lowercase();
        if lower.contains("http://")
            || lower.contains("https://")
            || lower.contains("powershell")
            || lower.contains("/bin/sh")
        {
            risk_signals.insert("suspicious_pickle_string".to_string());
        }
    }
}

fn pickle_scan_json(name: &str, pickle: &PickleScanSummary) -> serde_json::Value {
    let risky_opcodes = pickle
        .risky_opcode_counts
        .iter()
        .map(|(opcode, count)| {
            serde_json::json!({
                "opcode": opcode,
                "count": count,
            })
        })
        .collect::<Vec<_>>();
    serde_json::json!({
        "name": name,
        "protocol": pickle.protocol,
        "opcode_count": pickle.opcode_count,
        "globals": pickle.globals,
        "string_hits": pickle.string_hits,
        "risky_opcode_counts": risky_opcodes,
        "warnings": pickle.warnings,
        "truncated": pickle.truncated,
    })
}

fn align_to(value: u64, alignment: u64) -> Option<u64> {
    if alignment <= 1 {
        return Some(value);
    }
    let remainder = value % alignment;
    if remainder == 0 {
        Some(value)
    } else {
        value.checked_add(alignment - remainder)
    }
}

fn gguf_metadata_type_name(value: u32) -> &'static str {
    match value {
        0 => "uint8",
        1 => "int8",
        2 => "uint16",
        3 => "int16",
        4 => "uint32",
        5 => "int32",
        6 => "float32",
        7 => "bool",
        8 => "string",
        9 => "array",
        10 => "uint64",
        11 => "int64",
        12 => "float64",
        _ => "unknown",
    }
}

fn gguf_tensor_type_name(value: u32) -> &'static str {
    match value {
        0 => "F32",
        1 => "F16",
        2 => "Q4_0",
        3 => "Q4_1",
        6 => "Q5_0",
        7 => "Q5_1",
        8 => "Q8_0",
        9 => "Q8_1",
        10 => "Q2_K",
        11 => "Q3_K",
        12 => "Q4_K",
        13 => "Q5_K",
        14 => "Q6_K",
        15 => "Q8_K",
        16 => "IQ2_XXS",
        17 => "IQ2_XS",
        18 => "IQ3_XXS",
        19 => "IQ1_S",
        20 => "IQ4_NL",
        21 => "IQ3_S",
        22 => "IQ2_S",
        23 => "IQ4_XS",
        24 => "I8",
        25 => "I16",
        26 => "I32",
        27 => "I64",
        28 => "F64",
        29 => "IQ1_M",
        30 => "BF16",
        34 => "TQ1_0",
        35 => "TQ2_0",
        39 => "MXFP4",
        _ => "UNKNOWN",
    }
}

fn collect_gguf_tensor_risk_signals(tensor: &GgufTensorInfo, risk_signals: &mut BTreeSet<String>) {
    if gguf_tensor_type_name(tensor.tensor_type) == "UNKNOWN" {
        risk_signals.insert("unknown_tensor_dtype".to_string());
    }
    if tensor.role == "adapter" {
        risk_signals.insert("adapter_or_lora_tensors_present".to_string());
    }
    if tensor.shape.len() > 6 {
        risk_signals.insert("high_rank_tensor_present".to_string());
    }
}

fn collect_gguf_metadata_risk_signals(
    key: &str,
    value: &serde_json::Value,
    risk_signals: &mut BTreeSet<String>,
) {
    let joined = format!(
        "{} {}",
        key.to_ascii_lowercase(),
        gguf_metadata_value_signal_text(value)
    );
    if joined.contains("lora") || joined.contains("adapter") || joined.contains("peft") {
        risk_signals.insert("adapter_or_lora_metadata".to_string());
    }
    if joined.contains("mmproj") || joined.contains("multimodal") || joined.contains("vision") {
        risk_signals.insert("multimodal_or_projector_model".to_string());
    }
    if joined.contains("remote_code") || joined.contains("unsafe") || joined.contains("exec") {
        risk_signals.insert("suspicious_model_metadata".to_string());
    }
}

fn gguf_metadata_value_signal_text(value: &serde_json::Value) -> String {
    match value {
        serde_json::Value::String(text) => text.to_ascii_lowercase(),
        serde_json::Value::Object(map) => map
            .values()
            .take(16)
            .map(gguf_metadata_value_signal_text)
            .collect::<Vec<_>>()
            .join(" "),
        serde_json::Value::Array(items) => items
            .iter()
            .take(16)
            .map(gguf_metadata_value_signal_text)
            .collect::<Vec<_>>()
            .join(" "),
        _ => String::new(),
    }
}

fn analyze_object_android_package(object: &UniversalObject, bytes: &[u8]) -> ObjectAnalysisSummary {
    match extract_android_package_summary(object, bytes) {
        Ok(summary) => ObjectAnalysisSummary {
            analyzer: "android_package".to_string(),
            status: if summary.truncated || !summary.warnings.is_empty() {
                ObjectAnalysisStatus::Partial
            } else {
                ObjectAnalysisStatus::Completed
            },
            summary: format!(
                "Android package with {} entries, {} DEX file(s), {} native library ABI(s), {} risk signal(s)",
                summary.entry_count,
                summary.dex_count,
                summary.native_abi_count,
                summary.risk_signal_count
            ),
            details: summary.details,
            evidence_ids: vec![format!("analysis:{}:android_package", object.id)],
        },
        Err(err) => ObjectAnalysisSummary {
            analyzer: "android_package".to_string(),
            status: ObjectAnalysisStatus::Failed,
            summary: format!("Android package analysis failed: {err}"),
            details: serde_json::json!({ "error": err.to_string() }),
            evidence_ids: vec![format!("analysis:{}:android_package", object.id)],
        },
    }
}

#[derive(Debug)]
struct AndroidPackageAnalysisSummary {
    entry_count: usize,
    dex_count: usize,
    native_abi_count: usize,
    risk_signal_count: usize,
    truncated: bool,
    warnings: Vec<String>,
    details: serde_json::Value,
}

#[derive(Debug)]
struct AndroidDexSummary {
    name: String,
    size: u64,
    version: Option<String>,
    file_size: Option<u32>,
    header_size: Option<u32>,
    endian_tag: Option<String>,
    string_ids_size: Option<u32>,
    type_ids_size: Option<u32>,
    proto_ids_size: Option<u32>,
    field_ids_size: Option<u32>,
    method_ids_size: Option<u32>,
    class_defs_size: Option<u32>,
    data_size: Option<u32>,
}

const ANDROID_ENTRY_SCAN_LIMIT: usize = 4096;
const ANDROID_ENTRY_LIST_LIMIT: usize = 512;
const ANDROID_MANIFEST_READ_LIMIT: usize = 512 * 1024;
const ANDROID_MANIFEST_COMPONENT_LIMIT: usize = 256;
const ANDROID_PERMISSION_LIMIT: usize = 256;
const ANDROID_DEX_READ_LIMIT: usize = 4096;
const ANDROID_SAMPLE_LIMIT: usize = 128;

fn zip_contains_android_package_markers(bytes: &[u8]) -> bool {
    if !is_zip_like_bytes(bytes) {
        return false;
    }
    let cursor = Cursor::new(bytes);
    let Ok(mut archive) = zip::ZipArchive::new(cursor) else {
        return false;
    };
    let mut has_manifest = false;
    let mut has_dex = false;
    for index in 0..archive.len().min(ANDROID_ENTRY_SCAN_LIMIT) {
        let Ok(file) = archive.by_index(index) else {
            continue;
        };
        let name = file.name();
        if name == "AndroidManifest.xml" {
            has_manifest = true;
        }
        if name == "classes.dex" || (name.starts_with("classes") && name.ends_with(".dex")) {
            has_dex = true;
        }
        if has_manifest && has_dex {
            return true;
        }
    }
    false
}

fn extract_android_package_summary(
    object: &UniversalObject,
    bytes: &[u8],
) -> Result<AndroidPackageAnalysisSummary> {
    if !is_zip_like_bytes(bytes) {
        anyhow::bail!("object is not a ZIP-based Android package");
    }
    let cursor = Cursor::new(bytes);
    let mut archive =
        zip::ZipArchive::new(cursor).context("failed to parse Android package ZIP container")?;
    let entry_count = archive.len();
    let mut warnings = Vec::new();
    let mut risk_signals = BTreeSet::<String>::new();
    let mut entry_names = Vec::new();
    let mut entries = Vec::new();
    let mut dex_entries = Vec::new();
    let mut native_libs = Vec::new();
    let mut native_abis = BTreeSet::<String>::new();
    let mut assets = Vec::new();
    let mut resources = Vec::new();
    let mut meta_inf = Vec::new();
    let mut signature_files = Vec::new();
    let mut native_lib_count = 0usize;
    let mut asset_count = 0usize;
    let mut resource_count = 0usize;

    for index in 0..entry_count.min(ANDROID_ENTRY_SCAN_LIMIT) {
        let file = archive
            .by_index(index)
            .with_context(|| format!("failed to read APK ZIP entry index {index}"))?;
        let name = file.name().to_string();
        let role = android_entry_role(&name);
        entry_names.push(name.clone());
        if entries.len() < ANDROID_ENTRY_LIST_LIMIT {
            entries.push(serde_json::json!({
                "index": index,
                "name": name,
                "role": role,
                "is_dir": file.is_dir(),
                "compressed_size": file.compressed_size(),
                "uncompressed_size": file.size(),
            }));
        }
        if !file.is_dir() && is_android_dex_entry(&name) {
            dex_entries.push((name.clone(), file.size()));
        }
        if let Some((abi, library)) = android_native_lib_entry(&name) {
            native_lib_count += 1;
            native_abis.insert(abi.clone());
            if native_libs.len() < ANDROID_SAMPLE_LIMIT {
                native_libs.push(serde_json::json!({
                    "abi": abi,
                    "library": library,
                    "path": name,
                    "size": file.size(),
                }));
            }
        }
        if name.starts_with("assets/") && !file.is_dir() {
            asset_count += 1;
            if assets.len() < ANDROID_SAMPLE_LIMIT {
                assets.push(serde_json::json!({
                    "path": name,
                    "size": file.size(),
                    "role": android_asset_role(file.name()),
                }));
            }
        }
        if name.starts_with("res/") && !file.is_dir() {
            resource_count += 1;
            if resources.len() < ANDROID_SAMPLE_LIMIT {
                resources.push(serde_json::json!({
                    "path": name,
                    "size": file.size(),
                    "role": android_resource_role(file.name()),
                }));
            }
        }
        if name.starts_with("META-INF/") && !file.is_dir() {
            if meta_inf.len() < ANDROID_SAMPLE_LIMIT {
                meta_inf.push(serde_json::json!({
                    "path": name,
                    "size": file.size(),
                    "role": android_meta_inf_role(file.name()),
                }));
            }
            if android_signature_file_role(file.name()).is_some() {
                signature_files.push(name);
            }
        }
    }

    if entry_count > ANDROID_ENTRY_SCAN_LIMIT {
        warnings.push(format!(
            "APK entry scan truncated at {ANDROID_ENTRY_SCAN_LIMIT} of {entry_count} entries"
        ));
    }

    let manifest = android_manifest_summary(&mut archive, &mut risk_signals, &mut warnings)?;
    let mut dex_values = Vec::new();
    for (name, size) in dex_entries.iter().take(ANDROID_SAMPLE_LIMIT) {
        match read_zip_prefix(&mut archive, name, ANDROID_DEX_READ_LIMIT) {
            Ok(prefix) => {
                let summary = summarize_android_dex(name, *size, &prefix);
                collect_android_dex_risk_signals(&summary, &mut risk_signals);
                dex_values.push(android_dex_summary_json(&summary));
            }
            Err(err) => {
                warnings.push(format!("failed to read DEX entry {name}: {err}"));
                dex_values.push(serde_json::json!({
                    "name": name,
                    "size": size,
                    "error": err.to_string(),
                }));
            }
        }
    }
    if dex_entries.len() > dex_values.len() {
        risk_signals.insert("multi_dex_or_truncated_dex_listing".to_string());
    }
    if dex_entries.len() > 1 {
        risk_signals.insert("multi_dex".to_string());
    }
    if native_lib_count > 0 {
        risk_signals.insert("native_code_present".to_string());
    }
    if entry_names.iter().any(|name| name == "resources.arsc") {
        risk_signals.insert("compiled_resource_table_present".to_string());
    }
    if entry_names
        .iter()
        .any(|name| name.eq_ignore_ascii_case("kotlin/metadata.jvm.kotlin_module"))
    {
        risk_signals.insert("kotlin_metadata_present".to_string());
    }
    if entry_names
        .iter()
        .any(|name| name.starts_with("lib/") && name.ends_with(".so"))
    {
        risk_signals.insert("elf_shared_library_entries".to_string());
    }
    if signature_files.iter().any(|name| {
        name.to_ascii_lowercase().ends_with(".rsa")
            || name.to_ascii_lowercase().ends_with(".dsa")
            || name.to_ascii_lowercase().ends_with(".ec")
    }) {
        risk_signals.insert("jar_signature_file_present".to_string());
    }
    let signing_block = detect_android_signing_block(bytes);
    if signing_block["present"].as_bool().unwrap_or(false) {
        risk_signals.insert("apk_signing_block_present".to_string());
    }

    let truncated = entry_count > entries.len()
        || entry_count > ANDROID_ENTRY_SCAN_LIMIT
        || dex_entries.len() > dex_values.len();
    let native_abi_values = native_abis.into_iter().collect::<Vec<_>>();
    let risk_signal_values = risk_signals.into_iter().take(256).collect::<Vec<_>>();
    let details = serde_json::json!({
        "format": object.format.as_deref().unwrap_or("apk"),
        "entry_count": entry_count,
        "scanned_entry_count": entry_count.min(ANDROID_ENTRY_SCAN_LIMIT),
        "listed_entry_count": entries.len(),
        "entries_truncated": entry_count > entries.len() || entry_count > ANDROID_ENTRY_SCAN_LIMIT,
        "entries": entries,
        "manifest": manifest,
        "dex_count": dex_entries.len(),
        "listed_dex_count": dex_values.len(),
        "dex_files": dex_values,
        "native_library_count": native_lib_count,
        "native_abi_count": native_abi_values.len(),
        "native_abis": native_abi_values,
        "native_libraries": native_libs,
        "asset_count": asset_count,
        "assets": assets,
        "resource_count": resource_count,
        "resources": resources,
        "meta_inf": meta_inf,
        "signature_files": signature_files,
        "signing_block": signing_block,
        "risk_signals": risk_signal_values,
        "warnings": warnings,
        "truncated": truncated,
    });
    Ok(AndroidPackageAnalysisSummary {
        entry_count,
        dex_count: dex_entries.len(),
        native_abi_count: details["native_abi_count"].as_u64().unwrap_or(0) as usize,
        risk_signal_count: details["risk_signals"].as_array().map_or(0, Vec::len),
        truncated,
        warnings,
        details,
    })
}

fn read_zip_prefix<R: Read + std::io::Seek>(
    archive: &mut zip::ZipArchive<R>,
    name: &str,
    max_bytes: usize,
) -> Result<Vec<u8>> {
    let mut file = archive
        .by_name(name)
        .with_context(|| format!("failed to locate ZIP entry {name}"))?;
    let mut raw = Vec::new();
    let mut limited = (&mut file).take(max_bytes as u64);
    limited
        .read_to_end(&mut raw)
        .with_context(|| format!("failed to read ZIP entry {name}"))?;
    Ok(raw)
}

fn android_manifest_summary<R: Read + std::io::Seek>(
    archive: &mut zip::ZipArchive<R>,
    risk_signals: &mut BTreeSet<String>,
    warnings: &mut Vec<String>,
) -> Result<serde_json::Value> {
    let Some(entry) =
        read_zip_text_entry(archive, "AndroidManifest.xml", ANDROID_MANIFEST_READ_LIMIT)?
    else {
        warnings.push("APK is missing AndroidManifest.xml".to_string());
        risk_signals.insert("android_manifest_missing".to_string());
        return Ok(serde_json::json!({ "present": false }));
    };
    if entry.truncated {
        warnings.push("AndroidManifest.xml was truncated during analysis".to_string());
    }
    let bytes = entry.text.as_bytes();
    if bytes.starts_with(&[0x03, 0x00, 0x08, 0x00]) || bytes.iter().any(|byte| *byte == 0) {
        return Ok(serde_json::json!({
            "present": true,
            "encoding": "binary_axml",
            "size": entry.size,
            "truncated": entry.truncated,
            "parse_status": "binary_manifest_detected",
        }));
    }
    let root_tag = collect_xml_start_tags(&entry.text, "manifest", 1)
        .into_iter()
        .next();
    let root_attrs = root_tag.as_deref().map(xml_attributes).unwrap_or_default();
    let package_name = xml_attr_local(&root_attrs, "package");
    let version_code = xml_attr_local(&root_attrs, "versionCode");
    let version_name = xml_attr_local(&root_attrs, "versionName");
    let install_location = xml_attr_local(&root_attrs, "installLocation");
    let uses_sdk = collect_xml_start_tags(&entry.text, "uses-sdk", 1)
        .into_iter()
        .next()
        .map(|tag| {
            let attrs = xml_attributes(&tag);
            serde_json::json!({
                "min_sdk": xml_attr_local(&attrs, "minSdkVersion"),
                "target_sdk": xml_attr_local(&attrs, "targetSdkVersion"),
                "max_sdk": xml_attr_local(&attrs, "maxSdkVersion"),
            })
        });
    let application = collect_xml_start_tags(&entry.text, "application", 1)
        .into_iter()
        .next()
        .map(|tag| {
            let attrs = xml_attributes(&tag);
            let debuggable = xml_attr_local(&attrs, "debuggable");
            let allow_backup = xml_attr_local(&attrs, "allowBackup");
            let uses_cleartext = xml_attr_local(&attrs, "usesCleartextTraffic");
            if debuggable.as_deref() == Some("true") {
                risk_signals.insert("manifest_debuggable_true".to_string());
            }
            if allow_backup.as_deref() == Some("true") {
                risk_signals.insert("manifest_allow_backup_true".to_string());
            }
            if uses_cleartext.as_deref() == Some("true") {
                risk_signals.insert("manifest_cleartext_traffic_true".to_string());
            }
            serde_json::json!({
                "label": xml_attr_local(&attrs, "label"),
                "name": xml_attr_local(&attrs, "name"),
                "debuggable": debuggable,
                "allow_backup": allow_backup,
                "uses_cleartext_traffic": uses_cleartext,
                "network_security_config": xml_attr_local(&attrs, "networkSecurityConfig"),
                "extract_native_libs": xml_attr_local(&attrs, "extractNativeLibs"),
            })
        });
    let permissions = collect_android_manifest_named_tags(
        &entry.text,
        &["uses-permission", "uses-permission-sdk-23"],
        ANDROID_PERMISSION_LIMIT,
    );
    for permission in &permissions {
        if let Some(name) = permission["name"].as_str() {
            collect_android_permission_risk_signal(name, risk_signals);
        }
    }
    let custom_permissions =
        collect_android_manifest_named_tags(&entry.text, &["permission"], ANDROID_PERMISSION_LIMIT);
    let activities = collect_android_components(&entry.text, "activity", risk_signals);
    let services = collect_android_components(&entry.text, "service", risk_signals);
    let receivers = collect_android_components(&entry.text, "receiver", risk_signals);
    let providers = collect_android_components(&entry.text, "provider", risk_signals);
    let queries = count_xml_start_tags(&entry.text, "queries", 16);
    if queries > 0 {
        risk_signals.insert("manifest_package_visibility_queries".to_string());
    }
    Ok(serde_json::json!({
        "present": true,
        "encoding": "text_xml",
        "size": entry.size,
        "truncated": entry.truncated,
        "parse_status": if root_tag.is_some() { "parsed_text_manifest" } else { "heuristic_text_manifest" },
        "package": package_name,
        "version_code": version_code,
        "version_name": version_name,
        "install_location": install_location,
        "uses_sdk": uses_sdk,
        "application": application,
        "permission_count": permissions.len(),
        "permissions": permissions,
        "custom_permission_count": custom_permissions.len(),
        "custom_permissions": custom_permissions,
        "component_counts": {
            "activities": activities.len(),
            "services": services.len(),
            "receivers": receivers.len(),
            "providers": providers.len(),
        },
        "activities": activities,
        "services": services,
        "receivers": receivers,
        "providers": providers,
        "queries_count": queries,
    }))
}

fn collect_android_manifest_named_tags(
    xml: &str,
    local_names: &[&str],
    limit: usize,
) -> Vec<serde_json::Value> {
    let mut values = Vec::new();
    for local_name in local_names {
        for tag in collect_xml_start_tags(xml, local_name, limit.saturating_sub(values.len())) {
            if values.len() >= limit {
                break;
            }
            let attrs = xml_attributes(&tag);
            values.push(serde_json::json!({
                "tag": local_name,
                "name": xml_attr_local(&attrs, "name"),
                "protection_level": xml_attr_local(&attrs, "protectionLevel"),
            }));
        }
    }
    values
}

fn collect_android_components(
    xml: &str,
    local_name: &str,
    risk_signals: &mut BTreeSet<String>,
) -> Vec<serde_json::Value> {
    collect_xml_start_tags(xml, local_name, ANDROID_MANIFEST_COMPONENT_LIMIT + 1)
        .into_iter()
        .take(ANDROID_MANIFEST_COMPONENT_LIMIT)
        .map(|tag| {
            let attrs = xml_attributes(&tag);
            let exported = xml_attr_local(&attrs, "exported");
            let permission = xml_attr_local(&attrs, "permission");
            if exported.as_deref() == Some("true") && permission.is_none() {
                risk_signals.insert(format!("exported_{local_name}_without_permission"));
            } else if exported.as_deref() == Some("true") {
                risk_signals.insert(format!("exported_{local_name}"));
            }
            serde_json::json!({
                "name": xml_attr_local(&attrs, "name"),
                "exported": exported,
                "permission": permission,
                "enabled": xml_attr_local(&attrs, "enabled"),
                "process": xml_attr_local(&attrs, "process"),
                "direct_boot_aware": xml_attr_local(&attrs, "directBootAware"),
            })
        })
        .collect()
}

fn collect_android_permission_risk_signal(permission: &str, risk_signals: &mut BTreeSet<String>) {
    let lower = permission.to_ascii_lowercase();
    for (needle, signal) in [
        ("internet", "permission:internet"),
        ("read_sms", "permission:read_sms"),
        ("send_sms", "permission:send_sms"),
        ("receive_sms", "permission:receive_sms"),
        ("read_contacts", "permission:read_contacts"),
        ("access_fine_location", "permission:fine_location"),
        (
            "access_background_location",
            "permission:background_location",
        ),
        ("record_audio", "permission:record_audio"),
        ("camera", "permission:camera"),
        ("read_phone_state", "permission:read_phone_state"),
        (
            "request_install_packages",
            "permission:request_install_packages",
        ),
        (
            "bind_accessibility_service",
            "permission:accessibility_service",
        ),
        ("query_all_packages", "permission:query_all_packages"),
        ("system_alert_window", "permission:system_alert_window"),
        ("read_external_storage", "permission:read_external_storage"),
        (
            "write_external_storage",
            "permission:write_external_storage",
        ),
    ] {
        if lower.contains(needle) {
            risk_signals.insert(signal.to_string());
        }
    }
}

fn summarize_android_dex(name: &str, size: u64, bytes: &[u8]) -> AndroidDexSummary {
    AndroidDexSummary {
        name: name.to_string(),
        size,
        version: parse_dex_version(bytes),
        file_size: read_le_u32(bytes, 32),
        header_size: read_le_u32(bytes, 36),
        endian_tag: read_le_u32(bytes, 40).map(|value| match value {
            0x1234_5678 => "little".to_string(),
            0x7856_3412 => "reverse".to_string(),
            _ => format!("unknown:0x{value:08x}"),
        }),
        string_ids_size: read_le_u32(bytes, 56),
        type_ids_size: read_le_u32(bytes, 64),
        proto_ids_size: read_le_u32(bytes, 72),
        field_ids_size: read_le_u32(bytes, 80),
        method_ids_size: read_le_u32(bytes, 88),
        class_defs_size: read_le_u32(bytes, 96),
        data_size: read_le_u32(bytes, 104),
    }
}

fn android_dex_summary_json(summary: &AndroidDexSummary) -> serde_json::Value {
    serde_json::json!({
        "name": summary.name,
        "size": summary.size,
        "version": summary.version,
        "file_size": summary.file_size,
        "header_size": summary.header_size,
        "endian": summary.endian_tag,
        "string_ids_size": summary.string_ids_size,
        "type_ids_size": summary.type_ids_size,
        "proto_ids_size": summary.proto_ids_size,
        "field_ids_size": summary.field_ids_size,
        "method_ids_size": summary.method_ids_size,
        "class_defs_size": summary.class_defs_size,
        "data_size": summary.data_size,
    })
}

fn collect_android_dex_risk_signals(
    summary: &AndroidDexSummary,
    risk_signals: &mut BTreeSet<String>,
) {
    if summary
        .version
        .as_deref()
        .is_some_and(|version| version >= "039")
    {
        risk_signals.insert("modern_dex_version".to_string());
    }
    if summary.class_defs_size.unwrap_or(0) > 10_000 {
        risk_signals.insert("large_dex_class_count".to_string());
    }
    if summary.method_ids_size.unwrap_or(0) > 50_000 {
        risk_signals.insert("large_dex_method_count".to_string());
    }
}

fn parse_dex_version(bytes: &[u8]) -> Option<String> {
    if bytes.len() < 8 || !bytes.starts_with(b"dex\n") || bytes[7] != 0 {
        return None;
    }
    Some(String::from_utf8_lossy(&bytes[4..7]).into_owned())
}

fn is_dex_like_bytes(bytes: &[u8]) -> bool {
    parse_dex_version(bytes).is_some()
}


fn is_interesting_dex_string(text: &str) -> bool {
    let lower = text.to_ascii_lowercase();
    if text.len() < 4 {
        return false;
    }
    lower.starts_with("http://")
        || lower.starts_with("https://")
        || lower.contains("loadlibrary")
        || lower.contains("system.load")
        || lower.contains("runtime.exec")
        || lower.contains("dalvik.system")
        || lower.contains("javax.crypto")
        || lower.contains("android.permission")
        || lower.contains("base64")
        || lower.contains("encrypt")
        || lower.contains("decrypt")
        || lower.contains("shell")
        || lower.contains("su ")
        || lower.contains("/data/data/")
        || lower.contains("native-lib")
        || lower.ends_with(".so")
}

fn is_interesting_dex_method_name(name: &str) -> bool {
    let lower = name.to_ascii_lowercase();
    lower.contains("encrypt")
        || lower.contains("decrypt")
        || lower.contains("native")
        || lower.contains("jni")
        || lower.contains("hook")
        || lower.contains("load")
        || lower.contains("exec")
        || lower.contains("shell")
        || lower.contains("root")
        || lower.contains("inject")
        || lower.contains("unpack")
        || lower.contains("decode")
}

fn analyze_object_dex_bytecode(object: &UniversalObject, bytes: &[u8]) -> ObjectAnalysisSummary {
    match extract_dex_bytecode_summary(object, bytes) {
        Ok(summary) => ObjectAnalysisSummary {
            analyzer: "dex_bytecode".to_string(),
            status: if summary.truncated || !summary.warnings.is_empty() {
                ObjectAnalysisStatus::Partial
            } else {
                ObjectAnalysisStatus::Completed
            },
            summary: format!(
                "DEX {} with {} string(s), {} type(s), {} method id(s), {} class definition(s), {} risk signal(s)",
                summary.version,
                summary.string_count,
                summary.type_count,
                summary.method_count,
                summary.class_count,
                summary.risk_signal_count
            ),
            details: summary.details,
            evidence_ids: vec![format!("analysis:{}:dex_bytecode", object.id)],
        },
        Err(err) => ObjectAnalysisSummary {
            analyzer: "dex_bytecode".to_string(),
            status: ObjectAnalysisStatus::Failed,
            summary: format!("DEX bytecode analysis failed: {err}"),
            details: serde_json::json!({ "error": err.to_string() }),
            evidence_ids: vec![format!("analysis:{}:dex_bytecode", object.id)],
        },
    }
}

#[derive(Debug)]
struct DexBytecodeAnalysisSummary {
    version: String,
    string_count: usize,
    type_count: usize,
    method_count: usize,
    class_count: usize,
    risk_signal_count: usize,
    truncated: bool,
    warnings: Vec<String>,
    details: serde_json::Value,
}

#[derive(Debug)]
struct DexHeaderSummary {
    version: String,
    checksum: u32,
    signature: String,
    file_size: u32,
    header_size: u32,
    endian_tag: u32,
    link_size: u32,
    link_off: u32,
    map_off: u32,
    string_ids_size: u32,
    string_ids_off: u32,
    type_ids_size: u32,
    type_ids_off: u32,
    proto_ids_size: u32,
    proto_ids_off: u32,
    field_ids_size: u32,
    field_ids_off: u32,
    method_ids_size: u32,
    method_ids_off: u32,
    class_defs_size: u32,
    class_defs_off: u32,
    data_size: u32,
    data_off: u32,
}

#[derive(Debug, Clone)]
struct DexProtoSummary {
    index: usize,
    shorty: Option<String>,
    return_type: Option<String>,
    parameters: Vec<String>,
    parameters_off: u32,
}

#[derive(Debug, Clone)]
struct DexMethodSummary {
    index: usize,
    class: Option<String>,
    proto_index: u16,
    name: Option<String>,
    signature: String,
}

const DEX_STRING_LIMIT: usize = 512;
const DEX_ID_LIMIT: usize = 512;
const DEX_CLASS_LIMIT: usize = 256;
const DEX_TYPE_LIST_LIMIT: usize = 64;
const DEX_CLASS_DATA_MEMBER_LIMIT: usize = 128;
const DEX_STRING_VALUE_LIMIT: usize = 4096;

fn extract_dex_bytecode_summary(
    object: &UniversalObject,
    bytes: &[u8],
) -> Result<DexBytecodeAnalysisSummary> {
    let header = parse_dex_header(bytes)?;
    let mut warnings = Vec::new();
    let mut risk_signals = BTreeSet::<String>::new();
    risk_signals.insert("dex_bytecode_present".to_string());
    if header.version.as_str() >= "039" {
        risk_signals.insert("modern_dex_version".to_string());
    }
    if header.header_size != 0x70 {
        warnings.push(format!(
            "unexpected DEX header size {} (expected 112)",
            header.header_size
        ));
    }
    if header.file_size as usize > bytes.len() {
        warnings.push(format!(
            "DEX declared file size {} exceeds available {} bytes",
            header.file_size,
            bytes.len()
        ));
    }
    if header.endian_tag != 0x1234_5678 {
        warnings.push(format!(
            "DEX endian tag 0x{:08x} is not standard little endian",
            header.endian_tag
        ));
    }

    let strings = parse_dex_strings(bytes, &header, &mut warnings);
    let types = parse_dex_types(bytes, &header, &strings, &mut warnings);
    let protos = parse_dex_protos(bytes, &header, &strings, &types, &mut warnings);
    let fields = parse_dex_fields(bytes, &header, &strings, &types, &mut warnings);
    let methods = parse_dex_methods(bytes, &header, &strings, &types, &protos, &mut warnings);
    let classes = parse_dex_classes(
        bytes,
        &header,
        &strings,
        &types,
        &methods,
        &mut warnings,
        &mut risk_signals,
    );

    for string in strings.iter().flatten() {
        collect_dex_string_risk_signals(string, &mut risk_signals);
    }
    for method in &methods {
        collect_dex_method_risk_signals(method, &mut risk_signals);
    }
    if header.class_defs_size > 0 {
        risk_signals.insert("class_definitions_present".to_string());
    }
    if header.method_ids_size > 0 {
        risk_signals.insert("method_ids_present".to_string());
    }
    if header.string_ids_size as usize > strings.len() {
        risk_signals.insert("string_pool_truncated".to_string());
    }
    if header.method_ids_size as usize > methods.len() {
        risk_signals.insert("method_ids_truncated".to_string());
    }

    let string_values = strings
        .iter()
        .enumerate()
        .filter_map(|(index, value)| {
            value.as_ref().map(|value| {
                serde_json::json!({
                    "index": index,
                    "value": value,
                })
            })
        })
        .collect::<Vec<_>>();
    let type_values = types
        .iter()
        .enumerate()
        .filter_map(|(index, value)| {
            value.as_ref().map(|descriptor| {
                serde_json::json!({
                    "index": index,
                    "descriptor": descriptor,
                })
            })
        })
        .collect::<Vec<_>>();
    let proto_values = protos.iter().map(dex_proto_json).collect::<Vec<_>>();
    let method_values = methods.iter().map(dex_method_json).collect::<Vec<_>>();
    let truncated = !warnings.is_empty()
        || header.string_ids_size as usize > strings.len()
        || header.type_ids_size as usize > types.len()
        || header.proto_ids_size as usize > protos.len()
        || header.field_ids_size as usize > fields.len()
        || header.method_ids_size as usize > methods.len()
        || header.class_defs_size as usize > classes.len();
    let interesting_strings = string_values
        .iter()
        .filter_map(|value| value.as_str())
        .filter(|text| is_interesting_dex_string(text))
        .take(64)
        .map(|text| text.to_string())
        .collect::<Vec<_>>();
    let interesting_methods = method_values
        .iter()
        .filter(|method| {
            method
                .get("name")
                .and_then(|value| value.as_str())
                .is_some_and(is_interesting_dex_method_name)
                || method
                    .get("signature")
                    .and_then(|value| value.as_str())
                    .is_some_and(|sig| {
                        let lower = sig.to_ascii_lowercase();
                        lower.contains("native")
                            || lower.contains("jni")
                            || lower.contains("encrypt")
                            || lower.contains("decrypt")
                            || lower.contains("runtime")
                            || lower.contains("loadlibrary")
                    })
        })
        .take(64)
        .cloned()
        .collect::<Vec<_>>();
    if !interesting_strings.is_empty() {
        risk_signals.insert("interesting_dex_strings".to_string());
    }
    if !interesting_methods.is_empty() {
        risk_signals.insert("interesting_dex_methods".to_string());
    }
    if interesting_methods.iter().any(|method| {
        method
            .get("signature")
            .and_then(|value| value.as_str())
            .is_some_and(|sig| sig.to_ascii_lowercase().contains("native"))
    }) {
        risk_signals.insert("jni_or_native_bridge_methods".to_string());
    }
    let risk_signal_values = risk_signals.into_iter().take(256).collect::<Vec<_>>();
    let details = serde_json::json!({
        "format": object.format.as_deref().unwrap_or("dex"),
        "header": dex_header_json(&header),
        "string_count": header.string_ids_size,
        "listed_string_count": string_values.len(),
        "strings": string_values,
        "interesting_string_count": interesting_strings.len(),
        "interesting_strings": interesting_strings,
        "type_count": header.type_ids_size,
        "listed_type_count": type_values.len(),
        "types": type_values,
        "proto_count": header.proto_ids_size,
        "listed_proto_count": proto_values.len(),
        "protos": proto_values,
        "field_count": header.field_ids_size,
        "listed_field_count": fields.len(),
        "fields": fields,
        "method_count": header.method_ids_size,
        "listed_method_count": method_values.len(),
        "methods": method_values,
        "interesting_method_count": interesting_methods.len(),
        "interesting_methods": interesting_methods,
        "class_count": header.class_defs_size,
        "listed_class_count": classes.len(),
        "classes": classes,
        "risk_signals": risk_signal_values,
        "warnings": warnings,
        "truncated": truncated,
    });
    Ok(DexBytecodeAnalysisSummary {
        version: header.version,
        string_count: header.string_ids_size as usize,
        type_count: header.type_ids_size as usize,
        method_count: header.method_ids_size as usize,
        class_count: header.class_defs_size as usize,
        risk_signal_count: details["risk_signals"].as_array().map_or(0, Vec::len),
        truncated,
        warnings,
        details,
    })
}

fn parse_dex_header(bytes: &[u8]) -> Result<DexHeaderSummary> {
    let version = parse_dex_version(bytes).context("missing or invalid DEX magic")?;
    if bytes.len() < 0x70 {
        anyhow::bail!("DEX header is truncated");
    }
    Ok(DexHeaderSummary {
        version,
        checksum: read_le_u32(bytes, 8).unwrap_or(0),
        signature: bytes[12..32]
            .iter()
            .map(|byte| format!("{byte:02x}"))
            .collect::<Vec<_>>()
            .join(""),
        file_size: read_le_u32(bytes, 32).context("missing DEX file size")?,
        header_size: read_le_u32(bytes, 36).context("missing DEX header size")?,
        endian_tag: read_le_u32(bytes, 40).context("missing DEX endian tag")?,
        link_size: read_le_u32(bytes, 44).unwrap_or(0),
        link_off: read_le_u32(bytes, 48).unwrap_or(0),
        map_off: read_le_u32(bytes, 52).unwrap_or(0),
        string_ids_size: read_le_u32(bytes, 56).unwrap_or(0),
        string_ids_off: read_le_u32(bytes, 60).unwrap_or(0),
        type_ids_size: read_le_u32(bytes, 64).unwrap_or(0),
        type_ids_off: read_le_u32(bytes, 68).unwrap_or(0),
        proto_ids_size: read_le_u32(bytes, 72).unwrap_or(0),
        proto_ids_off: read_le_u32(bytes, 76).unwrap_or(0),
        field_ids_size: read_le_u32(bytes, 80).unwrap_or(0),
        field_ids_off: read_le_u32(bytes, 84).unwrap_or(0),
        method_ids_size: read_le_u32(bytes, 88).unwrap_or(0),
        method_ids_off: read_le_u32(bytes, 92).unwrap_or(0),
        class_defs_size: read_le_u32(bytes, 96).unwrap_or(0),
        class_defs_off: read_le_u32(bytes, 100).unwrap_or(0),
        data_size: read_le_u32(bytes, 104).unwrap_or(0),
        data_off: read_le_u32(bytes, 108).unwrap_or(0),
    })
}

fn parse_dex_strings(
    bytes: &[u8],
    header: &DexHeaderSummary,
    warnings: &mut Vec<String>,
) -> Vec<Option<String>> {
    let count = dex_table_count(
        bytes,
        header.string_ids_off,
        4,
        header.string_ids_size,
        DEX_STRING_LIMIT,
        "string_ids",
        warnings,
    );
    let mut strings = Vec::new();
    for index in 0..count {
        let item_offset = header.string_ids_off as usize + index * 4;
        let Some(string_data_off) = read_le_u32(bytes, item_offset) else {
            warnings.push(format!("DEX string_id[{index}] is truncated"));
            strings.push(None);
            continue;
        };
        match read_dex_string_data(bytes, string_data_off as usize) {
            Some(value) => strings.push(Some(value)),
            None => {
                warnings.push(format!(
                    "DEX string_id[{index}] points outside readable string data"
                ));
                strings.push(None);
            }
        }
    }
    strings
}

fn parse_dex_types(
    bytes: &[u8],
    header: &DexHeaderSummary,
    strings: &[Option<String>],
    warnings: &mut Vec<String>,
) -> Vec<Option<String>> {
    let count = dex_table_count(
        bytes,
        header.type_ids_off,
        4,
        header.type_ids_size,
        DEX_ID_LIMIT,
        "type_ids",
        warnings,
    );
    let mut types = Vec::new();
    for index in 0..count {
        let item_offset = header.type_ids_off as usize + index * 4;
        let descriptor = read_le_u32(bytes, item_offset)
            .and_then(|descriptor_idx| dex_string(strings, descriptor_idx));
        if descriptor.is_none() {
            warnings.push(format!("DEX type_id[{index}] has unresolved descriptor"));
        }
        types.push(descriptor);
    }
    types
}

fn parse_dex_protos(
    bytes: &[u8],
    header: &DexHeaderSummary,
    strings: &[Option<String>],
    types: &[Option<String>],
    warnings: &mut Vec<String>,
) -> Vec<DexProtoSummary> {
    let count = dex_table_count(
        bytes,
        header.proto_ids_off,
        12,
        header.proto_ids_size,
        DEX_ID_LIMIT,
        "proto_ids",
        warnings,
    );
    let mut protos = Vec::new();
    for index in 0..count {
        let item_offset = header.proto_ids_off as usize + index * 12;
        let shorty = read_le_u32(bytes, item_offset).and_then(|idx| dex_string(strings, idx));
        let return_type = read_le_u32(bytes, item_offset + 4).and_then(|idx| dex_type(types, idx));
        let parameters_off = read_le_u32(bytes, item_offset + 8).unwrap_or(0);
        let parameters = parse_dex_type_list(bytes, parameters_off, types, warnings);
        protos.push(DexProtoSummary {
            index,
            shorty,
            return_type,
            parameters,
            parameters_off,
        });
    }
    protos
}

fn parse_dex_fields(
    bytes: &[u8],
    header: &DexHeaderSummary,
    strings: &[Option<String>],
    types: &[Option<String>],
    warnings: &mut Vec<String>,
) -> Vec<serde_json::Value> {
    let count = dex_table_count(
        bytes,
        header.field_ids_off,
        8,
        header.field_ids_size,
        DEX_ID_LIMIT,
        "field_ids",
        warnings,
    );
    let mut fields = Vec::new();
    for index in 0..count {
        let item_offset = header.field_ids_off as usize + index * 8;
        let class_idx = read_le_u16(bytes, item_offset).unwrap_or(0) as u32;
        let type_idx = read_le_u16(bytes, item_offset + 2).unwrap_or(0) as u32;
        let name_idx = read_le_u32(bytes, item_offset + 4).unwrap_or(u32::MAX);
        let class = dex_type(types, class_idx);
        let ty = dex_type(types, type_idx);
        let name = dex_string(strings, name_idx);
        fields.push(serde_json::json!({
            "index": index,
            "class": class,
            "type": ty,
            "name": name,
            "signature": dex_member_signature(class.as_deref(), name.as_deref(), ty.as_deref()),
        }));
    }
    fields
}

fn parse_dex_methods(
    bytes: &[u8],
    header: &DexHeaderSummary,
    strings: &[Option<String>],
    types: &[Option<String>],
    protos: &[DexProtoSummary],
    warnings: &mut Vec<String>,
) -> Vec<DexMethodSummary> {
    let count = dex_table_count(
        bytes,
        header.method_ids_off,
        8,
        header.method_ids_size,
        DEX_ID_LIMIT,
        "method_ids",
        warnings,
    );
    let mut methods = Vec::new();
    for index in 0..count {
        let item_offset = header.method_ids_off as usize + index * 8;
        let class_idx = read_le_u16(bytes, item_offset).unwrap_or(0) as u32;
        let proto_index = read_le_u16(bytes, item_offset + 2).unwrap_or(0);
        let name_idx = read_le_u32(bytes, item_offset + 4).unwrap_or(u32::MAX);
        let class = dex_type(types, class_idx);
        let name = dex_string(strings, name_idx);
        let proto = protos.get(proto_index as usize);
        let signature = dex_method_signature(class.as_deref(), name.as_deref(), proto);
        methods.push(DexMethodSummary {
            index,
            class,
            proto_index,
            name,
            signature,
        });
    }
    methods
}

fn parse_dex_classes(
    bytes: &[u8],
    header: &DexHeaderSummary,
    strings: &[Option<String>],
    types: &[Option<String>],
    methods: &[DexMethodSummary],
    warnings: &mut Vec<String>,
    risk_signals: &mut BTreeSet<String>,
) -> Vec<serde_json::Value> {
    let count = dex_table_count(
        bytes,
        header.class_defs_off,
        32,
        header.class_defs_size,
        DEX_CLASS_LIMIT,
        "class_defs",
        warnings,
    );
    let mut classes = Vec::new();
    for index in 0..count {
        let item_offset = header.class_defs_off as usize + index * 32;
        let class_idx = read_le_u32(bytes, item_offset).unwrap_or(u32::MAX);
        let access_flags = read_le_u32(bytes, item_offset + 4).unwrap_or(0);
        let superclass_idx = read_le_u32(bytes, item_offset + 8).unwrap_or(u32::MAX);
        let interfaces_off = read_le_u32(bytes, item_offset + 12).unwrap_or(0);
        let source_file_idx = read_le_u32(bytes, item_offset + 16).unwrap_or(u32::MAX);
        let annotations_off = read_le_u32(bytes, item_offset + 20).unwrap_or(0);
        let class_data_off = read_le_u32(bytes, item_offset + 24).unwrap_or(0);
        let static_values_off = read_le_u32(bytes, item_offset + 28).unwrap_or(0);
        let descriptor = dex_type(types, class_idx);
        let class_data = parse_dex_class_data(bytes, class_data_off, methods, warnings);
        if class_data_off != 0 {
            risk_signals.insert("class_data_present".to_string());
        }
        classes.push(serde_json::json!({
            "index": index,
            "descriptor": descriptor,
            "access_flags": access_flags,
            "access": dex_access_flags(access_flags),
            "superclass": dex_type(types, superclass_idx),
            "interfaces": parse_dex_type_list(bytes, interfaces_off, types, warnings),
            "source_file": dex_string(strings, source_file_idx),
            "annotations_off": annotations_off,
            "class_data_off": class_data_off,
            "class_data": class_data,
            "static_values_off": static_values_off,
        }));
    }
    classes
}

fn parse_dex_class_data(
    bytes: &[u8],
    offset: u32,
    methods: &[DexMethodSummary],
    warnings: &mut Vec<String>,
) -> serde_json::Value {
    if offset == 0 {
        return serde_json::json!({ "present": false });
    }
    let mut cursor = offset as usize;
    let Some((static_fields_size, next)) = read_dex_uleb128(bytes, cursor) else {
        warnings.push(format!(
            "DEX class_data at {offset:#x} has truncated static field count"
        ));
        return serde_json::json!({ "present": true, "error": "truncated_static_field_count" });
    };
    cursor = next;
    let Some((instance_fields_size, next)) = read_dex_uleb128(bytes, cursor) else {
        warnings.push(format!(
            "DEX class_data at {offset:#x} has truncated instance field count"
        ));
        return serde_json::json!({ "present": true, "error": "truncated_instance_field_count" });
    };
    cursor = next;
    let Some((direct_methods_size, next)) = read_dex_uleb128(bytes, cursor) else {
        warnings.push(format!(
            "DEX class_data at {offset:#x} has truncated direct method count"
        ));
        return serde_json::json!({ "present": true, "error": "truncated_direct_method_count" });
    };
    cursor = next;
    let Some((virtual_methods_size, next)) = read_dex_uleb128(bytes, cursor) else {
        warnings.push(format!(
            "DEX class_data at {offset:#x} has truncated virtual method count"
        ));
        return serde_json::json!({ "present": true, "error": "truncated_virtual_method_count" });
    };
    cursor = next;
    cursor = skip_dex_encoded_fields(bytes, cursor, static_fields_size, warnings);
    cursor = skip_dex_encoded_fields(bytes, cursor, instance_fields_size, warnings);
    let (direct_methods, next) =
        parse_dex_encoded_methods(bytes, cursor, direct_methods_size, methods, warnings);
    let (virtual_methods, _) =
        parse_dex_encoded_methods(bytes, next, virtual_methods_size, methods, warnings);
    serde_json::json!({
        "present": true,
        "static_fields_size": static_fields_size,
        "instance_fields_size": instance_fields_size,
        "direct_methods_size": direct_methods_size,
        "virtual_methods_size": virtual_methods_size,
        "direct_methods": direct_methods,
        "virtual_methods": virtual_methods,
    })
}

fn skip_dex_encoded_fields(
    bytes: &[u8],
    mut cursor: usize,
    count: u32,
    warnings: &mut Vec<String>,
) -> usize {
    for index in 0..count.min(DEX_CLASS_DATA_MEMBER_LIMIT as u32) {
        let Some((_, next)) = read_dex_uleb128(bytes, cursor) else {
            warnings.push(format!(
                "DEX encoded_field[{index}] has truncated field index"
            ));
            return cursor;
        };
        cursor = next;
        let Some((_, next)) = read_dex_uleb128(bytes, cursor) else {
            warnings.push(format!(
                "DEX encoded_field[{index}] has truncated access flags"
            ));
            return cursor;
        };
        cursor = next;
    }
    cursor
}

fn parse_dex_encoded_methods(
    bytes: &[u8],
    mut cursor: usize,
    count: u32,
    methods: &[DexMethodSummary],
    warnings: &mut Vec<String>,
) -> (Vec<serde_json::Value>, usize) {
    let mut out = Vec::new();
    let mut method_idx = 0u32;
    for index in 0..count.min(DEX_CLASS_DATA_MEMBER_LIMIT as u32) {
        let Some((method_idx_diff, next)) = read_dex_uleb128(bytes, cursor) else {
            warnings.push(format!(
                "DEX encoded_method[{index}] has truncated method index"
            ));
            return (out, cursor);
        };
        cursor = next;
        method_idx = method_idx.saturating_add(method_idx_diff);
        let Some((access_flags, next)) = read_dex_uleb128(bytes, cursor) else {
            warnings.push(format!(
                "DEX encoded_method[{index}] has truncated access flags"
            ));
            return (out, cursor);
        };
        cursor = next;
        let Some((code_off, next)) = read_dex_uleb128(bytes, cursor) else {
            warnings.push(format!(
                "DEX encoded_method[{index}] has truncated code offset"
            ));
            return (out, cursor);
        };
        cursor = next;
        let method = methods.get(method_idx as usize);
        out.push(serde_json::json!({
            "index": index,
            "method_index": method_idx,
            "method": method.map(|method| method.signature.clone()),
            "access_flags": access_flags,
            "access": dex_access_flags(access_flags),
            "code_off": code_off,
        }));
    }
    if count as usize > DEX_CLASS_DATA_MEMBER_LIMIT {
        warnings.push(format!(
            "DEX encoded method listing truncated at {DEX_CLASS_DATA_MEMBER_LIMIT} of {count}"
        ));
    }
    (out, cursor)
}

fn parse_dex_type_list(
    bytes: &[u8],
    offset: u32,
    types: &[Option<String>],
    warnings: &mut Vec<String>,
) -> Vec<String> {
    if offset == 0 {
        return Vec::new();
    }
    let offset = offset as usize;
    let Some(size) = read_le_u32(bytes, offset) else {
        warnings.push(format!("DEX type_list at {offset:#x} is truncated"));
        return Vec::new();
    };
    let mut out = Vec::new();
    for index in 0..(size as usize).min(DEX_TYPE_LIST_LIMIT) {
        let Some(type_idx) = read_le_u16(bytes, offset + 4 + index * 2) else {
            warnings.push(format!(
                "DEX type_list[{index}] at {offset:#x} is truncated"
            ));
            break;
        };
        if let Some(descriptor) = dex_type(types, type_idx as u32) {
            out.push(descriptor);
        }
    }
    if size as usize > DEX_TYPE_LIST_LIMIT {
        warnings.push(format!(
            "DEX type_list at {offset:#x} truncated at {DEX_TYPE_LIST_LIMIT} of {size}"
        ));
    }
    out
}

fn read_dex_string_data(bytes: &[u8], offset: usize) -> Option<String> {
    let (_, cursor) = read_dex_uleb128(bytes, offset)?;
    let max_end = (cursor + DEX_STRING_VALUE_LIMIT).min(bytes.len());
    let rel_end = bytes
        .get(cursor..max_end)?
        .iter()
        .position(|byte| *byte == 0)?;
    Some(String::from_utf8_lossy(&bytes[cursor..cursor + rel_end]).to_string())
}

fn read_dex_uleb128(bytes: &[u8], offset: usize) -> Option<(u32, usize)> {
    let mut result = 0u32;
    for index in 0..5 {
        let byte = *bytes.get(offset + index)?;
        result |= ((byte & 0x7f) as u32) << (index * 7);
        if byte & 0x80 == 0 {
            return Some((result, offset + index + 1));
        }
    }
    None
}

fn dex_table_count(
    bytes: &[u8],
    offset: u32,
    item_size: usize,
    declared_count: u32,
    limit: usize,
    name: &str,
    warnings: &mut Vec<String>,
) -> usize {
    if declared_count == 0 {
        return 0;
    }
    if offset == 0 {
        warnings.push(format!(
            "DEX {name} declares {declared_count} item(s) at offset 0"
        ));
        return 0;
    }
    let offset = offset as usize;
    if offset >= bytes.len() {
        warnings.push(format!(
            "DEX {name} offset {offset:#x} is outside {} bytes",
            bytes.len()
        ));
        return 0;
    }
    let available = (bytes.len() - offset) / item_size;
    let declared = declared_count as usize;
    if available < declared {
        warnings.push(format!(
            "DEX {name} table truncated: {available} available of {declared} declared"
        ));
    }
    if declared > limit {
        warnings.push(format!(
            "DEX {name} listing truncated at {limit} of {declared} declared items"
        ));
    }
    declared.min(available).min(limit)
}

fn dex_string(strings: &[Option<String>], index: u32) -> Option<String> {
    if index == u32::MAX {
        return None;
    }
    strings.get(index as usize).and_then(Clone::clone)
}

fn dex_type(types: &[Option<String>], index: u32) -> Option<String> {
    if index == u32::MAX {
        return None;
    }
    types.get(index as usize).and_then(Clone::clone)
}

fn dex_header_json(header: &DexHeaderSummary) -> serde_json::Value {
    serde_json::json!({
        "version": header.version,
        "checksum": header.checksum,
        "signature": header.signature,
        "file_size": header.file_size,
        "header_size": header.header_size,
        "endian_tag": format!("0x{:08x}", header.endian_tag),
        "endian": match header.endian_tag {
            0x1234_5678 => "little",
            0x7856_3412 => "reverse",
            _ => "unknown",
        },
        "link_size": header.link_size,
        "link_off": header.link_off,
        "map_off": header.map_off,
        "string_ids_size": header.string_ids_size,
        "string_ids_off": header.string_ids_off,
        "type_ids_size": header.type_ids_size,
        "type_ids_off": header.type_ids_off,
        "proto_ids_size": header.proto_ids_size,
        "proto_ids_off": header.proto_ids_off,
        "field_ids_size": header.field_ids_size,
        "field_ids_off": header.field_ids_off,
        "method_ids_size": header.method_ids_size,
        "method_ids_off": header.method_ids_off,
        "class_defs_size": header.class_defs_size,
        "class_defs_off": header.class_defs_off,
        "data_size": header.data_size,
        "data_off": header.data_off,
    })
}

fn dex_proto_json(proto: &DexProtoSummary) -> serde_json::Value {
    serde_json::json!({
        "index": proto.index,
        "shorty": proto.shorty,
        "return_type": proto.return_type,
        "parameters": proto.parameters,
        "parameters_off": proto.parameters_off,
    })
}

fn dex_method_json(method: &DexMethodSummary) -> serde_json::Value {
    serde_json::json!({
        "index": method.index,
        "class": method.class,
        "proto_index": method.proto_index,
        "name": method.name,
        "signature": method.signature,
    })
}

fn dex_member_signature(
    class: Option<&str>,
    name: Option<&str>,
    descriptor: Option<&str>,
) -> String {
    format!(
        "{}->{}:{}",
        class.unwrap_or("<unknown>"),
        name.unwrap_or("<unknown>"),
        descriptor.unwrap_or("<unknown>")
    )
}

fn dex_method_signature(
    class: Option<&str>,
    name: Option<&str>,
    proto: Option<&DexProtoSummary>,
) -> String {
    let params = proto
        .map(|proto| proto.parameters.join(""))
        .unwrap_or_default();
    let return_type = proto
        .and_then(|proto| proto.return_type.as_deref())
        .unwrap_or("<unknown>");
    format!(
        "{}->{}({}){}",
        class.unwrap_or("<unknown>"),
        name.unwrap_or("<unknown>"),
        params,
        return_type
    )
}

fn dex_access_flags(flags: u32) -> Vec<&'static str> {
    let mut out = Vec::new();
    for (bit, name) in [
        (0x1, "public"),
        (0x2, "private"),
        (0x4, "protected"),
        (0x8, "static"),
        (0x10, "final"),
        (0x20, "synchronized"),
        (0x40, "volatile_or_bridge"),
        (0x80, "transient_or_varargs"),
        (0x100, "native"),
        (0x200, "interface"),
        (0x400, "abstract"),
        (0x800, "strict"),
        (0x1000, "synthetic"),
        (0x2000, "annotation"),
        (0x4000, "enum"),
        (0x10000, "constructor"),
        (0x20000, "declared_synchronized"),
    ] {
        if flags & bit != 0 {
            out.push(name);
        }
    }
    out
}

fn collect_dex_string_risk_signals(value: &str, risk_signals: &mut BTreeSet<String>) {
    let lower = value.to_ascii_lowercase();
    if lower.contains("http://") || lower.contains("https://") {
        risk_signals.insert("url_strings_present".to_string());
    }
    if lower.contains("/system/bin/sh") || lower == "su" || lower.contains("busybox") {
        risk_signals.insert("shell_command_strings".to_string());
    }
    if lower.contains("dexclassloader") || lower.contains("pathclassloader") {
        risk_signals.insert("dynamic_code_loading_strings".to_string());
    }
    if lower.contains("loadlibrary") || lower.contains("load_library") {
        risk_signals.insert("native_library_loading_strings".to_string());
    }
    if lower.contains("runtime") || lower.contains("exec") {
        risk_signals.insert("command_execution_strings".to_string());
    }
}

fn collect_dex_method_risk_signals(method: &DexMethodSummary, risk_signals: &mut BTreeSet<String>) {
    let class = method.class.as_deref().unwrap_or_default();
    let name = method.name.as_deref().unwrap_or_default();
    if class == "Ljava/lang/Runtime;" && name == "exec" {
        risk_signals.insert("runtime_exec_reference".to_string());
    }
    if class == "Ljava/lang/System;" && name == "loadLibrary" {
        risk_signals.insert("native_library_loading_reference".to_string());
    }
    if class.contains("DexClassLoader") || class.contains("PathClassLoader") {
        risk_signals.insert("dynamic_code_loading_reference".to_string());
    }
    if class.contains("java/lang/reflect") {
        risk_signals.insert("reflection_reference".to_string());
    }
    if class.contains("HttpURLConnection") || class.contains("okhttp") {
        risk_signals.insert("network_api_reference".to_string());
    }
}

fn is_android_dex_entry(name: &str) -> bool {
    let lower = name.to_ascii_lowercase();
    lower == "classes.dex"
        || (lower.starts_with("classes") && lower.ends_with(".dex"))
        || lower.ends_with("/classes.dex")
}

fn android_native_lib_entry(name: &str) -> Option<(String, String)> {
    let remainder = name.strip_prefix("lib/")?;
    let (abi, library) = remainder.split_once('/')?;
    if library.ends_with(".so") && !abi.is_empty() {
        Some((abi.to_string(), library.to_string()))
    } else {
        None
    }
}

fn android_entry_role(name: &str) -> &'static str {
    if name == "AndroidManifest.xml" {
        "manifest"
    } else if is_android_dex_entry(name) {
        "dex_bytecode"
    } else if name == "resources.arsc" {
        "compiled_resources"
    } else if android_native_lib_entry(name).is_some() {
        "native_library"
    } else if name.starts_with("assets/") {
        "asset"
    } else if name.starts_with("res/") {
        android_resource_role(name)
    } else if name.starts_with("META-INF/") {
        android_meta_inf_role(name)
    } else {
        "entry"
    }
}

fn android_resource_role(name: &str) -> &'static str {
    if name.starts_with("res/layout") {
        "layout_resource"
    } else if name.starts_with("res/xml") {
        "xml_resource"
    } else if name.starts_with("res/drawable") || name.starts_with("res/mipmap") {
        "image_or_drawable_resource"
    } else if name.starts_with("res/raw") {
        "raw_resource"
    } else if name.starts_with("res/values") {
        "value_resource"
    } else {
        "resource"
    }
}

fn android_asset_role(name: &str) -> &'static str {
    let lower = name.to_ascii_lowercase();
    if lower.ends_with(".dex") || lower.ends_with(".jar") || lower.ends_with(".apk") {
        "embedded_executable_or_package"
    } else if lower.ends_with(".so") {
        "embedded_native_library"
    } else if lower.ends_with(".js") || lower.ends_with(".html") {
        "web_asset"
    } else if lower.ends_with(".json") || lower.ends_with(".xml") {
        "structured_asset"
    } else {
        "asset"
    }
}

fn android_meta_inf_role(name: &str) -> &'static str {
    android_signature_file_role(name).unwrap_or("metadata")
}

fn android_signature_file_role(name: &str) -> Option<&'static str> {
    let lower = name.to_ascii_lowercase();
    if lower.ends_with("/manifest.mf") || lower == "meta-inf/manifest.mf" {
        Some("jar_manifest")
    } else if lower.ends_with(".sf") {
        Some("jar_signature_metadata")
    } else if lower.ends_with(".rsa") || lower.ends_with(".dsa") || lower.ends_with(".ec") {
        Some("jar_signature_block")
    } else {
        None
    }
}

fn detect_android_signing_block(bytes: &[u8]) -> serde_json::Value {
    const APK_SIG_BLOCK_MAGIC: &[u8; 16] = b"APK Sig Block 42";
    let Some(eocd_offset) = find_zip_eocd(bytes) else {
        return serde_json::json!({ "present": false, "reason": "zip_eocd_not_found" });
    };
    let Some(central_directory_offset) = read_le_u32(bytes, eocd_offset + 16) else {
        return serde_json::json!({ "present": false, "reason": "zip_eocd_truncated" });
    };
    let cd_offset = central_directory_offset as usize;
    if cd_offset < 24 || cd_offset > bytes.len() {
        return serde_json::json!({ "present": false, "reason": "central_directory_offset_out_of_range" });
    }
    let footer = &bytes[cd_offset - 24..cd_offset];
    if &footer[8..24] != APK_SIG_BLOCK_MAGIC {
        return serde_json::json!({ "present": false });
    }
    let Some(size_without_first_size) = read_le_u64(footer, 0) else {
        return serde_json::json!({ "present": false, "reason": "signing_block_footer_truncated" });
    };
    let total_size = size_without_first_size.saturating_add(8);
    let start = cd_offset.saturating_sub(total_size as usize);
    serde_json::json!({
        "present": true,
        "offset": start,
        "size": total_size,
    })
}

fn find_zip_eocd(bytes: &[u8]) -> Option<usize> {
    if bytes.len() < 22 {
        return None;
    }
    let min = bytes.len().saturating_sub(22 + 65_535);
    (min..=bytes.len() - 22)
        .rev()
        .find(|offset| bytes.get(*offset..offset + 4) == Some(b"PK\x05\x06"))
}

fn analyze_object_java_archive(object: &UniversalObject, bytes: &[u8]) -> ObjectAnalysisSummary {
    match extract_java_archive_summary(object, bytes) {
        Ok(summary) => ObjectAnalysisSummary {
            analyzer: "java_archive".to_string(),
            status: if summary.truncated || !summary.warnings.is_empty() {
                ObjectAnalysisStatus::Partial
            } else {
                ObjectAnalysisStatus::Completed
            },
            summary: format!(
                "Java archive with {} entries, {} class file(s), {} service provider file(s), {} risk signal(s)",
                summary.entry_count,
                summary.class_count,
                summary.service_count,
                summary.risk_signal_count
            ),
            details: summary.details,
            evidence_ids: vec![format!("analysis:{}:java_archive", object.id)],
        },
        Err(err) => ObjectAnalysisSummary {
            analyzer: "java_archive".to_string(),
            status: ObjectAnalysisStatus::Failed,
            summary: format!("Java archive analysis failed: {err}"),
            details: serde_json::json!({ "error": err.to_string() }),
            evidence_ids: vec![format!("analysis:{}:java_archive", object.id)],
        },
    }
}

#[derive(Debug)]
struct JavaArchiveAnalysisSummary {
    entry_count: usize,
    class_count: usize,
    service_count: usize,
    risk_signal_count: usize,
    truncated: bool,
    warnings: Vec<String>,
    details: serde_json::Value,
}

#[derive(Debug)]
struct JavaClassSummary {
    name: String,
    size: u64,
    major_version: Option<u16>,
    minor_version: Option<u16>,
    java_version: Option<String>,
}

const JAVA_ARCHIVE_ENTRY_SCAN_LIMIT: usize = 4096;
const JAVA_ARCHIVE_ENTRY_LIST_LIMIT: usize = 512;
const JAVA_ARCHIVE_MANIFEST_READ_LIMIT: usize = 512 * 1024;
const JAVA_ARCHIVE_SERVICE_READ_LIMIT: usize = 128 * 1024;
const JAVA_ARCHIVE_CLASS_READ_LIMIT: usize = 32;
const JAVA_ARCHIVE_SAMPLE_LIMIT: usize = 128;

fn zip_contains_java_archive_markers(bytes: &[u8]) -> bool {
    if !is_zip_like_bytes(bytes) {
        return false;
    }
    let cursor = Cursor::new(bytes);
    let Ok(mut archive) = zip::ZipArchive::new(cursor) else {
        return false;
    };
    let mut has_manifest = false;
    let mut has_class = false;
    let mut has_service = false;
    for index in 0..archive.len().min(JAVA_ARCHIVE_ENTRY_SCAN_LIMIT) {
        let Ok(file) = archive.by_index(index) else {
            continue;
        };
        let name = file.name();
        if name.eq_ignore_ascii_case("META-INF/MANIFEST.MF") {
            has_manifest = true;
        }
        if name.ends_with(".class") {
            has_class = true;
        }
        if name.starts_with("META-INF/services/") {
            has_service = true;
        }
        if has_class && (has_manifest || has_service) {
            return true;
        }
    }
    has_manifest && has_class
}

fn extract_java_archive_summary(
    object: &UniversalObject,
    bytes: &[u8],
) -> Result<JavaArchiveAnalysisSummary> {
    if !is_zip_like_bytes(bytes) {
        anyhow::bail!("object is not a ZIP-based Java archive");
    }
    let cursor = Cursor::new(bytes);
    let mut archive =
        zip::ZipArchive::new(cursor).context("failed to parse Java archive ZIP container")?;
    let entry_count = archive.len();
    let mut warnings = Vec::new();
    let mut risk_signals = BTreeSet::<String>::new();
    let mut entries = Vec::new();
    let mut class_entries = Vec::<(String, u64)>::new();
    let mut service_entries = Vec::<(String, u64)>::new();
    let mut package_counts = BTreeMap::<String, usize>::new();
    let mut native_libraries = Vec::new();
    let mut nested_archives = Vec::new();
    let mut meta_inf = Vec::new();
    let mut signature_files = Vec::new();
    let mut native_library_count = 0usize;
    let mut nested_archive_count = 0usize;

    for index in 0..entry_count.min(JAVA_ARCHIVE_ENTRY_SCAN_LIMIT) {
        let file = archive
            .by_index(index)
            .with_context(|| format!("failed to read JAR ZIP entry index {index}"))?;
        let name = file.name().to_string();
        let role = java_archive_entry_role(&name);
        if entries.len() < JAVA_ARCHIVE_ENTRY_LIST_LIMIT {
            entries.push(serde_json::json!({
                "index": index,
                "name": name,
                "role": role,
                "is_dir": file.is_dir(),
                "compressed_size": file.compressed_size(),
                "uncompressed_size": file.size(),
            }));
        }
        if file.is_dir() {
            continue;
        }
        if name.ends_with(".class") {
            *package_counts
                .entry(java_class_package_name(&name))
                .or_default() += 1;
            class_entries.push((name.clone(), file.size()));
        }
        if name.starts_with("META-INF/services/") && name.len() > "META-INF/services/".len() {
            service_entries.push((name.clone(), file.size()));
        }
        if java_native_library_entry(&name) {
            native_library_count += 1;
            if native_libraries.len() < JAVA_ARCHIVE_SAMPLE_LIMIT {
                native_libraries.push(serde_json::json!({
                    "path": name,
                    "size": file.size(),
                    "format_hint": java_native_library_format(&name),
                }));
            }
        }
        if java_nested_archive_entry(&name) {
            nested_archive_count += 1;
            if nested_archives.len() < JAVA_ARCHIVE_SAMPLE_LIMIT {
                nested_archives.push(serde_json::json!({
                    "path": name,
                    "size": file.size(),
                    "format_hint": java_nested_archive_format(&name),
                }));
            }
        }
        if name.starts_with("META-INF/") {
            if meta_inf.len() < JAVA_ARCHIVE_SAMPLE_LIMIT {
                meta_inf.push(serde_json::json!({
                    "path": name,
                    "size": file.size(),
                    "role": java_archive_meta_inf_role(&name),
                }));
            }
            if java_archive_signature_file_role(&name).is_some() {
                signature_files.push(name);
            }
        }
    }

    if entry_count > JAVA_ARCHIVE_ENTRY_SCAN_LIMIT {
        warnings.push(format!(
            "JAR entry scan truncated at {JAVA_ARCHIVE_ENTRY_SCAN_LIMIT} of {entry_count} entries"
        ));
    }

    let manifest = java_manifest_summary(&mut archive, &mut risk_signals, &mut warnings)?
        .unwrap_or_else(|| {
            serde_json::json!({
                "present": false,
                "attributes": {},
            })
        });
    let services = java_service_summaries(&mut archive, &service_entries, &mut warnings)?;
    for service in &services {
        if service["provider_count"].as_u64().unwrap_or(0) > 0 {
            risk_signals.insert("service_loader_entries".to_string());
        }
    }
    let mut class_values = Vec::new();
    for (name, size) in class_entries.iter().take(JAVA_ARCHIVE_SAMPLE_LIMIT) {
        match read_zip_prefix(&mut archive, name, JAVA_ARCHIVE_CLASS_READ_LIMIT) {
            Ok(prefix) => {
                let summary = summarize_java_class(name, *size, &prefix);
                collect_java_class_risk_signals(&summary, &mut risk_signals);
                class_values.push(java_class_summary_json(&summary));
            }
            Err(err) => {
                warnings.push(format!("failed to read class entry {name}: {err}"));
                class_values.push(serde_json::json!({
                    "name": name,
                    "size": size,
                    "error": err.to_string(),
                }));
            }
        }
    }
    if class_entries.len() > class_values.len() {
        risk_signals.insert("class_listing_truncated".to_string());
    }
    if class_entries.len() > 1_000 {
        risk_signals.insert("large_class_count".to_string());
    }
    if native_library_count > 0 {
        risk_signals.insert("native_libraries_in_archive".to_string());
    }
    if nested_archive_count > 0 {
        risk_signals.insert("nested_archives_in_archive".to_string());
    }
    if signature_files.iter().any(|name| {
        name.to_ascii_lowercase().ends_with(".rsa")
            || name.to_ascii_lowercase().ends_with(".dsa")
            || name.to_ascii_lowercase().ends_with(".ec")
    }) {
        risk_signals.insert("jar_signature_file_present".to_string());
    }

    let packages = package_counts
        .iter()
        .take(JAVA_ARCHIVE_SAMPLE_LIMIT)
        .map(|(name, count)| {
            serde_json::json!({
                "package": name,
                "class_count": count,
            })
        })
        .collect::<Vec<_>>();
    let truncated = entry_count > entries.len()
        || entry_count > JAVA_ARCHIVE_ENTRY_SCAN_LIMIT
        || class_entries.len() > class_values.len()
        || service_entries.len() > services.len();
    let risk_signal_values = risk_signals.into_iter().take(256).collect::<Vec<_>>();
    let details = serde_json::json!({
        "format": object.format.as_deref().unwrap_or("jar"),
        "entry_count": entry_count,
        "scanned_entry_count": entry_count.min(JAVA_ARCHIVE_ENTRY_SCAN_LIMIT),
        "listed_entry_count": entries.len(),
        "entries_truncated": entry_count > entries.len() || entry_count > JAVA_ARCHIVE_ENTRY_SCAN_LIMIT,
        "entries": entries,
        "manifest": manifest,
        "class_count": class_entries.len(),
        "listed_class_count": class_values.len(),
        "classes": class_values,
        "packages": packages,
        "service_count": service_entries.len(),
        "services": services,
        "native_library_count": native_library_count,
        "native_libraries": native_libraries,
        "nested_archive_count": nested_archive_count,
        "nested_archives": nested_archives,
        "meta_inf": meta_inf,
        "signature_files": signature_files,
        "risk_signals": risk_signal_values,
        "warnings": warnings,
        "truncated": truncated,
    });
    Ok(JavaArchiveAnalysisSummary {
        entry_count,
        class_count: class_entries.len(),
        service_count: service_entries.len(),
        risk_signal_count: details["risk_signals"].as_array().map_or(0, Vec::len),
        truncated,
        warnings,
        details,
    })
}

fn java_manifest_summary<R: Read + std::io::Seek>(
    archive: &mut zip::ZipArchive<R>,
    risk_signals: &mut BTreeSet<String>,
    warnings: &mut Vec<String>,
) -> Result<Option<serde_json::Value>> {
    let Some(entry) = read_zip_text_entry(
        archive,
        "META-INF/MANIFEST.MF",
        JAVA_ARCHIVE_MANIFEST_READ_LIMIT,
    )?
    else {
        return Ok(None);
    };
    if entry.truncated {
        warnings.push("META-INF/MANIFEST.MF was truncated during analysis".to_string());
    }
    let attributes = parse_manifest_attributes(&entry.text);
    let main_class = manifest_attr(&attributes, "Main-Class");
    let agent_class = manifest_attr(&attributes, "Agent-Class");
    let premain_class = manifest_attr(&attributes, "Premain-Class");
    let launcher_agent_class = manifest_attr(&attributes, "Launcher-Agent-Class");
    let class_path = manifest_attr(&attributes, "Class-Path")
        .map(|value| {
            value
                .split_whitespace()
                .take(JAVA_ARCHIVE_SAMPLE_LIMIT)
                .map(ToOwned::to_owned)
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();
    if main_class.is_some() {
        risk_signals.insert("jar_main_class_present".to_string());
    }
    if agent_class.is_some() || premain_class.is_some() || launcher_agent_class.is_some() {
        risk_signals.insert("java_agent_entry_present".to_string());
    }
    if manifest_attr(&attributes, "Multi-Release").as_deref() == Some("true") {
        risk_signals.insert("multi_release_jar".to_string());
    }
    if !class_path.is_empty() {
        risk_signals.insert("manifest_class_path_present".to_string());
    }
    let attributes_json = attributes
        .iter()
        .take(JAVA_ARCHIVE_SAMPLE_LIMIT)
        .map(|(name, value)| {
            serde_json::json!({
                "name": name,
                "value": value,
            })
        })
        .collect::<Vec<_>>();
    Ok(Some(serde_json::json!({
        "present": true,
        "size": entry.size,
        "truncated": entry.truncated,
        "main_class": main_class,
        "agent_class": agent_class,
        "premain_class": premain_class,
        "launcher_agent_class": launcher_agent_class,
        "multi_release": manifest_attr(&attributes, "Multi-Release"),
        "class_path": class_path,
        "implementation_title": manifest_attr(&attributes, "Implementation-Title"),
        "implementation_version": manifest_attr(&attributes, "Implementation-Version"),
        "automatic_module_name": manifest_attr(&attributes, "Automatic-Module-Name"),
        "sealed": manifest_attr(&attributes, "Sealed"),
        "attributes": attributes_json,
    })))
}

fn parse_manifest_attributes(text: &str) -> BTreeMap<String, String> {
    let mut attrs = BTreeMap::new();
    let mut current_name = None::<String>;
    for raw_line in text.replace("\r\n", "\n").replace('\r', "\n").lines() {
        if raw_line.is_empty() {
            continue;
        }
        if let Some(rest) = raw_line.strip_prefix(' ') {
            if let Some(name) = current_name.as_ref() {
                attrs
                    .entry(name.clone())
                    .and_modify(|value: &mut String| value.push_str(rest));
            }
            continue;
        }
        let Some((name, value)) = raw_line.split_once(':') else {
            continue;
        };
        let name = name.trim().to_string();
        let value = value.trim_start().to_string();
        current_name = Some(name.clone());
        attrs.insert(name, value);
    }
    attrs
}

fn manifest_attr(attrs: &BTreeMap<String, String>, name: &str) -> Option<String> {
    attrs
        .iter()
        .find(|(key, _)| key.eq_ignore_ascii_case(name))
        .map(|(_, value)| value.clone())
}

fn java_service_summaries<R: Read + std::io::Seek>(
    archive: &mut zip::ZipArchive<R>,
    services: &[(String, u64)],
    warnings: &mut Vec<String>,
) -> Result<Vec<serde_json::Value>> {
    let mut values = Vec::new();
    for (path, size) in services.iter().take(JAVA_ARCHIVE_SAMPLE_LIMIT) {
        match read_zip_text_entry(archive, path, JAVA_ARCHIVE_SERVICE_READ_LIMIT) {
            Ok(Some(entry)) => {
                if entry.truncated {
                    warnings.push(format!("{path} was truncated during analysis"));
                }
                let providers = entry
                    .text
                    .lines()
                    .map(|line| {
                        line.split_once('#')
                            .map(|(left, _)| left)
                            .unwrap_or(line)
                            .trim()
                    })
                    .filter(|line| !line.is_empty())
                    .take(JAVA_ARCHIVE_SAMPLE_LIMIT)
                    .map(ToOwned::to_owned)
                    .collect::<Vec<_>>();
                values.push(serde_json::json!({
                    "path": path,
                    "service": path.trim_start_matches("META-INF/services/"),
                    "size": size,
                    "provider_count": providers.len(),
                    "providers": providers,
                    "truncated": entry.truncated,
                }));
            }
            Ok(None) => values.push(serde_json::json!({
                "path": path,
                "service": path.trim_start_matches("META-INF/services/"),
                "size": size,
                "error": "service entry not found",
            })),
            Err(err) => {
                warnings.push(format!(
                    "failed to read service provider entry {path}: {err}"
                ));
                values.push(serde_json::json!({
                    "path": path,
                    "service": path.trim_start_matches("META-INF/services/"),
                    "size": size,
                    "error": err.to_string(),
                }));
            }
        }
    }
    Ok(values)
}

fn summarize_java_class(name: &str, size: u64, bytes: &[u8]) -> JavaClassSummary {
    let major = read_be_u16(bytes, 6);
    let minor = read_be_u16(bytes, 4);
    JavaClassSummary {
        name: name.to_string(),
        size,
        major_version: major,
        minor_version: minor,
        java_version: major
            .map(java_class_major_version_label)
            .map(ToOwned::to_owned),
    }
}

fn java_class_summary_json(summary: &JavaClassSummary) -> serde_json::Value {
    serde_json::json!({
        "name": summary.name,
        "size": summary.size,
        "major_version": summary.major_version,
        "minor_version": summary.minor_version,
        "java_version": summary.java_version,
        "package": java_class_package_name(&summary.name),
    })
}

fn collect_java_class_risk_signals(
    summary: &JavaClassSummary,
    risk_signals: &mut BTreeSet<String>,
) {
    if summary.name.starts_with("META-INF/versions/") {
        risk_signals.insert("multi_release_class_entries".to_string());
    }
    if summary.major_version.unwrap_or(0) >= 61 {
        risk_signals.insert("modern_java_class_version".to_string());
    }
}

fn is_jvm_class_like_bytes(bytes: &[u8]) -> bool {
    bytes.starts_with(&[0xca, 0xfe, 0xba, 0xbe])
}

fn analyze_object_jvm_class(object: &UniversalObject, bytes: &[u8]) -> ObjectAnalysisSummary {
    match extract_jvm_class_summary(object, bytes) {
        Ok(summary) => ObjectAnalysisSummary {
            analyzer: "jvm_class".to_string(),
            status: if summary.truncated || !summary.warnings.is_empty() {
                ObjectAnalysisStatus::Partial
            } else {
                ObjectAnalysisStatus::Completed
            },
            summary: format!(
                "JVM class {} extends {} with {} field(s), {} method(s), {} risk signal(s)",
                summary.class_name,
                summary.super_name.unwrap_or_else(|| "none".to_string()),
                summary.field_count,
                summary.method_count,
                summary.risk_signal_count
            ),
            details: summary.details,
            evidence_ids: vec![format!("analysis:{}:jvm_class", object.id)],
        },
        Err(err) => ObjectAnalysisSummary {
            analyzer: "jvm_class".to_string(),
            status: ObjectAnalysisStatus::Failed,
            summary: format!("JVM class analysis failed: {err}"),
            details: serde_json::json!({ "error": err.to_string() }),
            evidence_ids: vec![format!("analysis:{}:jvm_class", object.id)],
        },
    }
}

#[derive(Debug)]
struct JvmClassAnalysisSummary {
    class_name: String,
    super_name: Option<String>,
    field_count: usize,
    method_count: usize,
    risk_signal_count: usize,
    truncated: bool,
    warnings: Vec<String>,
    details: serde_json::Value,
}

#[derive(Debug, Clone)]
enum JvmConstantPoolEntry {
    Utf8(String),
    Integer,
    Float,
    Long,
    Double,
    Class {
        name_index: u16,
    },
    String {
        string_index: u16,
    },
    Fieldref {
        class_index: u16,
        name_and_type_index: u16,
    },
    Methodref {
        class_index: u16,
        name_and_type_index: u16,
    },
    InterfaceMethodref {
        class_index: u16,
        name_and_type_index: u16,
    },
    NameAndType {
        name_index: u16,
        descriptor_index: u16,
    },
    MethodHandle {
        reference_kind: u8,
        reference_index: u16,
    },
    MethodType {
        descriptor_index: u16,
    },
    Dynamic {
        bootstrap_method_attr_index: u16,
        name_and_type_index: u16,
    },
    InvokeDynamic {
        bootstrap_method_attr_index: u16,
        name_and_type_index: u16,
    },
    Module {
        name_index: u16,
    },
    Package {
        name_index: u16,
    },
    Unusable,
}

#[derive(Debug)]
struct JvmClassParseContext {
    constant_pool: Vec<Option<JvmConstantPoolEntry>>,
    cursor: usize,
    warnings: Vec<String>,
}

const JVM_CONSTANT_POOL_LIMIT: usize = 1024;
const JVM_MEMBER_LIMIT: usize = 512;
const JVM_ATTRIBUTE_LIMIT: usize = 512;
const JVM_REFERENCE_LIMIT: usize = 512;
const JVM_STRING_LIMIT: usize = 512;

fn extract_jvm_class_summary(
    object: &UniversalObject,
    bytes: &[u8],
) -> Result<JvmClassAnalysisSummary> {
    if !is_jvm_class_like_bytes(bytes) {
        anyhow::bail!("object is not a JVM class file");
    }
    let minor_version = read_be_u16(bytes, 4).context("missing JVM class minor version")?;
    let major_version = read_be_u16(bytes, 6).context("missing JVM class major version")?;
    let constant_pool_count = read_be_u16(bytes, 8).context("missing JVM constant pool count")?;
    let mut context = parse_jvm_constant_pool(bytes, constant_pool_count)?;
    let access_flags =
        read_be_u16(bytes, context.cursor).context("missing JVM class access flags")?;
    let this_class = read_be_u16(bytes, context.cursor + 2).context("missing JVM this_class")?;
    let super_class = read_be_u16(bytes, context.cursor + 4).unwrap_or(0);
    context.cursor += 6;
    let interfaces_count =
        read_be_u16(bytes, context.cursor).context("missing JVM interfaces count")? as usize;
    context.cursor += 2;
    let mut interfaces = Vec::new();
    for index in 0..interfaces_count.min(JVM_MEMBER_LIMIT) {
        let Some(interface_index) = read_be_u16(bytes, context.cursor) else {
            context
                .warnings
                .push(format!("JVM interface[{index}] is truncated"));
            break;
        };
        context.cursor += 2;
        if let Some(name) = jvm_cp_class_name(&context.constant_pool, interface_index) {
            interfaces.push(name);
        }
    }
    if interfaces_count > JVM_MEMBER_LIMIT {
        context.warnings.push(format!(
            "JVM interface listing truncated at {JVM_MEMBER_LIMIT} of {interfaces_count}"
        ));
        context.cursor = context
            .cursor
            .saturating_add((interfaces_count - JVM_MEMBER_LIMIT) * 2);
    }

    let fields = parse_jvm_members(bytes, &mut context, "field");
    let methods = parse_jvm_members(bytes, &mut context, "method");
    let class_attributes = parse_jvm_attributes(bytes, &mut context, "class");
    let class_name = jvm_cp_class_name(&context.constant_pool, this_class)
        .unwrap_or_else(|| "<unknown>".to_string());
    let super_name = (super_class != 0)
        .then(|| jvm_cp_class_name(&context.constant_pool, super_class))
        .flatten();
    let constant_pool_preview = jvm_constant_pool_preview(&context.constant_pool);
    let string_constants = jvm_string_constants(&context.constant_pool);
    let references = jvm_member_references(&context.constant_pool);
    let mut risk_signals = BTreeSet::<String>::new();
    risk_signals.insert("jvm_class_present".to_string());
    if major_version >= 61 {
        risk_signals.insert("modern_java_class_version".to_string());
    }
    collect_jvm_access_risk_signals(access_flags as u32, &mut risk_signals);
    for method in &methods {
        if method["name"] == serde_json::json!("<clinit>") {
            risk_signals.insert("static_initializer_present".to_string());
        }
        if method["access"]
            .as_array()
            .is_some_and(|items| items.iter().any(|item| item == "native"))
        {
            risk_signals.insert("native_methods_present".to_string());
        }
    }
    for reference in &references {
        collect_jvm_reference_risk_signals(reference, &mut risk_signals);
    }
    for value in &string_constants {
        if let Some(value) = value["value"].as_str() {
            collect_jvm_string_risk_signals(value, &mut risk_signals);
        }
    }
    for attribute in &class_attributes {
        if attribute["name"] == serde_json::json!("BootstrapMethods") {
            risk_signals.insert("invokedynamic_bootstrap_methods".to_string());
        }
        if attribute["name"] == serde_json::json!("Module") {
            risk_signals.insert("module_descriptor_present".to_string());
        }
    }
    let truncated = !context.warnings.is_empty()
        || constant_pool_count as usize > constant_pool_preview.len() + 1
        || fields.len() >= JVM_MEMBER_LIMIT
        || methods.len() >= JVM_MEMBER_LIMIT
        || class_attributes.len() >= JVM_ATTRIBUTE_LIMIT;
    let risk_signal_values = risk_signals.into_iter().take(256).collect::<Vec<_>>();
    let details = serde_json::json!({
        "format": object.format.as_deref().unwrap_or("jvm_class"),
        "minor_version": minor_version,
        "major_version": major_version,
        "java_version": java_class_major_version_label(major_version),
        "constant_pool_count": constant_pool_count,
        "constant_pool": constant_pool_preview,
        "class": {
            "name": class_name,
            "super_name": super_name,
            "access_flags": access_flags,
            "access": jvm_access_flags(access_flags as u32),
            "interfaces": interfaces,
        },
        "field_count": fields.len(),
        "fields": fields,
        "method_count": methods.len(),
        "methods": methods,
        "class_attributes": class_attributes,
        "references": references,
        "string_constants": string_constants,
        "risk_signals": risk_signal_values,
        "warnings": context.warnings,
        "truncated": truncated,
    });
    Ok(JvmClassAnalysisSummary {
        class_name,
        super_name,
        field_count: details["field_count"].as_u64().unwrap_or(0) as usize,
        method_count: details["method_count"].as_u64().unwrap_or(0) as usize,
        risk_signal_count: details["risk_signals"].as_array().map_or(0, Vec::len),
        truncated,
        warnings: details["warnings"]
            .as_array()
            .map(|items| {
                items
                    .iter()
                    .filter_map(|item| item.as_str().map(ToOwned::to_owned))
                    .collect()
            })
            .unwrap_or_default(),
        details,
    })
}

fn parse_jvm_constant_pool(bytes: &[u8], count: u16) -> Result<JvmClassParseContext> {
    let mut pool = vec![None; count as usize];
    let mut cursor = 10usize;
    let mut warnings = Vec::new();
    let mut index = 1usize;
    while index < count as usize {
        let tag = *bytes
            .get(cursor)
            .with_context(|| format!("JVM constant_pool[{index}] tag is truncated"))?;
        cursor += 1;
        let entry = match tag {
            1 => {
                let len = read_be_u16(bytes, cursor)
                    .with_context(|| format!("JVM Utf8 constant[{index}] length missing"))?
                    as usize;
                cursor += 2;
                let data = bytes
                    .get(cursor..cursor + len)
                    .with_context(|| format!("JVM Utf8 constant[{index}] bytes truncated"))?;
                cursor += len;
                JvmConstantPoolEntry::Utf8(String::from_utf8_lossy(data).to_string())
            }
            3 => {
                cursor += 4;
                JvmConstantPoolEntry::Integer
            }
            4 => {
                cursor += 4;
                JvmConstantPoolEntry::Float
            }
            5 => {
                cursor += 8;
                pool[index] = Some(JvmConstantPoolEntry::Long);
                index += 1;
                if index < pool.len() {
                    pool[index] = Some(JvmConstantPoolEntry::Unusable);
                }
                index += 1;
                continue;
            }
            6 => {
                cursor += 8;
                pool[index] = Some(JvmConstantPoolEntry::Double);
                index += 1;
                if index < pool.len() {
                    pool[index] = Some(JvmConstantPoolEntry::Unusable);
                }
                index += 1;
                continue;
            }
            7 => {
                let name_index = read_be_u16(bytes, cursor)
                    .with_context(|| format!("JVM Class constant[{index}] truncated"))?;
                cursor += 2;
                JvmConstantPoolEntry::Class { name_index }
            }
            8 => {
                let string_index = read_be_u16(bytes, cursor)
                    .with_context(|| format!("JVM String constant[{index}] truncated"))?;
                cursor += 2;
                JvmConstantPoolEntry::String { string_index }
            }
            9 => {
                let class_index = read_be_u16(bytes, cursor)
                    .with_context(|| format!("JVM Fieldref constant[{index}] class truncated"))?;
                let name_and_type_index = read_be_u16(bytes, cursor + 2).with_context(|| {
                    format!("JVM Fieldref constant[{index}] name_and_type truncated")
                })?;
                cursor += 4;
                JvmConstantPoolEntry::Fieldref {
                    class_index,
                    name_and_type_index,
                }
            }
            10 => {
                let class_index = read_be_u16(bytes, cursor)
                    .with_context(|| format!("JVM Methodref constant[{index}] class truncated"))?;
                let name_and_type_index = read_be_u16(bytes, cursor + 2).with_context(|| {
                    format!("JVM Methodref constant[{index}] name_and_type truncated")
                })?;
                cursor += 4;
                JvmConstantPoolEntry::Methodref {
                    class_index,
                    name_and_type_index,
                }
            }
            11 => {
                let class_index = read_be_u16(bytes, cursor).with_context(|| {
                    format!("JVM InterfaceMethodref constant[{index}] class truncated")
                })?;
                let name_and_type_index = read_be_u16(bytes, cursor + 2).with_context(|| {
                    format!("JVM InterfaceMethodref constant[{index}] name_and_type truncated")
                })?;
                cursor += 4;
                JvmConstantPoolEntry::InterfaceMethodref {
                    class_index,
                    name_and_type_index,
                }
            }
            12 => {
                let name_index = read_be_u16(bytes, cursor)
                    .with_context(|| format!("JVM NameAndType constant[{index}] name truncated"))?;
                let descriptor_index = read_be_u16(bytes, cursor + 2).with_context(|| {
                    format!("JVM NameAndType constant[{index}] descriptor truncated")
                })?;
                cursor += 4;
                JvmConstantPoolEntry::NameAndType {
                    name_index,
                    descriptor_index,
                }
            }
            15 => {
                let reference_kind = *bytes.get(cursor).with_context(|| {
                    format!("JVM MethodHandle constant[{index}] reference kind truncated")
                })?;
                let reference_index = read_be_u16(bytes, cursor + 1).with_context(|| {
                    format!("JVM MethodHandle constant[{index}] reference index truncated")
                })?;
                cursor += 3;
                JvmConstantPoolEntry::MethodHandle {
                    reference_kind,
                    reference_index,
                }
            }
            16 => {
                let descriptor_index = read_be_u16(bytes, cursor).with_context(|| {
                    format!("JVM MethodType constant[{index}] descriptor truncated")
                })?;
                cursor += 2;
                JvmConstantPoolEntry::MethodType { descriptor_index }
            }
            17 => {
                let bootstrap_method_attr_index =
                    read_be_u16(bytes, cursor).with_context(|| {
                        format!("JVM Dynamic constant[{index}] bootstrap index truncated")
                    })?;
                let name_and_type_index = read_be_u16(bytes, cursor + 2).with_context(|| {
                    format!("JVM Dynamic constant[{index}] name_and_type truncated")
                })?;
                cursor += 4;
                JvmConstantPoolEntry::Dynamic {
                    bootstrap_method_attr_index,
                    name_and_type_index,
                }
            }
            18 => {
                let bootstrap_method_attr_index =
                    read_be_u16(bytes, cursor).with_context(|| {
                        format!("JVM InvokeDynamic constant[{index}] bootstrap index truncated")
                    })?;
                let name_and_type_index = read_be_u16(bytes, cursor + 2).with_context(|| {
                    format!("JVM InvokeDynamic constant[{index}] name_and_type truncated")
                })?;
                cursor += 4;
                JvmConstantPoolEntry::InvokeDynamic {
                    bootstrap_method_attr_index,
                    name_and_type_index,
                }
            }
            19 => {
                let name_index = read_be_u16(bytes, cursor)
                    .with_context(|| format!("JVM Module constant[{index}] truncated"))?;
                cursor += 2;
                JvmConstantPoolEntry::Module { name_index }
            }
            20 => {
                let name_index = read_be_u16(bytes, cursor)
                    .with_context(|| format!("JVM Package constant[{index}] truncated"))?;
                cursor += 2;
                JvmConstantPoolEntry::Package { name_index }
            }
            other => {
                warnings.push(format!(
                    "unsupported JVM constant pool tag {other} at index {index}"
                ));
                anyhow::bail!("unsupported JVM constant pool tag {other} at index {index}");
            }
        };
        if cursor > bytes.len() {
            anyhow::bail!("JVM constant pool is truncated at index {index}");
        }
        pool[index] = Some(entry);
        index += 1;
    }
    Ok(JvmClassParseContext {
        constant_pool: pool,
        cursor,
        warnings,
    })
}

fn parse_jvm_members(
    bytes: &[u8],
    context: &mut JvmClassParseContext,
    kind: &str,
) -> Vec<serde_json::Value> {
    let Some(count) = read_be_u16(bytes, context.cursor) else {
        context
            .warnings
            .push(format!("JVM {kind} count is truncated"));
        return Vec::new();
    };
    context.cursor += 2;
    let mut members = Vec::new();
    for index in 0..(count as usize).min(JVM_MEMBER_LIMIT) {
        if context.cursor + 8 > bytes.len() {
            context
                .warnings
                .push(format!("JVM {kind}[{index}] header is truncated"));
            break;
        }
        let access_flags = read_be_u16(bytes, context.cursor).unwrap_or(0);
        let name_index = read_be_u16(bytes, context.cursor + 2).unwrap_or(0);
        let descriptor_index = read_be_u16(bytes, context.cursor + 4).unwrap_or(0);
        context.cursor += 6;
        let attributes = parse_jvm_attributes(bytes, context, kind);
        let name = jvm_cp_utf8(&context.constant_pool, name_index);
        let descriptor = jvm_cp_utf8(&context.constant_pool, descriptor_index);
        members.push(serde_json::json!({
            "index": index,
            "name": name,
            "descriptor": descriptor,
            "access_flags": access_flags,
            "access": jvm_access_flags(access_flags as u32),
            "attributes": attributes,
        }));
    }
    if count as usize > JVM_MEMBER_LIMIT {
        context.warnings.push(format!(
            "JVM {kind} listing truncated at {JVM_MEMBER_LIMIT} of {count}"
        ));
    }
    members
}

fn parse_jvm_attributes(
    bytes: &[u8],
    context: &mut JvmClassParseContext,
    owner: &str,
) -> Vec<serde_json::Value> {
    let Some(count) = read_be_u16(bytes, context.cursor) else {
        context
            .warnings
            .push(format!("JVM {owner} attribute count is truncated"));
        return Vec::new();
    };
    context.cursor += 2;
    let mut attributes = Vec::new();
    for index in 0..(count as usize).min(JVM_ATTRIBUTE_LIMIT) {
        if context.cursor + 6 > bytes.len() {
            context.warnings.push(format!(
                "JVM {owner} attribute[{index}] header is truncated"
            ));
            break;
        }
        let name_index = read_be_u16(bytes, context.cursor).unwrap_or(0);
        let length = read_be_u32(bytes, context.cursor + 2).unwrap_or(0);
        let data_offset = context.cursor + 6;
        let name = jvm_cp_utf8(&context.constant_pool, name_index);
        let truncated = data_offset
            .checked_add(length as usize)
            .is_none_or(|end| end > bytes.len());
        attributes.push(serde_json::json!({
            "index": index,
            "name": name,
            "length": length,
            "data_offset": data_offset,
            "truncated": truncated,
        }));
        if truncated {
            context
                .warnings
                .push(format!("JVM {owner} attribute[{index}] data is truncated"));
            context.cursor = bytes.len();
            break;
        }
        context.cursor = data_offset + length as usize;
    }
    if count as usize > JVM_ATTRIBUTE_LIMIT {
        context.warnings.push(format!(
            "JVM {owner} attributes truncated at {JVM_ATTRIBUTE_LIMIT} of {count}"
        ));
    }
    attributes
}

fn jvm_constant_pool_preview(pool: &[Option<JvmConstantPoolEntry>]) -> Vec<serde_json::Value> {
    pool.iter()
        .enumerate()
        .skip(1)
        .filter_map(|(index, entry)| {
            entry
                .as_ref()
                .map(|entry| jvm_cp_entry_json(pool, index, entry))
        })
        .take(JVM_CONSTANT_POOL_LIMIT)
        .collect()
}

fn jvm_cp_entry_json(
    pool: &[Option<JvmConstantPoolEntry>],
    index: usize,
    entry: &JvmConstantPoolEntry,
) -> serde_json::Value {
    match entry {
        JvmConstantPoolEntry::Utf8(value) => serde_json::json!({
            "index": index,
            "tag": "utf8",
            "value": preview_chars(value, 256),
        }),
        JvmConstantPoolEntry::Integer => serde_json::json!({ "index": index, "tag": "integer" }),
        JvmConstantPoolEntry::Float => serde_json::json!({ "index": index, "tag": "float" }),
        JvmConstantPoolEntry::Long => serde_json::json!({ "index": index, "tag": "long" }),
        JvmConstantPoolEntry::Double => serde_json::json!({ "index": index, "tag": "double" }),
        JvmConstantPoolEntry::Class { name_index } => serde_json::json!({
            "index": index,
            "tag": "class",
            "name_index": name_index,
            "name": jvm_cp_utf8(pool, *name_index),
        }),
        JvmConstantPoolEntry::String { string_index } => serde_json::json!({
            "index": index,
            "tag": "string",
            "string_index": string_index,
            "value": jvm_cp_utf8(pool, *string_index),
        }),
        JvmConstantPoolEntry::Fieldref {
            class_index,
            name_and_type_index,
        } => {
            let (name, descriptor) = jvm_cp_name_and_type(pool, *name_and_type_index);
            serde_json::json!({
                "index": index,
                "tag": "fieldref",
                "class": jvm_cp_class_name(pool, *class_index),
                "name": name,
                "descriptor": descriptor,
            })
        }
        JvmConstantPoolEntry::Methodref {
            class_index,
            name_and_type_index,
        } => {
            let (name, descriptor) = jvm_cp_name_and_type(pool, *name_and_type_index);
            serde_json::json!({
                "index": index,
                "tag": "methodref",
                "class": jvm_cp_class_name(pool, *class_index),
                "name": name,
                "descriptor": descriptor,
            })
        }
        JvmConstantPoolEntry::InterfaceMethodref {
            class_index,
            name_and_type_index,
        } => {
            let (name, descriptor) = jvm_cp_name_and_type(pool, *name_and_type_index);
            serde_json::json!({
                "index": index,
                "tag": "interface_methodref",
                "class": jvm_cp_class_name(pool, *class_index),
                "name": name,
                "descriptor": descriptor,
            })
        }
        JvmConstantPoolEntry::NameAndType {
            name_index,
            descriptor_index,
        } => serde_json::json!({
            "index": index,
            "tag": "name_and_type",
            "name": jvm_cp_utf8(pool, *name_index),
            "descriptor": jvm_cp_utf8(pool, *descriptor_index),
        }),
        JvmConstantPoolEntry::MethodHandle {
            reference_kind,
            reference_index,
        } => serde_json::json!({
            "index": index,
            "tag": "method_handle",
            "reference_kind": reference_kind,
            "reference_index": reference_index,
        }),
        JvmConstantPoolEntry::MethodType { descriptor_index } => serde_json::json!({
            "index": index,
            "tag": "method_type",
            "descriptor": jvm_cp_utf8(pool, *descriptor_index),
        }),
        JvmConstantPoolEntry::Dynamic {
            bootstrap_method_attr_index,
            name_and_type_index,
        } => {
            let (name, descriptor) = jvm_cp_name_and_type(pool, *name_and_type_index);
            serde_json::json!({
                "index": index,
                "tag": "dynamic",
                "bootstrap_method_attr_index": bootstrap_method_attr_index,
                "name": name,
                "descriptor": descriptor,
            })
        }
        JvmConstantPoolEntry::InvokeDynamic {
            bootstrap_method_attr_index,
            name_and_type_index,
        } => {
            let (name, descriptor) = jvm_cp_name_and_type(pool, *name_and_type_index);
            serde_json::json!({
                "index": index,
                "tag": "invoke_dynamic",
                "bootstrap_method_attr_index": bootstrap_method_attr_index,
                "name": name,
                "descriptor": descriptor,
            })
        }
        JvmConstantPoolEntry::Module { name_index } => serde_json::json!({
            "index": index,
            "tag": "module",
            "name": jvm_cp_utf8(pool, *name_index),
        }),
        JvmConstantPoolEntry::Package { name_index } => serde_json::json!({
            "index": index,
            "tag": "package",
            "name": jvm_cp_utf8(pool, *name_index),
        }),
        JvmConstantPoolEntry::Unusable => serde_json::json!({ "index": index, "tag": "unusable" }),
    }
}

fn jvm_string_constants(pool: &[Option<JvmConstantPoolEntry>]) -> Vec<serde_json::Value> {
    let mut values = Vec::new();
    for (index, entry) in pool.iter().enumerate().skip(1) {
        match entry {
            Some(JvmConstantPoolEntry::String { string_index }) => {
                if let Some(value) = jvm_cp_utf8(pool, *string_index) {
                    values.push(serde_json::json!({
                        "index": index,
                        "value": value,
                    }));
                }
            }
            Some(JvmConstantPoolEntry::Utf8(value)) => {
                if value.contains("://") || value.contains("/bin/") {
                    values.push(serde_json::json!({
                        "index": index,
                        "value": value,
                        "source": "utf8_constant",
                    }));
                }
            }
            _ => {}
        }
        if values.len() >= JVM_STRING_LIMIT {
            break;
        }
    }
    values
}

fn jvm_member_references(pool: &[Option<JvmConstantPoolEntry>]) -> Vec<serde_json::Value> {
    let mut refs = Vec::new();
    for (index, entry) in pool.iter().enumerate().skip(1) {
        let value = match entry {
            Some(JvmConstantPoolEntry::Fieldref {
                class_index,
                name_and_type_index,
            }) => {
                let (name, descriptor) = jvm_cp_name_and_type(pool, *name_and_type_index);
                Some(serde_json::json!({
                    "index": index,
                    "kind": "field",
                    "class": jvm_cp_class_name(pool, *class_index),
                    "name": name,
                    "descriptor": descriptor,
                }))
            }
            Some(JvmConstantPoolEntry::Methodref {
                class_index,
                name_and_type_index,
            }) => {
                let (name, descriptor) = jvm_cp_name_and_type(pool, *name_and_type_index);
                Some(serde_json::json!({
                    "index": index,
                    "kind": "method",
                    "class": jvm_cp_class_name(pool, *class_index),
                    "name": name,
                    "descriptor": descriptor,
                }))
            }
            Some(JvmConstantPoolEntry::InterfaceMethodref {
                class_index,
                name_and_type_index,
            }) => {
                let (name, descriptor) = jvm_cp_name_and_type(pool, *name_and_type_index);
                Some(serde_json::json!({
                    "index": index,
                    "kind": "interface_method",
                    "class": jvm_cp_class_name(pool, *class_index),
                    "name": name,
                    "descriptor": descriptor,
                }))
            }
            _ => None,
        };
        if let Some(value) = value {
            refs.push(value);
            if refs.len() >= JVM_REFERENCE_LIMIT {
                break;
            }
        }
    }
    refs
}

fn jvm_cp_utf8(pool: &[Option<JvmConstantPoolEntry>], index: u16) -> Option<String> {
    match pool.get(index as usize)? {
        Some(JvmConstantPoolEntry::Utf8(value)) => Some(value.clone()),
        _ => None,
    }
}

fn jvm_cp_class_name(pool: &[Option<JvmConstantPoolEntry>], index: u16) -> Option<String> {
    match pool.get(index as usize)? {
        Some(JvmConstantPoolEntry::Class { name_index }) => jvm_cp_utf8(pool, *name_index),
        _ => None,
    }
}

fn jvm_cp_name_and_type(
    pool: &[Option<JvmConstantPoolEntry>],
    index: u16,
) -> (Option<String>, Option<String>) {
    match pool.get(index as usize) {
        Some(Some(JvmConstantPoolEntry::NameAndType {
            name_index,
            descriptor_index,
        })) => (
            jvm_cp_utf8(pool, *name_index),
            jvm_cp_utf8(pool, *descriptor_index),
        ),
        _ => (None, None),
    }
}

fn jvm_access_flags(flags: u32) -> Vec<&'static str> {
    let mut out = Vec::new();
    for (bit, name) in [
        (0x0001, "public"),
        (0x0002, "private"),
        (0x0004, "protected"),
        (0x0008, "static"),
        (0x0010, "final"),
        (0x0020, "synchronized_or_super"),
        (0x0040, "volatile_or_bridge"),
        (0x0080, "transient_or_varargs"),
        (0x0100, "native"),
        (0x0200, "interface"),
        (0x0400, "abstract"),
        (0x0800, "strict"),
        (0x1000, "synthetic"),
        (0x2000, "annotation"),
        (0x4000, "enum"),
        (0x8000, "module"),
    ] {
        if flags & bit != 0 {
            out.push(name);
        }
    }
    out
}

fn collect_jvm_access_risk_signals(flags: u32, risk_signals: &mut BTreeSet<String>) {
    if flags & 0x0200 != 0 {
        risk_signals.insert("interface_class".to_string());
    }
    if flags & 0x8000 != 0 {
        risk_signals.insert("module_info_class".to_string());
    }
}

fn collect_jvm_reference_risk_signals(
    reference: &serde_json::Value,
    risk_signals: &mut BTreeSet<String>,
) {
    let class = reference["class"].as_str().unwrap_or_default();
    let name = reference["name"].as_str().unwrap_or_default();
    if class == "java/lang/Runtime" && name == "exec" {
        risk_signals.insert("runtime_exec_reference".to_string());
    }
    if class == "java/lang/System" && name == "loadLibrary" {
        risk_signals.insert("native_library_loading_reference".to_string());
    }
    if class.contains("URLClassLoader") || class.contains("ClassLoader") {
        risk_signals.insert("dynamic_class_loading_reference".to_string());
    }
    if class.contains("java/lang/reflect") {
        risk_signals.insert("reflection_reference".to_string());
    }
    if class.contains("HttpURLConnection")
        || class.contains("java/net/Socket")
        || class.contains("java/net/URL")
    {
        risk_signals.insert("network_api_reference".to_string());
    }
    if class.contains("javax/crypto") || class.contains("java/security") {
        risk_signals.insert("crypto_api_reference".to_string());
    }
}

fn collect_jvm_string_risk_signals(value: &str, risk_signals: &mut BTreeSet<String>) {
    let lower = value.to_ascii_lowercase();
    if lower.contains("http://") || lower.contains("https://") {
        risk_signals.insert("url_strings_present".to_string());
    }
    if lower.contains("/bin/sh") || lower.contains("cmd.exe") || lower.contains("powershell") {
        risk_signals.insert("shell_command_strings".to_string());
    }
    if lower.ends_with(".dll") || lower.ends_with(".so") || lower.ends_with(".dylib") {
        risk_signals.insert("native_library_name_strings".to_string());
    }
}

fn is_python_bytecode_like_bytes(bytes: &[u8]) -> bool {
    bytes.len() >= 16 && bytes.get(2..4) == Some(b"\r\n")
}

fn analyze_object_python_bytecode(object: &UniversalObject, bytes: &[u8]) -> ObjectAnalysisSummary {
    match extract_python_bytecode_summary(object, bytes) {
        Ok(summary) => ObjectAnalysisSummary {
            analyzer: "python_bytecode".to_string(),
            status: if summary.truncated || !summary.warnings.is_empty() {
                ObjectAnalysisStatus::Partial
            } else {
                ObjectAnalysisStatus::Completed
            },
            summary: format!(
                "Python bytecode {} with {} name(s), {} constant(s), {} nested code object(s), {} risk signal(s)",
                summary.module_name,
                summary.name_count,
                summary.constant_count,
                summary.nested_code_count,
                summary.risk_signal_count
            ),
            details: summary.details,
            evidence_ids: vec![format!("analysis:{}:python_bytecode", object.id)],
        },
        Err(err) => ObjectAnalysisSummary {
            analyzer: "python_bytecode".to_string(),
            status: ObjectAnalysisStatus::Failed,
            summary: format!("Python bytecode analysis failed: {err}"),
            details: serde_json::json!({ "error": err.to_string() }),
            evidence_ids: vec![format!("analysis:{}:python_bytecode", object.id)],
        },
    }
}

#[derive(Debug)]
struct PythonBytecodeAnalysisSummary {
    module_name: String,
    name_count: usize,
    constant_count: usize,
    nested_code_count: usize,
    risk_signal_count: usize,
    truncated: bool,
    warnings: Vec<String>,
    details: serde_json::Value,
}

#[derive(Debug)]
struct PythonMarshalReader<'a> {
    bytes: &'a [u8],
    cursor: usize,
    warnings: Vec<String>,
    code_objects: Vec<serde_json::Value>,
    strings: BTreeSet<String>,
    names: BTreeSet<String>,
    risk_signals: BTreeSet<String>,
    max_depth: usize,
    version: PythonCodeObjectVersion,
}

#[derive(Debug, Clone, Copy)]
enum PythonCodeObjectVersion {
    Py39Or310,
    Py311Plus,
}

const PYTHON_MARSHAL_REF_FLAG: u8 = 0x80;
const PYTHON_MARSHAL_COLLECTION_LIMIT: usize = 4096;
const PYTHON_MARSHAL_STRING_LIMIT: usize = 4096;
const PYTHON_CODE_OBJECT_LIMIT: usize = 256;

fn extract_python_bytecode_summary(
    object: &UniversalObject,
    bytes: &[u8],
) -> Result<PythonBytecodeAnalysisSummary> {
    if !is_python_bytecode_like_bytes(bytes) {
        anyhow::bail!("object is not CPython bytecode");
    }
    if bytes.len() < 16 {
        anyhow::bail!("Python bytecode header is truncated");
    }
    let magic = read_le_u32(bytes, 0).context("missing Python bytecode magic")?;
    let flags = read_le_u32(bytes, 4).unwrap_or(0);
    let hash_based = flags & 0x1 != 0;
    let checked_hash = flags & 0x2 != 0;
    let (timestamp, source_size, hash) = if hash_based {
        (
            None,
            None,
            Some(
                bytes
                    .get(8..16)
                    .unwrap_or_default()
                    .iter()
                    .map(|byte| format!("{byte:02x}"))
                    .collect::<Vec<_>>()
                    .join(""),
            ),
        )
    } else {
        (
            read_le_u32(bytes, 8),
            read_le_u32(bytes, 12),
            None::<String>,
        )
    };
    let mut reader = PythonMarshalReader {
        bytes,
        cursor: 16,
        warnings: Vec::new(),
        code_objects: Vec::new(),
        strings: BTreeSet::new(),
        names: BTreeSet::new(),
        risk_signals: BTreeSet::new(),
        max_depth: 24,
        version: python_code_object_version(magic),
    };
    reader
        .risk_signals
        .insert("python_bytecode_present".to_string());
    reader.parse_value(0, "module")?;
    let module_name = reader
        .code_objects
        .first()
        .and_then(|value| value["name"].as_str())
        .unwrap_or("<module>")
        .to_string();
    if reader.cursor < bytes.len() {
        reader.warnings.push(format!(
            "Python marshal payload has {} trailing byte(s)",
            bytes.len() - reader.cursor
        ));
    }
    let string_values = reader
        .strings
        .iter()
        .take(PYTHON_MARSHAL_STRING_LIMIT)
        .map(|value| serde_json::json!({ "value": value }))
        .collect::<Vec<_>>();
    let name_values = reader
        .names
        .iter()
        .take(PYTHON_MARSHAL_STRING_LIMIT)
        .map(|value| serde_json::json!({ "value": value }))
        .collect::<Vec<_>>();
    let risk_signal_values = reader
        .risk_signals
        .into_iter()
        .take(256)
        .collect::<Vec<_>>();
    let truncated = !reader.warnings.is_empty()
        || reader.code_objects.len() >= PYTHON_CODE_OBJECT_LIMIT
        || reader.strings.len() > PYTHON_MARSHAL_STRING_LIMIT
        || reader.names.len() > PYTHON_MARSHAL_STRING_LIMIT;
    let details = serde_json::json!({
        "format": object.format.as_deref().unwrap_or("python_bytecode"),
        "header": {
            "magic": format!("0x{magic:08x}"),
            "magic_bytes": bytes.iter().take(4).map(|byte| format!("{byte:02x}")).collect::<Vec<_>>().join(""),
            "flags": flags,
            "hash_based": hash_based,
            "checked_hash": checked_hash,
            "timestamp": timestamp,
            "source_size": source_size,
            "hash": hash,
        },
        "code_objects": reader.code_objects,
        "string_count": string_values.len(),
        "strings": string_values,
        "name_count": name_values.len(),
        "names": name_values,
        "risk_signals": risk_signal_values,
        "warnings": reader.warnings,
        "truncated": truncated,
    });
    Ok(PythonBytecodeAnalysisSummary {
        module_name,
        name_count: details["name_count"].as_u64().unwrap_or(0) as usize,
        constant_count: details["code_objects"][0]["const_count"]
            .as_u64()
            .unwrap_or(0) as usize,
        nested_code_count: details["code_objects"]
            .as_array()
            .map_or(0, |items| items.len().saturating_sub(1)),
        risk_signal_count: details["risk_signals"].as_array().map_or(0, Vec::len),
        truncated,
        warnings: details["warnings"]
            .as_array()
            .map(|items| {
                items
                    .iter()
                    .filter_map(|item| item.as_str().map(ToOwned::to_owned))
                    .collect()
            })
            .unwrap_or_default(),
        details,
    })
}

impl<'a> PythonMarshalReader<'a> {
    fn parse_value(&mut self, depth: usize, role: &str) -> Result<Option<serde_json::Value>> {
        if depth > self.max_depth {
            self.warnings.push(format!(
                "Python marshal nesting limit reached while reading {role}"
            ));
            return Ok(None);
        }
        let Some(raw_tag) = self.read_u8() else {
            anyhow::bail!("Python marshal value {role} is truncated");
        };
        let tag = raw_tag & !PYTHON_MARSHAL_REF_FLAG;
        match tag as char {
            '0' => Ok(Some(serde_json::json!({ "type": "null" }))),
            'N' => Ok(Some(serde_json::json!({ "type": "none" }))),
            'F' => Ok(Some(serde_json::json!({ "type": "false", "value": false }))),
            'T' => Ok(Some(serde_json::json!({ "type": "true", "value": true }))),
            'S' => Ok(Some(serde_json::json!({ "type": "stop_iteration" }))),
            '.' => Ok(Some(serde_json::json!({ "type": "ellipsis" }))),
            'i' => {
                let value = self.read_i32(role)?;
                Ok(Some(serde_json::json!({ "type": "int", "value": value })))
            }
            'I' => {
                let value = self.read_i64(role)?;
                Ok(Some(serde_json::json!({ "type": "int64", "value": value })))
            }
            'l' => {
                let digits = self.read_i32(role)?.unsigned_abs() as usize;
                self.skip(digits.saturating_mul(2), role)?;
                Ok(Some(
                    serde_json::json!({ "type": "long", "digit_count": digits }),
                ))
            }
            'g' => {
                self.skip(8, role)?;
                Ok(Some(serde_json::json!({ "type": "float" })))
            }
            'y' => {
                self.skip(16, role)?;
                Ok(Some(serde_json::json!({ "type": "complex" })))
            }
            'f' | 'x' => {
                let len = self.read_u8().unwrap_or(0) as usize;
                self.skip(len, role)?;
                Ok(Some(
                    serde_json::json!({ "type": if tag as char == 'f' { "float_text" } else { "complex_text" } }),
                ))
            }
            's' | 't' | 'a' | 'A' | 'z' | 'Z' | 'u' => {
                let value = self.read_marshal_string(tag, role)?;
                self.collect_string(&value);
                Ok(Some(serde_json::json!({
                    "type": python_marshal_string_type(tag),
                    "value": preview_chars(&value, 512),
                })))
            }
            ')' => {
                let count = self.read_u8().unwrap_or(0) as usize;
                let values = self.parse_sequence(depth, role, count)?;
                Ok(Some(
                    serde_json::json!({ "type": "small_tuple", "items": values }),
                ))
            }
            '(' | '[' | '<' | '>' => {
                let count = self.read_i32(role)?.max(0) as usize;
                let values = self.parse_sequence(depth, role, count)?;
                Ok(Some(serde_json::json!({
                    "type": python_marshal_collection_type(tag),
                    "items": values,
                    "declared_count": count,
                })))
            }
            '{' => {
                let mut items = Vec::new();
                for index in 0..PYTHON_MARSHAL_COLLECTION_LIMIT {
                    let key = self.parse_value(depth + 1, "dict_key")?;
                    if key
                        .as_ref()
                        .is_some_and(|value| value["type"] == serde_json::json!("null"))
                    {
                        break;
                    }
                    let value = self.parse_value(depth + 1, "dict_value")?;
                    items.push(serde_json::json!({
                        "index": index,
                        "key": key,
                        "value": value,
                    }));
                }
                Ok(Some(serde_json::json!({ "type": "dict", "items": items })))
            }
            'r' => {
                let index = self.read_i32(role)?;
                Ok(Some(serde_json::json!({ "type": "ref", "index": index })))
            }
            'c' => self.parse_code_object(depth, role),
            other => {
                self.warnings.push(format!(
                    "unsupported Python marshal tag 0x{tag:02x} ({other:?}) while reading {role}"
                ));
                Ok(Some(serde_json::json!({
                    "type": "unsupported",
                    "tag": format!("0x{tag:02x}"),
                })))
            }
        }
    }

    fn parse_code_object(
        &mut self,
        depth: usize,
        _role: &str,
    ) -> Result<Option<serde_json::Value>> {
        let argcount = self.read_i32("co_argcount")?;
        let posonlyargcount = self.read_i32("co_posonlyargcount")?;
        let kwonlyargcount = self.read_i32("co_kwonlyargcount")?;
        let nlocals = self.read_i32("co_nlocals")?;
        let stacksize = self.read_i32("co_stacksize")?;
        let flags = self.read_i32("co_flags")?;
        let code = self.parse_value(depth + 1, "co_code")?;
        let consts = self.parse_value(depth + 1, "co_consts")?;
        let names = self.parse_value(depth + 1, "co_names")?;
        let varnames = self.parse_value(depth + 1, "co_varnames")?;
        let freevars = self.parse_value(depth + 1, "co_freevars")?;
        let cellvars = self.parse_value(depth + 1, "co_cellvars")?;
        let filename = self
            .parse_value(depth + 1, "co_filename")?
            .and_then(|value| value["value"].as_str().map(ToOwned::to_owned))
            .unwrap_or_default();
        let name = self
            .parse_value(depth + 1, "co_name")?
            .and_then(|value| value["value"].as_str().map(ToOwned::to_owned))
            .unwrap_or_default();
        let qualname = if matches!(self.version, PythonCodeObjectVersion::Py311Plus) {
            self.parse_value(depth + 1, "co_qualname")?
                .and_then(|value| value["value"].as_str().map(ToOwned::to_owned))
        } else {
            None
        };
        let firstlineno = self.read_i32("co_firstlineno")?;
        let linetable = self.parse_value(depth + 1, "co_linetable")?;
        let exceptiontable = if matches!(self.version, PythonCodeObjectVersion::Py311Plus) {
            self.parse_value(depth + 1, "co_exceptiontable")?
        } else {
            None
        };
        let name_values = python_marshal_items_as_strings(names.as_ref());
        for value in &name_values {
            self.names.insert(value.clone());
            collect_python_name_risk_signals(value, &mut self.risk_signals);
        }
        let const_values = python_marshal_items_as_constants(consts.as_ref());
        for value in &const_values {
            if let Some(text) = value["value"].as_str() {
                self.collect_string(text);
            }
        }
        let code_len = code
            .as_ref()
            .and_then(|value| value["value"].as_str())
            .map(|value| value.len())
            .unwrap_or(0);
        let code_object = serde_json::json!({
            "index": self.code_objects.len(),
            "name": name,
            "qualname": qualname,
            "filename": filename,
            "firstlineno": firstlineno,
            "argcount": argcount,
            "posonlyargcount": posonlyargcount,
            "kwonlyargcount": kwonlyargcount,
            "nlocals": nlocals,
            "stacksize": stacksize,
            "flags": flags,
            "flag_names": python_code_flags(flags as u32),
            "code_length": code_len,
            "const_count": python_marshal_item_count(consts.as_ref()),
            "constants": const_values,
            "names": name_values,
            "varnames": python_marshal_items_as_strings(varnames.as_ref()),
            "freevars": python_marshal_items_as_strings(freevars.as_ref()),
            "cellvars": python_marshal_items_as_strings(cellvars.as_ref()),
            "linetable_type": linetable.as_ref().and_then(|value| value["type"].as_str()),
            "exceptiontable_type": exceptiontable.as_ref().and_then(|value| value["type"].as_str()),
        });
        if self.code_objects.len() < PYTHON_CODE_OBJECT_LIMIT {
            self.code_objects.push(code_object.clone());
        } else {
            self.warnings.push(format!(
                "Python code object listing truncated at {PYTHON_CODE_OBJECT_LIMIT}"
            ));
        }
        Ok(Some(serde_json::json!({
            "type": "code",
            "name": code_object["name"],
            "filename": code_object["filename"],
            "firstlineno": firstlineno,
        })))
    }

    fn parse_sequence(
        &mut self,
        depth: usize,
        role: &str,
        count: usize,
    ) -> Result<Vec<serde_json::Value>> {
        let mut values = Vec::new();
        for index in 0..count.min(PYTHON_MARSHAL_COLLECTION_LIMIT) {
            if let Some(value) = self.parse_value(depth + 1, role)? {
                values.push(serde_json::json!({
                    "index": index,
                    "value": value,
                }));
            }
        }
        if count > PYTHON_MARSHAL_COLLECTION_LIMIT {
            self.warnings.push(format!(
                "Python marshal {role} collection truncated at {PYTHON_MARSHAL_COLLECTION_LIMIT} of {count}"
            ));
        }
        Ok(values)
    }

    fn read_marshal_string(&mut self, tag: u8, role: &str) -> Result<String> {
        let len = match tag as char {
            'z' | 'Z' => self.read_u8().unwrap_or(0) as usize,
            _ => self.read_i32(role)?.max(0) as usize,
        };
        if len > PYTHON_MARSHAL_STRING_LIMIT {
            self.warnings.push(format!(
                "Python marshal string {role} truncated for preview at {PYTHON_MARSHAL_STRING_LIMIT} of {len} bytes"
            ));
        }
        let read_len = len.min(PYTHON_MARSHAL_STRING_LIMIT);
        let data = self
            .bytes
            .get(self.cursor..self.cursor + read_len)
            .with_context(|| format!("Python marshal string {role} is truncated"))?;
        self.skip(len, role)?;
        Ok(String::from_utf8_lossy(data).to_string())
    }

    fn collect_string(&mut self, value: &str) {
        if !value.is_empty() {
            self.strings.insert(value.to_string());
            collect_python_string_risk_signals(value, &mut self.risk_signals);
        }
    }

    fn read_u8(&mut self) -> Option<u8> {
        let value = *self.bytes.get(self.cursor)?;
        self.cursor += 1;
        Some(value)
    }

    fn read_i32(&mut self, role: &str) -> Result<i32> {
        let value = read_le_i32(self.bytes, self.cursor)
            .with_context(|| format!("Python marshal i32 {role} is truncated"))?;
        self.cursor += 4;
        Ok(value)
    }

    fn read_i64(&mut self, role: &str) -> Result<i64> {
        let slice = self
            .bytes
            .get(self.cursor..self.cursor + 8)
            .with_context(|| format!("Python marshal i64 {role} is truncated"))?;
        self.cursor += 8;
        Ok(i64::from_le_bytes([
            slice[0], slice[1], slice[2], slice[3], slice[4], slice[5], slice[6], slice[7],
        ]))
    }

    fn skip(&mut self, len: usize, role: &str) -> Result<()> {
        let end = self
            .cursor
            .checked_add(len)
            .with_context(|| format!("Python marshal {role} length overflows"))?;
        if end > self.bytes.len() {
            anyhow::bail!("Python marshal {role} is truncated");
        }
        self.cursor = end;
        Ok(())
    }
}

fn python_code_object_version(magic: u32) -> PythonCodeObjectVersion {
    let magic_low = magic & 0xffff;
    if magic_low >= 0x0da7 {
        PythonCodeObjectVersion::Py311Plus
    } else {
        PythonCodeObjectVersion::Py39Or310
    }
}

fn python_marshal_string_type(tag: u8) -> &'static str {
    match tag as char {
        's' => "bytes",
        't' => "interned",
        'a' => "ascii",
        'A' => "ascii_interned",
        'z' => "short_ascii",
        'Z' => "short_ascii_interned",
        'u' => "unicode",
        _ => "string",
    }
}

fn python_marshal_collection_type(tag: u8) -> &'static str {
    match tag as char {
        '(' => "tuple",
        '[' => "list",
        '<' => "set",
        '>' => "frozenset",
        _ => "collection",
    }
}

fn python_marshal_item_count(value: Option<&serde_json::Value>) -> usize {
    value
        .and_then(|value| value["items"].as_array())
        .map_or(0, Vec::len)
}

fn python_marshal_items_as_strings(value: Option<&serde_json::Value>) -> Vec<String> {
    value
        .and_then(|value| value["items"].as_array())
        .into_iter()
        .flatten()
        .filter_map(|item| item["value"]["value"].as_str().map(ToOwned::to_owned))
        .take(512)
        .collect()
}

fn python_marshal_items_as_constants(value: Option<&serde_json::Value>) -> Vec<serde_json::Value> {
    value
        .and_then(|value| value["items"].as_array())
        .into_iter()
        .flatten()
        .take(512)
        .map(|item| {
            let value = &item["value"];
            serde_json::json!({
                "index": item["index"],
                "type": value["type"],
                "value": value.get("value").cloned(),
                "name": value.get("name").cloned(),
                "filename": value.get("filename").cloned(),
            })
        })
        .collect()
}

fn python_code_flags(flags: u32) -> Vec<&'static str> {
    let mut out = Vec::new();
    for (bit, name) in [
        (0x0001, "optimized"),
        (0x0002, "newlocals"),
        (0x0004, "varargs"),
        (0x0008, "varkeywords"),
        (0x0010, "nested"),
        (0x0020, "generator"),
        (0x0040, "no_free"),
        (0x0080, "coroutine"),
        (0x0200, "async_generator"),
    ] {
        if flags & bit != 0 {
            out.push(name);
        }
    }
    out
}

fn collect_python_name_risk_signals(name: &str, risk_signals: &mut BTreeSet<String>) {
    for (needle, signal) in [
        ("eval", "dynamic_eval_reference"),
        ("exec", "dynamic_exec_reference"),
        ("compile", "dynamic_compile_reference"),
        ("__import__", "dynamic_import_reference"),
        ("importlib", "importlib_reference"),
        ("subprocess", "subprocess_reference"),
        ("popen", "process_spawn_reference"),
        ("system", "process_spawn_reference"),
        ("socket", "network_api_reference"),
        ("requests", "network_api_reference"),
        ("urllib", "network_api_reference"),
        ("ctypes", "native_ffi_reference"),
        ("marshal", "marshal_reference"),
        ("base64", "encoding_or_obfuscation_reference"),
    ] {
        if name.eq_ignore_ascii_case(needle) || name.to_ascii_lowercase().contains(needle) {
            risk_signals.insert(signal.to_string());
        }
    }
}

fn collect_python_string_risk_signals(value: &str, risk_signals: &mut BTreeSet<String>) {
    let lower = value.to_ascii_lowercase();
    if lower.contains("http://") || lower.contains("https://") {
        risk_signals.insert("url_strings_present".to_string());
    }
    if lower.contains("/bin/sh") || lower.contains("cmd.exe") || lower.contains("powershell") {
        risk_signals.insert("shell_command_strings".to_string());
    }
    if lower.contains("base64") || lower.contains("fromhex") {
        risk_signals.insert("encoding_or_obfuscation_strings".to_string());
    }
}

fn analyze_object_shell_link(object: &UniversalObject, bytes: &[u8]) -> ObjectAnalysisSummary {
    match extract_shell_link_summary(object, bytes) {
        Ok(summary) => ObjectAnalysisSummary {
            analyzer: "shell_link".to_string(),
            status: if summary.truncated || !summary.warnings.is_empty() {
                ObjectAnalysisStatus::Partial
            } else {
                ObjectAnalysisStatus::Completed
            },
            summary: format!(
                "Windows Shell Link targeting {} with {} risk signal(s)",
                summary.target_hint, summary.risk_signal_count
            ),
            details: summary.details,
            evidence_ids: vec![format!("analysis:{}:shell_link", object.id)],
        },
        Err(err) => ObjectAnalysisSummary {
            analyzer: "shell_link".to_string(),
            status: ObjectAnalysisStatus::Failed,
            summary: format!("Windows Shell Link analysis failed: {err}"),
            details: serde_json::json!({ "error": err.to_string() }),
            evidence_ids: vec![format!("analysis:{}:shell_link", object.id)],
        },
    }
}

#[derive(Debug)]
struct ShellLinkAnalysisSummary {
    target_hint: String,
    risk_signal_count: usize,
    truncated: bool,
    warnings: Vec<String>,
    details: serde_json::Value,
}

#[derive(Debug)]
struct ShellLinkHeader {
    header_size: u32,
    link_clsid: String,
    link_flags: u32,
    file_attributes: u32,
    creation_time: u64,
    access_time: u64,
    write_time: u64,
    file_size: u32,
    icon_index: i32,
    show_command: u32,
    hot_key: u16,
}

#[derive(Debug)]
struct ShellLinkLinkInfo {
    size: u32,
    header_size: u32,
    flags: u32,
    volume_id_offset: u32,
    local_base_path_offset: u32,
    common_network_relative_link_offset: u32,
    common_path_suffix_offset: u32,
    local_base_path: Option<String>,
    common_path_suffix: Option<String>,
    local_base_path_unicode: Option<String>,
    common_path_suffix_unicode: Option<String>,
    common_network: Option<serde_json::Value>,
}

#[derive(Debug)]
struct ShellLinkParsed {
    header: ShellLinkHeader,
    link_target_id_list: Option<serde_json::Value>,
    link_info: Option<ShellLinkLinkInfo>,
    strings: BTreeMap<&'static str, String>,
    extra_data: Vec<serde_json::Value>,
    warnings: Vec<String>,
    truncated: bool,
}

const SHELL_LINK_HEADER_SIZE: usize = 0x4c;
const SHELL_LINK_CLSID: [u8; 16] = [
    0x01, 0x14, 0x02, 0x00, 0x00, 0x00, 0x00, 0x00, 0xc0, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x46,
];
const SHELL_LINK_STRING_LIMIT: usize = 4096;
const SHELL_LINK_EXTRA_DATA_LIMIT: usize = 64;

fn extract_shell_link_summary(
    object: &UniversalObject,
    bytes: &[u8],
) -> Result<ShellLinkAnalysisSummary> {
    let parsed = parse_shell_link(bytes)?;
    let mut risk_signals = BTreeSet::<String>::new();
    risk_signals.insert("shell_link_present".to_string());
    if parsed.link_info.as_ref().is_some_and(|link_info| {
        link_info.common_network.is_some()
            || link_info
                .common_path_suffix
                .as_deref()
                .is_some_and(is_unc_or_url)
            || link_info
                .common_path_suffix_unicode
                .as_deref()
                .is_some_and(is_unc_or_url)
    }) {
        risk_signals.insert("network_target_reference".to_string());
    }
    for value in parsed.strings.values() {
        collect_shell_link_risk_signals(value, &mut risk_signals);
    }
    if let Some(link_info) = &parsed.link_info {
        for value in [
            link_info.local_base_path.as_deref(),
            link_info.common_path_suffix.as_deref(),
            link_info.local_base_path_unicode.as_deref(),
            link_info.common_path_suffix_unicode.as_deref(),
        ]
        .into_iter()
        .flatten()
        {
            collect_shell_link_risk_signals(value, &mut risk_signals);
        }
        if let Some(common_network) = &link_info.common_network {
            for key in [
                "net_name",
                "device_name",
                "net_name_unicode",
                "device_name_unicode",
            ] {
                if let Some(value) = common_network[key].as_str() {
                    collect_shell_link_risk_signals(value, &mut risk_signals);
                }
            }
        }
    }
    for block in &parsed.extra_data {
        if block["kind"] == "environment_variables_location" {
            risk_signals.insert("environment_variable_target".to_string());
        }
        if block["kind"] == "tracker" {
            risk_signals.insert("distributed_link_tracking_data".to_string());
        }
        for key in ["target_ansi", "target_unicode", "machine_id"] {
            if let Some(value) = block[key].as_str() {
                collect_shell_link_risk_signals(value, &mut risk_signals);
            }
        }
    }

    let string_values = parsed
        .strings
        .iter()
        .map(|(name, value)| serde_json::json!({ "name": name, "value": value }))
        .collect::<Vec<_>>();
    let target_hint = shell_link_target_hint(&parsed);
    let risk_signal_values = risk_signals.into_iter().take(256).collect::<Vec<_>>();
    let details = serde_json::json!({
        "format": object.format.as_deref().unwrap_or("lnk"),
        "header": shell_link_header_json(&parsed.header),
        "link_target_id_list": parsed.link_target_id_list,
        "link_info": parsed.link_info.as_ref().map(shell_link_info_json),
        "string_data": {
            "relative_path": parsed.strings.get("relative_path"),
            "working_dir": parsed.strings.get("working_dir"),
            "command_line_arguments": parsed.strings.get("command_line_arguments"),
            "icon_location": parsed.strings.get("icon_location"),
            "name": parsed.strings.get("name"),
            "entries": string_values,
        },
        "extra_data": parsed.extra_data,
        "target_hint": target_hint,
        "risk_signals": risk_signal_values,
        "warnings": parsed.warnings,
        "truncated": parsed.truncated,
    });
    Ok(ShellLinkAnalysisSummary {
        target_hint,
        risk_signal_count: details["risk_signals"].as_array().map_or(0, Vec::len),
        truncated: details["truncated"].as_bool().unwrap_or(false),
        warnings: details["warnings"]
            .as_array()
            .map(|items| {
                items
                    .iter()
                    .filter_map(|item| item.as_str().map(ToOwned::to_owned))
                    .collect()
            })
            .unwrap_or_default(),
        details,
    })
}

fn parse_shell_link(bytes: &[u8]) -> Result<ShellLinkParsed> {
    if !is_shell_link_like_bytes(bytes) {
        anyhow::bail!("object is not a Windows Shell Link");
    }
    let header = ShellLinkHeader {
        header_size: read_le_u32(bytes, 0).context("missing Shell Link header size")?,
        link_clsid: shell_link_clsid_string(bytes.get(4..20).unwrap_or_default()),
        link_flags: read_le_u32(bytes, 20).context("missing Shell Link flags")?,
        file_attributes: read_le_u32(bytes, 24).context("missing Shell Link file attributes")?,
        creation_time: read_le_u64(bytes, 28).unwrap_or(0),
        access_time: read_le_u64(bytes, 36).unwrap_or(0),
        write_time: read_le_u64(bytes, 44).unwrap_or(0),
        file_size: read_le_u32(bytes, 52).unwrap_or(0),
        icon_index: read_le_i32(bytes, 56).unwrap_or(0),
        show_command: read_le_u32(bytes, 60).unwrap_or(0),
        hot_key: read_le_u16(bytes, 64).unwrap_or(0),
    };
    let mut cursor = SHELL_LINK_HEADER_SIZE;
    let mut warnings = Vec::new();
    let mut truncated = false;
    let mut link_target_id_list = None;
    if header.link_flags & 0x0000_0001 != 0 {
        if cursor + 2 > bytes.len() {
            anyhow::bail!("Shell Link target ID list size is truncated");
        }
        let size = read_le_u16(bytes, cursor).unwrap_or(0) as usize;
        let data_offset = cursor + 2;
        let end = data_offset.saturating_add(size);
        if end > bytes.len() {
            warnings.push("Shell Link target ID list extends beyond object bounds".to_string());
            truncated = true;
            cursor = bytes.len();
        } else {
            link_target_id_list = Some(parse_shell_link_id_list(bytes, data_offset, size));
            cursor = end;
        }
    }
    let mut link_info = None;
    if header.link_flags & 0x0000_0002 != 0 {
        match parse_shell_link_info(bytes, cursor, &mut warnings) {
            Ok((info, next_cursor)) => {
                link_info = Some(info);
                cursor = next_cursor;
            }
            Err(err) => {
                warnings.push(format!("Shell Link LinkInfo parse failed: {err}"));
                truncated = true;
                cursor = bytes.len();
            }
        }
    }
    let unicode = header.link_flags & 0x0000_0080 != 0;
    let mut strings = BTreeMap::new();
    for (bit, name) in [
        (0x0000_0004, "name"),
        (0x0000_0008, "relative_path"),
        (0x0000_0010, "working_dir"),
        (0x0000_0020, "command_line_arguments"),
        (0x0000_0040, "icon_location"),
    ] {
        if header.link_flags & bit == 0 {
            continue;
        }
        match read_shell_link_counted_string(bytes, cursor, unicode) {
            Ok((value, next_cursor)) => {
                strings.insert(name, value);
                cursor = next_cursor;
            }
            Err(err) => {
                warnings.push(format!("Shell Link {name} string parse failed: {err}"));
                truncated = true;
                cursor = bytes.len();
                break;
            }
        }
    }
    let extra_data = parse_shell_link_extra_data(bytes, cursor, &mut warnings, &mut truncated);
    Ok(ShellLinkParsed {
        header,
        link_target_id_list,
        link_info,
        strings,
        extra_data,
        warnings,
        truncated,
    })
}

fn parse_shell_link_id_list(bytes: &[u8], offset: usize, size: usize) -> serde_json::Value {
    let mut cursor = offset;
    let end = offset.saturating_add(size).min(bytes.len());
    let mut items = Vec::new();
    let mut truncated = false;
    while cursor + 2 <= end && items.len() < 128 {
        let item_size = read_le_u16(bytes, cursor).unwrap_or(0) as usize;
        if item_size == 0 {
            cursor += 2;
            break;
        }
        if item_size < 2 || cursor + item_size > end {
            truncated = true;
            break;
        }
        let data = &bytes[cursor + 2..cursor + item_size];
        items.push(serde_json::json!({
            "index": items.len(),
            "offset": cursor,
            "size": item_size,
            "preview_hex": hex::encode(&data[..data.len().min(32)]),
            "preview_text": text_preview(data),
        }));
        cursor += item_size;
    }
    serde_json::json!({
        "offset": offset,
        "declared_size": size,
        "item_count": items.len(),
        "items": items,
        "terminated": cursor <= end && bytes.get(cursor.saturating_sub(2)..cursor) == Some(&[0, 0]),
        "truncated": truncated,
    })
}

fn parse_shell_link_info(
    bytes: &[u8],
    offset: usize,
    warnings: &mut Vec<String>,
) -> Result<(ShellLinkLinkInfo, usize)> {
    if offset + 28 > bytes.len() {
        anyhow::bail!("LinkInfo header is truncated");
    }
    let size = read_le_u32(bytes, offset).context("missing LinkInfo size")?;
    if size < 28 {
        anyhow::bail!("LinkInfo size {size} is too small");
    }
    let end = offset
        .checked_add(size as usize)
        .context("LinkInfo size overflow")?;
    if end > bytes.len() {
        anyhow::bail!("LinkInfo extends beyond object bounds");
    }
    let header_size = read_le_u32(bytes, offset + 4).unwrap_or(0);
    let flags = read_le_u32(bytes, offset + 8).unwrap_or(0);
    let volume_id_offset = read_le_u32(bytes, offset + 12).unwrap_or(0);
    let local_base_path_offset = read_le_u32(bytes, offset + 16).unwrap_or(0);
    let common_network_relative_link_offset = read_le_u32(bytes, offset + 20).unwrap_or(0);
    let common_path_suffix_offset = read_le_u32(bytes, offset + 24).unwrap_or(0);
    let local_base_path_unicode_offset = (header_size >= 36)
        .then(|| read_le_u32(bytes, offset + 28))
        .flatten()
        .unwrap_or(0);
    let common_path_suffix_unicode_offset = (header_size >= 36)
        .then(|| read_le_u32(bytes, offset + 32))
        .flatten()
        .unwrap_or(0);
    let local_base_path = shell_link_ascii_at(bytes, offset, end, local_base_path_offset, 4096);
    let common_path_suffix =
        shell_link_ascii_at(bytes, offset, end, common_path_suffix_offset, 4096);
    let local_base_path_unicode =
        shell_link_utf16_at(bytes, offset, end, local_base_path_unicode_offset, 4096);
    let common_path_suffix_unicode =
        shell_link_utf16_at(bytes, offset, end, common_path_suffix_unicode_offset, 4096);
    let common_network = if common_network_relative_link_offset != 0 {
        match parse_shell_link_common_network(
            bytes,
            offset + common_network_relative_link_offset as usize,
            end,
        ) {
            Ok(value) => Some(value),
            Err(err) => {
                warnings.push(format!(
                    "Shell Link CommonNetworkRelativeLink parse failed: {err}"
                ));
                None
            }
        }
    } else {
        None
    };
    Ok((
        ShellLinkLinkInfo {
            size,
            header_size,
            flags,
            volume_id_offset,
            local_base_path_offset,
            common_network_relative_link_offset,
            common_path_suffix_offset,
            local_base_path,
            common_path_suffix,
            local_base_path_unicode,
            common_path_suffix_unicode,
            common_network,
        },
        end,
    ))
}

fn parse_shell_link_common_network(
    bytes: &[u8],
    offset: usize,
    link_info_end: usize,
) -> Result<serde_json::Value> {
    if offset + 20 > link_info_end || offset + 20 > bytes.len() {
        anyhow::bail!("CommonNetworkRelativeLink header is truncated");
    }
    let size = read_le_u32(bytes, offset).context("missing CommonNetworkRelativeLink size")?;
    let end = offset
        .checked_add(size as usize)
        .context("CommonNetworkRelativeLink size overflow")?;
    if end > link_info_end || end > bytes.len() {
        anyhow::bail!("CommonNetworkRelativeLink extends beyond LinkInfo");
    }
    let flags = read_le_u32(bytes, offset + 4).unwrap_or(0);
    let net_name_offset = read_le_u32(bytes, offset + 8).unwrap_or(0);
    let device_name_offset = read_le_u32(bytes, offset + 12).unwrap_or(0);
    let network_provider_type = read_le_u32(bytes, offset + 16).unwrap_or(0);
    let net_name_unicode_offset = (net_name_offset > 0x14)
        .then(|| read_le_u32(bytes, offset + 20))
        .flatten()
        .unwrap_or(0);
    let device_name_unicode_offset = (device_name_offset > 0x14)
        .then(|| read_le_u32(bytes, offset + 24))
        .flatten()
        .unwrap_or(0);
    Ok(serde_json::json!({
        "size": size,
        "flags": flags,
        "flag_names": shell_link_common_network_flags(flags),
        "net_name": shell_link_ascii_at(bytes, offset, end, net_name_offset, 4096),
        "device_name": shell_link_ascii_at(bytes, offset, end, device_name_offset, 4096),
        "network_provider_type": network_provider_type,
        "net_name_unicode": shell_link_utf16_at(bytes, offset, end, net_name_unicode_offset, 4096),
        "device_name_unicode": shell_link_utf16_at(bytes, offset, end, device_name_unicode_offset, 4096),
    }))
}

fn read_shell_link_counted_string(
    bytes: &[u8],
    offset: usize,
    unicode: bool,
) -> Result<(String, usize)> {
    let char_count = read_le_u16(bytes, offset).context("missing counted string length")? as usize;
    let data_offset = offset + 2;
    if char_count > SHELL_LINK_STRING_LIMIT {
        anyhow::bail!("counted string length {char_count} exceeds limit");
    }
    if unicode {
        let byte_len = char_count
            .checked_mul(2)
            .context("counted UTF-16 string length overflow")?;
        let end = data_offset
            .checked_add(byte_len)
            .context("counted UTF-16 string end overflow")?;
        if end > bytes.len() {
            anyhow::bail!("counted UTF-16 string is truncated");
        }
        let value = decode_utf16le_lossy(&bytes[data_offset..end]);
        Ok((value, end))
    } else {
        let end = data_offset
            .checked_add(char_count)
            .context("counted ANSI string end overflow")?;
        if end > bytes.len() {
            anyhow::bail!("counted ANSI string is truncated");
        }
        Ok((
            String::from_utf8_lossy(&bytes[data_offset..end]).to_string(),
            end,
        ))
    }
}

fn parse_shell_link_extra_data(
    bytes: &[u8],
    mut cursor: usize,
    warnings: &mut Vec<String>,
    truncated: &mut bool,
) -> Vec<serde_json::Value> {
    let mut blocks = Vec::new();
    while cursor + 4 <= bytes.len() && blocks.len() < SHELL_LINK_EXTRA_DATA_LIMIT {
        let size = read_le_u32(bytes, cursor).unwrap_or(0) as usize;
        if size == 0 {
            break;
        }
        if size < 4 {
            warnings.push(format!(
                "Shell Link ExtraData block at {cursor} has invalid size {size}"
            ));
            *truncated = true;
            break;
        }
        let Some(end) = cursor.checked_add(size) else {
            warnings.push("Shell Link ExtraData block offset overflow".to_string());
            *truncated = true;
            break;
        };
        if end > bytes.len() {
            warnings.push(format!(
                "Shell Link ExtraData block at {cursor} extends beyond object bounds"
            ));
            *truncated = true;
            break;
        }
        let signature = read_le_u32(bytes, cursor + 4).unwrap_or(0);
        blocks.push(shell_link_extra_data_json(
            bytes, cursor, end, size, signature,
        ));
        cursor = end;
    }
    if blocks.len() >= SHELL_LINK_EXTRA_DATA_LIMIT && cursor + 4 <= bytes.len() {
        warnings.push(format!(
            "Shell Link ExtraData listing truncated at {SHELL_LINK_EXTRA_DATA_LIMIT} blocks"
        ));
        *truncated = true;
    }
    blocks
}

fn shell_link_extra_data_json(
    bytes: &[u8],
    offset: usize,
    end: usize,
    size: usize,
    signature: u32,
) -> serde_json::Value {
    match signature {
        0xa000_0001 => serde_json::json!({
            "offset": offset,
            "size": size,
            "signature": format!("0x{signature:08x}"),
            "kind": "environment_variables_location",
            "target_ansi": shell_link_ascii_at(bytes, offset, end, 8, 260),
            "target_unicode": shell_link_utf16_at(bytes, offset, end, 268, 260),
        }),
        0xa000_0003 => serde_json::json!({
            "offset": offset,
            "size": size,
            "signature": format!("0x{signature:08x}"),
            "kind": "tracker",
            "machine_id": shell_link_ascii_at(bytes, offset, end, 16, 16),
            "droid": shell_link_guid_list(bytes, offset + 32, 2),
            "droid_birth": shell_link_guid_list(bytes, offset + 64, 2),
        }),
        0xa000_0007 => serde_json::json!({
            "offset": offset,
            "size": size,
            "signature": format!("0x{signature:08x}"),
            "kind": "known_folder",
            "known_folder_id": bytes.get(offset + 8..offset + 24).map(shell_link_clsid_string),
            "offset_value": read_le_u32(bytes, offset + 24),
        }),
        _ => serde_json::json!({
            "offset": offset,
            "size": size,
            "signature": format!("0x{signature:08x}"),
            "kind": "unknown",
            "preview_hex": hex::encode(&bytes[offset..end.min(offset + 64)]),
        }),
    }
}

fn shell_link_ascii_at(
    bytes: &[u8],
    base: usize,
    end: usize,
    relative_offset: u32,
    max_len: usize,
) -> Option<String> {
    if relative_offset == 0 {
        return None;
    }
    let offset = base.checked_add(relative_offset as usize)?;
    if offset >= end || offset >= bytes.len() {
        return None;
    }
    let max_end = end.min(bytes.len()).min(offset.saturating_add(max_len));
    let slice = &bytes[offset..max_end];
    let nul = slice
        .iter()
        .position(|byte| *byte == 0)
        .unwrap_or(slice.len());
    if nul == 0 {
        return None;
    }
    Some(String::from_utf8_lossy(&slice[..nul]).to_string())
}

fn shell_link_utf16_at(
    bytes: &[u8],
    base: usize,
    end: usize,
    relative_offset: u32,
    max_units: usize,
) -> Option<String> {
    if relative_offset == 0 {
        return None;
    }
    let offset = base.checked_add(relative_offset as usize)?;
    if offset + 2 > end || offset + 2 > bytes.len() {
        return None;
    }
    let max_end = end
        .min(bytes.len())
        .min(offset.saturating_add(max_units.saturating_mul(2)));
    let mut units = Vec::new();
    let mut cursor = offset;
    while cursor + 2 <= max_end {
        let unit = read_le_u16(bytes, cursor).unwrap_or(0);
        if unit == 0 {
            break;
        }
        units.push(unit);
        cursor += 2;
    }
    if units.is_empty() {
        None
    } else {
        Some(String::from_utf16_lossy(&units))
    }
}

fn decode_utf16le_lossy(bytes: &[u8]) -> String {
    let units = bytes
        .chunks_exact(2)
        .map(|chunk| u16::from_le_bytes([chunk[0], chunk[1]]))
        .collect::<Vec<_>>();
    String::from_utf16_lossy(&units)
}

fn shell_link_guid_list(bytes: &[u8], offset: usize, count: usize) -> Vec<String> {
    (0..count)
        .filter_map(|index| {
            bytes
                .get(offset + index * 16..offset + (index + 1) * 16)
                .map(shell_link_clsid_string)
        })
        .collect()
}

fn shell_link_clsid_string(bytes: &[u8]) -> String {
    if bytes.len() < 16 {
        return hex::encode(bytes);
    }
    format!(
        "{:08x}-{:04x}-{:04x}-{:02x}{:02x}-{:02x}{:02x}{:02x}{:02x}{:02x}{:02x}",
        u32::from_le_bytes([bytes[0], bytes[1], bytes[2], bytes[3]]),
        u16::from_le_bytes([bytes[4], bytes[5]]),
        u16::from_le_bytes([bytes[6], bytes[7]]),
        bytes[8],
        bytes[9],
        bytes[10],
        bytes[11],
        bytes[12],
        bytes[13],
        bytes[14],
        bytes[15],
    )
}

fn shell_link_header_json(header: &ShellLinkHeader) -> serde_json::Value {
    serde_json::json!({
        "header_size": header.header_size,
        "link_clsid": header.link_clsid,
        "link_flags": header.link_flags,
        "link_flag_names": shell_link_flag_names(header.link_flags),
        "file_attributes": header.file_attributes,
        "file_attribute_names": shell_link_file_attribute_names(header.file_attributes),
        "creation_time": header.creation_time,
        "access_time": header.access_time,
        "write_time": header.write_time,
        "file_size": header.file_size,
        "icon_index": header.icon_index,
        "show_command": header.show_command,
        "show_command_name": shell_link_show_command_name(header.show_command),
        "hot_key": header.hot_key,
    })
}

fn shell_link_info_json(info: &ShellLinkLinkInfo) -> serde_json::Value {
    serde_json::json!({
        "size": info.size,
        "header_size": info.header_size,
        "flags": info.flags,
        "flag_names": shell_link_info_flag_names(info.flags),
        "volume_id_offset": info.volume_id_offset,
        "local_base_path_offset": info.local_base_path_offset,
        "common_network_relative_link_offset": info.common_network_relative_link_offset,
        "common_path_suffix_offset": info.common_path_suffix_offset,
        "local_base_path": info.local_base_path,
        "common_path_suffix": info.common_path_suffix,
        "local_base_path_unicode": info.local_base_path_unicode,
        "common_path_suffix_unicode": info.common_path_suffix_unicode,
        "common_network": info.common_network,
    })
}

fn shell_link_target_hint(parsed: &ShellLinkParsed) -> String {
    if let Some(value) = parsed.strings.get("command_line_arguments") {
        if let Some(relative) = parsed.strings.get("relative_path") {
            return format!("{relative} {value}");
        }
    }
    for value in [
        parsed.strings.get("relative_path").map(String::as_str),
        parsed
            .link_info
            .as_ref()
            .and_then(|info| info.local_base_path_unicode.as_deref()),
        parsed
            .link_info
            .as_ref()
            .and_then(|info| info.local_base_path.as_deref()),
        parsed
            .link_info
            .as_ref()
            .and_then(|info| info.common_path_suffix_unicode.as_deref()),
        parsed
            .link_info
            .as_ref()
            .and_then(|info| info.common_path_suffix.as_deref()),
    ]
    .into_iter()
    .flatten()
    {
        if !value.is_empty() {
            return value.to_string();
        }
    }
    "(unknown target)".to_string()
}

fn collect_shell_link_risk_signals(value: &str, risk_signals: &mut BTreeSet<String>) {
    let lower = value.to_ascii_lowercase();
    if is_unc_or_url(&lower) {
        risk_signals.insert("network_target_reference".to_string());
    }
    if lower.contains("powershell")
        || lower.contains("pwsh")
        || lower.contains("cmd.exe")
        || lower.contains("wscript")
        || lower.contains("cscript")
        || lower.contains("mshta")
        || lower.contains("rundll32")
        || lower.contains("regsvr32")
        || lower.contains("wmic")
    {
        risk_signals.insert("script_or_lolbin_target".to_string());
    }
    if lower.contains("-enc")
        || lower.contains("-encodedcommand")
        || lower.contains("frombase64string")
        || lower.contains("iex")
        || lower.contains("invoke-expression")
    {
        risk_signals.insert("encoded_or_dynamic_command".to_string());
    }
    if lower.contains("http://") || lower.contains("https://") || lower.contains("ftp://") {
        risk_signals.insert("url_reference".to_string());
    }
    if lower.contains("%appdata%")
        || lower.contains("%temp%")
        || lower.contains("%public%")
        || lower.contains("startup")
    {
        risk_signals.insert("user_writable_or_startup_path".to_string());
    }
}

fn is_unc_or_url(value: &str) -> bool {
    value.starts_with("\\\\")
        || value.starts_with("//")
        || value.starts_with("http://")
        || value.starts_with("https://")
        || value.starts_with("ftp://")
}

fn shell_link_flag_names(flags: u32) -> Vec<&'static str> {
    let mut out = Vec::new();
    for (bit, name) in [
        (0x0000_0001, "has_link_target_id_list"),
        (0x0000_0002, "has_link_info"),
        (0x0000_0004, "has_name"),
        (0x0000_0008, "has_relative_path"),
        (0x0000_0010, "has_working_dir"),
        (0x0000_0020, "has_arguments"),
        (0x0000_0040, "has_icon_location"),
        (0x0000_0080, "is_unicode"),
        (0x0000_0200, "has_exp_string"),
        (0x0000_2000, "run_as_user"),
        (0x0000_4000, "has_exp_icon"),
        (0x0000_8000, "no_pidl_alias"),
        (0x0002_0000, "run_with_shim_layer"),
        (0x0008_0000, "enable_target_metadata"),
        (0x0200_0000, "prefer_environment_path"),
        (0x0800_0000, "keep_local_id_list_for_unc_target"),
    ] {
        if flags & bit != 0 {
            out.push(name);
        }
    }
    out
}

fn shell_link_file_attribute_names(flags: u32) -> Vec<&'static str> {
    let mut out = Vec::new();
    for (bit, name) in [
        (0x0000_0001, "readonly"),
        (0x0000_0002, "hidden"),
        (0x0000_0004, "system"),
        (0x0000_0010, "directory"),
        (0x0000_0020, "archive"),
        (0x0000_0040, "device"),
        (0x0000_0080, "normal"),
        (0x0000_0100, "temporary"),
        (0x0000_0400, "reparse_point"),
        (0x0000_0800, "compressed"),
        (0x0000_1000, "offline"),
        (0x0000_4000, "encrypted"),
    ] {
        if flags & bit != 0 {
            out.push(name);
        }
    }
    out
}

fn shell_link_info_flag_names(flags: u32) -> Vec<&'static str> {
    let mut out = Vec::new();
    if flags & 0x1 != 0 {
        out.push("volume_id_and_local_base_path");
    }
    if flags & 0x2 != 0 {
        out.push("common_network_relative_link_and_path_suffix");
    }
    out
}

fn shell_link_common_network_flags(flags: u32) -> Vec<&'static str> {
    let mut out = Vec::new();
    if flags & 0x1 != 0 {
        out.push("valid_device");
    }
    if flags & 0x2 != 0 {
        out.push("valid_net_type");
    }
    out
}

fn shell_link_show_command_name(value: u32) -> &'static str {
    match value {
        1 => "normal",
        3 => "maximized",
        7 => "minimized_no_active",
        _ => "unknown",
    }
}

fn is_shell_link_like_bytes(bytes: &[u8]) -> bool {
    bytes.len() >= SHELL_LINK_HEADER_SIZE
        && bytes.get(0..4) == Some(&[0x4c, 0x00, 0x00, 0x00])
        && bytes.get(4..20) == Some(&SHELL_LINK_CLSID)
}

fn java_class_major_version_label(major: u16) -> &'static str {
    match major {
        45 => "Java 1.1",
        46 => "Java 1.2",
        47 => "Java 1.3",
        48 => "Java 1.4",
        49 => "Java 5",
        50 => "Java 6",
        51 => "Java 7",
        52 => "Java 8",
        53 => "Java 9",
        54 => "Java 10",
        55 => "Java 11",
        56 => "Java 12",
        57 => "Java 13",
        58 => "Java 14",
        59 => "Java 15",
        60 => "Java 16",
        61 => "Java 17",
        62 => "Java 18",
        63 => "Java 19",
        64 => "Java 20",
        65 => "Java 21",
        66 => "Java 22",
        _ => "unknown",
    }
}

fn java_archive_entry_role(name: &str) -> &'static str {
    let lower = name.to_ascii_lowercase();
    if lower == "meta-inf/manifest.mf" {
        "manifest"
    } else if lower.ends_with(".class") {
        "jvm_class"
    } else if lower.starts_with("meta-inf/services/") {
        "service_provider_configuration"
    } else if java_archive_signature_file_role(name).is_some() {
        "signature"
    } else if java_native_library_entry(name) {
        "native_library"
    } else if java_nested_archive_entry(name) {
        "nested_archive"
    } else if lower.starts_with("meta-inf/") {
        "metadata"
    } else {
        "entry"
    }
}

fn java_archive_meta_inf_role(name: &str) -> &'static str {
    java_archive_signature_file_role(name).unwrap_or_else(|| {
        if name.starts_with("META-INF/services/") {
            "service_provider_configuration"
        } else if name.eq_ignore_ascii_case("META-INF/MANIFEST.MF") {
            "manifest"
        } else {
            "metadata"
        }
    })
}

fn java_archive_signature_file_role(name: &str) -> Option<&'static str> {
    android_signature_file_role(name)
}

fn java_native_library_entry(name: &str) -> bool {
    let lower = name.to_ascii_lowercase();
    lower.ends_with(".so")
        || lower.ends_with(".dll")
        || lower.ends_with(".dylib")
        || lower.ends_with(".jnilib")
}

fn java_native_library_format(name: &str) -> &'static str {
    let lower = name.to_ascii_lowercase();
    if lower.ends_with(".so") {
        "elf_shared_library"
    } else if lower.ends_with(".dll") {
        "pe_dynamic_library"
    } else if lower.ends_with(".dylib") || lower.ends_with(".jnilib") {
        "macho_dynamic_library"
    } else {
        "native_library"
    }
}

fn java_nested_archive_entry(name: &str) -> bool {
    let lower = name.to_ascii_lowercase();
    lower.ends_with(".jar") || lower.ends_with(".war") || lower.ends_with(".ear")
}

fn java_nested_archive_format(name: &str) -> &'static str {
    let lower = name.to_ascii_lowercase();
    if lower.ends_with(".war") {
        "war"
    } else if lower.ends_with(".ear") {
        "ear"
    } else {
        "jar"
    }
}

fn java_class_package_name(name: &str) -> String {
    let class_path = name
        .strip_prefix("META-INF/versions/")
        .and_then(|rest| rest.split_once('/').map(|(_, path)| path))
        .unwrap_or(name);
    class_path
        .rsplit_once('/')
        .map(|(package, _)| package.replace('/', "."))
        .filter(|package| !package.is_empty())
        .unwrap_or_else(|| "(default)".to_string())
}

fn analyze_object_portable_executable(
    object: &UniversalObject,
    bytes: &[u8],
) -> ObjectAnalysisSummary {
    match extract_portable_executable_summary(object, bytes) {
        Ok(summary) => ObjectAnalysisSummary {
            analyzer: "portable_executable".to_string(),
            status: if summary.truncated || !summary.warnings.is_empty() {
                ObjectAnalysisStatus::Partial
            } else {
                ObjectAnalysisStatus::Completed
            },
            summary: format!(
                "PE {} {} with {} section(s), {} import DLL(s), {} export(s), {} risk signal(s)",
                summary.architecture,
                summary.subsystem,
                summary.section_count,
                summary.import_library_count,
                summary.export_count,
                summary.risk_signal_count
            ),
            details: summary.details,
            evidence_ids: vec![format!("analysis:{}:portable_executable", object.id)],
        },
        Err(err) => ObjectAnalysisSummary {
            analyzer: "portable_executable".to_string(),
            status: ObjectAnalysisStatus::Failed,
            summary: format!("Portable Executable analysis failed: {err}"),
            details: serde_json::json!({ "error": err.to_string() }),
            evidence_ids: vec![format!("analysis:{}:portable_executable", object.id)],
        },
    }
}

