const DOTNET_STREAM_LIMIT: usize = 64;
const DOTNET_STREAM_NAME_LIMIT: usize = 128;
const DOTNET_TYPE_REF_LIMIT: usize = 1024;
const DOTNET_TYPE_DEF_LIMIT: usize = 1024;
const DOTNET_METHOD_DEF_LIMIT: usize = 2048;
const DOTNET_MEMBER_REF_LIMIT: usize = 2048;
const DOTNET_ASSEMBLY_LIMIT: usize = 64;
const DOTNET_ASSEMBLY_REF_LIMIT: usize = 512;
const DOTNET_MANIFEST_RESOURCE_LIMIT: usize = 256;
const DOTNET_MODULE_REF_LIMIT: usize = 256;
const DOTNET_IMPL_MAP_LIMIT: usize = 512;
const DOTNET_STRING_HEAP_LIMIT: usize = 2048;
const DOTNET_USER_STRING_LIMIT: usize = 512;

fn extract_dotnet_metadata_summary(
    object: &UniversalObject,
    bytes: &[u8],
) -> Result<DotnetMetadataAnalysisSummary> {
    let layout = parse_pe_dotnet_layout(bytes)?;
    let clr_directory = pe_directory(&layout.directories, "clr_runtime")
        .filter(|directory| directory.rva != 0 && directory.size != 0)
        .context("PE CLR runtime data directory is not present")?;
    let clr_offset = pe_rva_to_file_offset(clr_directory.rva, &layout.sections)
        .context("PE CLR runtime data directory RVA did not map to a file offset")?;
    let clr_header = parse_dotnet_clr_header(bytes, clr_offset)?;
    let mut warnings = Vec::new();
    if clr_header.cb < 72 {
        warnings.push(format!(
            ".NET CLR header declares {} byte(s); expected at least 72 for IMAGE_COR20_HEADER",
            clr_header.cb
        ));
    }
    if clr_header.metadata.rva == 0 || clr_header.metadata.size == 0 {
        anyhow::bail!(".NET CLR header does not declare a metadata directory");
    }
    let metadata_offset = pe_rva_to_file_offset(clr_header.metadata.rva, &layout.sections)
        .context(".NET metadata RVA did not map to a file offset")?;
    if metadata_offset
        .checked_add(clr_header.metadata.size as usize)
        .is_none_or(|end| end > bytes.len())
    {
        warnings.push(".NET metadata directory extends beyond object bounds".to_string());
    }
    let metadata_root = parse_dotnet_metadata_root(
        bytes,
        metadata_offset,
        clr_header.metadata.size,
        &mut warnings,
    )?;
    let stream_values = metadata_root
        .streams
        .iter()
        .map(dotnet_metadata_stream_json)
        .collect::<Vec<_>>();
    let strings_heap = metadata_root
        .streams
        .iter()
        .find(|stream| stream.name == "#Strings")
        .and_then(|stream| dotnet_stream_bytes(bytes, stream))
        .unwrap_or(&[]);
    let (strings_heap_values, strings_for_risk, strings_truncated) =
        dotnet_extract_strings_heap_values(strings_heap, DOTNET_STRING_HEAP_LIMIT);
    let us_heap = metadata_root
        .streams
        .iter()
        .find(|stream| stream.name == "#US")
        .and_then(|stream| dotnet_stream_bytes(bytes, stream))
        .unwrap_or(&[]);
    let (user_string_values, user_strings_for_risk, user_strings_truncated) =
        dotnet_extract_user_strings(us_heap, DOTNET_USER_STRING_LIMIT);
    let tables_stream = metadata_root
        .streams
        .iter()
        .find(|stream| stream.name == "#~" || stream.name == "#-")
        .context(".NET metadata tables stream (#~ or #-) is not present")?;
    let tables = parse_dotnet_tables_stream(bytes, tables_stream, strings_heap, &mut warnings)?;

    let mut risk_signals = BTreeSet::<String>::new();
    risk_signals.insert("dotnet_metadata_present".to_string());
    if clr_header.entry_point_token_or_rva != 0 && clr_header.flags & 0x10 == 0 {
        risk_signals.insert("managed_entrypoint_present".to_string());
    }
    if clr_header.entry_point_token_or_rva != 0 && clr_header.flags & 0x10 != 0 {
        risk_signals.insert("native_entrypoint_present".to_string());
    }
    if !tables.assembly_refs.is_empty() {
        risk_signals.insert("assembly_refs_present".to_string());
    }
    for type_ref in &tables.type_refs {
        collect_dotnet_name_risk_signals(&type_ref.qualified_name, &mut risk_signals);
    }
    for type_def in &tables.type_defs {
        collect_dotnet_name_risk_signals(&type_def.qualified_name, &mut risk_signals);
    }
    for method in &tables.method_defs {
        collect_dotnet_name_risk_signals(&method.qualified_name, &mut risk_signals);
        if method.flags & 0x2000 != 0 {
            risk_signals.insert("pinvoke_or_native_interop_reference".to_string());
        }
    }
    for member_ref in &tables.member_refs {
        collect_dotnet_name_risk_signals(&member_ref.qualified_name, &mut risk_signals);
    }
    for assembly in &tables.assemblies {
        collect_dotnet_name_risk_signals(&assembly.name, &mut risk_signals);
    }
    for assembly_ref in &tables.assembly_refs {
        collect_dotnet_name_risk_signals(&assembly_ref.name, &mut risk_signals);
    }
    if !tables.manifest_resources.is_empty() {
        risk_signals.insert("manifest_resources_present".to_string());
    }
    if tables.manifest_resources.iter().any(|item| item.is_embedded) {
        risk_signals.insert("embedded_manifest_resources_present".to_string());
    }
    for resource in &tables.manifest_resources {
        collect_dotnet_name_risk_signals(&resource.name, &mut risk_signals);
        let lower = resource.name.to_ascii_lowercase();
        if lower.ends_with(".dll")
            || lower.ends_with(".exe")
            || lower.ends_with(".bin")
            || lower.ends_with(".dat")
            || lower.contains("payload")
            || lower.contains("resource")
            || lower.contains("embed")
        {
            risk_signals.insert("interesting_manifest_resource_name".to_string());
        }
    }
    if !tables.module_refs.is_empty() {
        risk_signals.insert("module_refs_present".to_string());
    }
    if !tables.impl_maps.is_empty() {
        risk_signals.insert("impl_maps_present".to_string());
        risk_signals.insert("pinvoke_or_native_interop_reference".to_string());
    }
    for module_ref in &tables.module_refs {
        collect_dotnet_name_risk_signals(&module_ref.name, &mut risk_signals);
        let lower = module_ref.name.to_ascii_lowercase();
        if lower.ends_with(".dll")
            || lower.ends_with(".so")
            || lower.ends_with(".dylib")
            || lower.contains("kernel32")
            || lower.contains("ntdll")
            || lower.contains("user32")
            || lower.contains("advapi32")
            || lower.contains("ws2_32")
            || lower.contains("wininet")
            || lower.contains("crypt")
        {
            risk_signals.insert("native_module_ref_present".to_string());
        }
    }
    for impl_map in &tables.impl_maps {
        collect_dotnet_name_risk_signals(&impl_map.import_name, &mut risk_signals);
        if let Some(module_name) = &impl_map.module_name {
            collect_dotnet_name_risk_signals(module_name, &mut risk_signals);
        }
        if let Some(method_name) = &impl_map.method_name {
            collect_dotnet_name_risk_signals(method_name, &mut risk_signals);
        }
        let import_lower = impl_map.import_name.to_ascii_lowercase();
        if import_lower.contains("virtualalloc")
            || import_lower.contains("virtualprotect")
            || import_lower.contains("writeprocessmemory")
            || import_lower.contains("createremotethread")
            || import_lower.contains("loadlibrary")
            || import_lower.contains("getprocaddress")
            || import_lower.contains("ntprotectvirtualmemory")
        {
            risk_signals.insert("suspicious_pinvoke_import".to_string());
        }
    }
    for value in &strings_for_risk {
        collect_dotnet_name_risk_signals(value, &mut risk_signals);
    }
    if !user_string_values.is_empty() {
        risk_signals.insert("user_strings_present".to_string());
    }
    for value in &user_strings_for_risk {
        collect_dotnet_name_risk_signals(value, &mut risk_signals);
        collect_dotnet_user_string_risk_signals(value, &mut risk_signals);
    }

    let type_ref_values = tables
        .type_refs
        .iter()
        .map(dotnet_type_ref_json)
        .collect::<Vec<_>>();
    let type_def_values = tables
        .type_defs
        .iter()
        .map(dotnet_type_def_json)
        .collect::<Vec<_>>();
    let method_def_values = tables
        .method_defs
        .iter()
        .map(dotnet_method_def_json)
        .collect::<Vec<_>>();
    let member_ref_values = tables
        .member_refs
        .iter()
        .map(dotnet_member_ref_json)
        .collect::<Vec<_>>();
    let assembly_values = tables
        .assemblies
        .iter()
        .map(|assembly| dotnet_assembly_json(assembly, "assembly"))
        .collect::<Vec<_>>();
    let assembly_ref_values = tables
        .assembly_refs
        .iter()
        .map(|assembly| dotnet_assembly_json(assembly, "assembly_ref"))
        .collect::<Vec<_>>();
    let manifest_resource_values = tables
        .manifest_resources
        .iter()
        .map(dotnet_manifest_resource_json)
        .collect::<Vec<_>>();
    let module_ref_values = tables
        .module_refs
        .iter()
        .map(dotnet_module_ref_json)
        .collect::<Vec<_>>();
    let impl_map_values = tables
        .impl_maps
        .iter()
        .map(dotnet_impl_map_json)
        .collect::<Vec<_>>();
    let risk_signal_values = risk_signals.into_iter().take(256).collect::<Vec<_>>();
    let truncated = tables.truncated
        || strings_truncated
        || user_strings_truncated
        || metadata_root.streams.len() >= DOTNET_STREAM_LIMIT
            && metadata_root.declared_stream_count as usize > DOTNET_STREAM_LIMIT
        || tables.type_refs.len() >= DOTNET_TYPE_REF_LIMIT
            && tables.row_counts[1] as usize > DOTNET_TYPE_REF_LIMIT
        || tables.type_defs.len() >= DOTNET_TYPE_DEF_LIMIT
            && tables.row_counts[2] as usize > DOTNET_TYPE_DEF_LIMIT
        || tables.method_defs.len() >= DOTNET_METHOD_DEF_LIMIT
            && tables.row_counts[6] as usize > DOTNET_METHOD_DEF_LIMIT
        || tables.member_refs.len() >= DOTNET_MEMBER_REF_LIMIT
            && tables.row_counts[10] as usize > DOTNET_MEMBER_REF_LIMIT
        || tables.assembly_refs.len() >= DOTNET_ASSEMBLY_REF_LIMIT
            && tables.row_counts[35] as usize > DOTNET_ASSEMBLY_REF_LIMIT
        || tables.manifest_resources.len() >= DOTNET_MANIFEST_RESOURCE_LIMIT
            && tables.row_counts[40] as usize > DOTNET_MANIFEST_RESOURCE_LIMIT
        || tables.module_refs.len() >= DOTNET_MODULE_REF_LIMIT
            && tables.row_counts[26] as usize > DOTNET_MODULE_REF_LIMIT
        || tables.impl_maps.len() >= DOTNET_IMPL_MAP_LIMIT
            && tables.row_counts[28] as usize > DOTNET_IMPL_MAP_LIMIT;
    let assembly_name = tables
        .assemblies
        .first()
        .map(|assembly| assembly.name.clone())
        .filter(|name| !name.is_empty())
        .unwrap_or_else(|| {
            object
                .path
                .as_deref()
                .unwrap_or(object.id.as_str())
                .to_string()
        });
    let details = serde_json::json!({
        "format": object.format.as_deref().unwrap_or("pe"),
        "clr_runtime_directory": pe_directory_summary(&layout.directories, &layout.sections, "clr_runtime"),
        "clr_header": {
            "file_offset": clr_offset,
            "cb": clr_header.cb,
            "major_runtime_version": clr_header.major_runtime_version,
            "minor_runtime_version": clr_header.minor_runtime_version,
            "metadata": dotnet_rva_directory_json(&clr_header.metadata, &layout.sections),
            "flags": clr_header.flags,
            "flag_names": dotnet_clr_header_flags(clr_header.flags),
            "entry_point_token_or_rva": clr_header.entry_point_token_or_rva,
            "entry_point": dotnet_entry_point_json(clr_header.entry_point_token_or_rva, clr_header.flags),
            "resources": dotnet_rva_directory_json(&clr_header.resources, &layout.sections),
            "strong_name_signature": dotnet_rva_directory_json(&clr_header.strong_name_signature, &layout.sections),
            "code_manager_table": dotnet_rva_directory_json(&clr_header.code_manager_table, &layout.sections),
            "vtable_fixups": dotnet_rva_directory_json(&clr_header.vtable_fixups, &layout.sections),
            "export_address_table_jumps": dotnet_rva_directory_json(&clr_header.export_address_table_jumps, &layout.sections),
            "managed_native_header": dotnet_rva_directory_json(&clr_header.managed_native_header, &layout.sections),
        },
        "metadata_root": {
            "file_offset": metadata_offset,
            "signature": "BSJB",
            "major_version": metadata_root.major_version,
            "minor_version": metadata_root.minor_version,
            "reserved": metadata_root.reserved,
            "version_string": metadata_root.version_string,
            "flags": metadata_root.flags,
            "declared_stream_count": metadata_root.declared_stream_count,
            "listed_stream_count": metadata_root.streams.len(),
        },
        "streams": stream_values,
        "tables": {
            "stream_name": tables.stream_name,
            "major_version": tables.major_version,
            "minor_version": tables.minor_version,
            "heap_sizes": tables.heap_sizes,
            "heap_index_sizes": {
                "strings": dotnet_heap_index_size(tables.heap_sizes, 0x01),
                "guid": dotnet_heap_index_size(tables.heap_sizes, 0x02),
                "blob": dotnet_heap_index_size(tables.heap_sizes, 0x04),
            },
            "valid_mask": format!("0x{:016x}", tables.valid_mask),
            "sorted_mask": format!("0x{:016x}", tables.sorted_mask),
            "row_counts": tables.row_count_values,
        },
        "strings_heap": {
            "listed_count": strings_heap_values.len(),
            "strings_truncated": strings_truncated,
            "strings": strings_heap_values,
        },
        "user_strings": {
            "listed_count": user_string_values.len(),
            "strings_truncated": user_strings_truncated,
            "strings": user_string_values,
        },
        "type_refs": type_ref_values,
        "type_defs": type_def_values,
        "method_defs": method_def_values,
        "member_refs": member_ref_values,
        "assembly": assembly_values.first().cloned().unwrap_or(serde_json::Value::Null),
        "assemblies": assembly_values,
        "assembly_refs": assembly_ref_values,
        "manifest_resources": manifest_resource_values,
        "module_refs": module_ref_values,
        "impl_maps": impl_map_values,
        "risk_signals": risk_signal_values,
        "warnings": warnings,
        "truncated": truncated,
    });

    Ok(DotnetMetadataAnalysisSummary {
        assembly_name,
        type_count: details["type_defs"].as_array().map_or(0, Vec::len),
        method_count: details["method_defs"].as_array().map_or(0, Vec::len),
        member_ref_count: details["member_refs"].as_array().map_or(0, Vec::len),
        assembly_ref_count: details["assembly_refs"].as_array().map_or(0, Vec::len),
        risk_signal_count: details["risk_signals"].as_array().map_or(0, Vec::len),
        truncated,
        warnings: details["warnings"]
            .as_array()
            .map(|items| {
                items
                    .iter()
                    .filter_map(|item| item.as_str().map(ToOwned::to_owned))
                    .collect()
            })
            .unwrap_or_default(),
        details,
    })
}

fn parse_pe_dotnet_layout(bytes: &[u8]) -> Result<PeDotnetLayout> {
    if !bytes.starts_with(PE_DOS_HEADER) {
        anyhow::bail!("object does not start with an MZ DOS header");
    }
    let pe_offset = read_le_u32(bytes, 0x3c).context("missing DOS e_lfanew pointer")? as usize;
    if pe_offset
        .checked_add(24)
        .is_none_or(|end| end > bytes.len())
    {
        anyhow::bail!("PE header offset is outside object bounds");
    }
    if bytes.get(pe_offset..pe_offset + 4) != Some(PE_SIGNATURE) {
        anyhow::bail!("DOS header does not point to a PE signature");
    }
    let number_of_sections =
        read_le_u16(bytes, pe_offset + 6).context("missing COFF section count")?;
    let optional_header_size =
        read_le_u16(bytes, pe_offset + 20).context("missing optional header size")? as usize;
    let optional_header_offset = pe_offset + 24;
    let optional_header_end = optional_header_offset
        .checked_add(optional_header_size)
        .context("PE optional header size overflow")?;
    if optional_header_end > bytes.len() {
        anyhow::bail!("PE optional header is truncated");
    }
    let optional_magic =
        read_le_u16(bytes, optional_header_offset).context("missing optional header magic")?;
    let data_directory_offset = match optional_magic {
        0x10b => optional_header_offset + 96,
        0x20b => optional_header_offset + 112,
        other => anyhow::bail!("unsupported PE optional header magic {other:#x}"),
    };
    let number_of_rva_and_sizes_offset = match optional_magic {
        0x10b => optional_header_offset + 92,
        0x20b => optional_header_offset + 108,
        _ => unreachable!(),
    };
    let number_of_rva_and_sizes = read_le_u32(bytes, number_of_rva_and_sizes_offset)
        .context("missing data directory count")? as usize;
    let section_table_offset = optional_header_end;
    let section_count_for_read = (number_of_sections as usize).min(PE_SECTION_LIMIT);
    let sections = parse_pe_sections(
        bytes,
        section_table_offset,
        number_of_sections as usize,
        section_count_for_read,
    );
    let directories = parse_pe_data_directories(
        bytes,
        data_directory_offset,
        number_of_rva_and_sizes,
        optional_header_end,
    );
    Ok(PeDotnetLayout {
        sections,
        directories,
    })
}

fn pe_has_clr_runtime_directory(bytes: &[u8]) -> bool {
    parse_pe_dotnet_layout(bytes).ok().is_some_and(|layout| {
        pe_directory(&layout.directories, "clr_runtime")
            .filter(|directory| directory.rva != 0 && directory.size != 0)
            .and_then(|directory| pe_rva_to_file_offset(directory.rva, &layout.sections))
            .is_some()
    })
}

fn parse_dotnet_clr_header(bytes: &[u8], offset: usize) -> Result<DotnetClrHeader> {
    if offset.checked_add(24).is_none_or(|end| end > bytes.len()) {
        anyhow::bail!(".NET CLR header is truncated");
    }
    let directory = |relative: usize| DotnetRvaDirectory {
        rva: read_le_u32(bytes, offset + relative).unwrap_or(0),
        size: read_le_u32(bytes, offset + relative + 4).unwrap_or(0),
    };
    Ok(DotnetClrHeader {
        cb: read_le_u32(bytes, offset).context("missing .NET CLR header size")?,
        major_runtime_version: read_le_u16(bytes, offset + 4)
            .context("missing .NET CLR major runtime version")?,
        minor_runtime_version: read_le_u16(bytes, offset + 6)
            .context("missing .NET CLR minor runtime version")?,
        metadata: directory(8),
        flags: read_le_u32(bytes, offset + 16).context("missing .NET CLR flags")?,
        entry_point_token_or_rva: read_le_u32(bytes, offset + 20)
            .context("missing .NET CLR entry point token/RVA")?,
        resources: directory(24),
        strong_name_signature: directory(32),
        code_manager_table: directory(40),
        vtable_fixups: directory(48),
        export_address_table_jumps: directory(56),
        managed_native_header: directory(64),
    })
}

fn parse_dotnet_metadata_root(
    bytes: &[u8],
    metadata_offset: usize,
    metadata_size: u32,
    warnings: &mut Vec<String>,
) -> Result<DotnetMetadataRoot> {
    if metadata_offset
        .checked_add(16)
        .is_none_or(|end| end > bytes.len())
    {
        anyhow::bail!(".NET metadata root is truncated");
    }
    if bytes.get(metadata_offset..metadata_offset + 4) != Some(b"BSJB") {
        anyhow::bail!(".NET metadata root signature is not BSJB");
    }
    let metadata_end = metadata_offset
        .checked_add(metadata_size as usize)
        .unwrap_or(bytes.len())
        .min(bytes.len());
    let major_version =
        read_le_u16(bytes, metadata_offset + 4).context("missing .NET metadata major version")?;
    let minor_version =
        read_le_u16(bytes, metadata_offset + 6).context("missing .NET metadata minor version")?;
    let reserved =
        read_le_u32(bytes, metadata_offset + 8).context("missing .NET metadata reserved field")?;
    let version_len = read_le_u32(bytes, metadata_offset + 12)
        .context("missing .NET metadata version string length")? as usize;
    let version_offset = metadata_offset + 16;
    let version_end = version_offset
        .checked_add(version_len)
        .context(".NET metadata version string length overflow")?;
    if version_end > bytes.len() {
        anyhow::bail!(".NET metadata version string is truncated");
    }
    if version_end > metadata_end {
        warnings
            .push(".NET metadata version string extends beyond declared metadata size".to_string());
    }
    let version_raw = &bytes[version_offset..version_end];
    let version_trimmed = version_raw
        .split(|byte| *byte == 0)
        .next()
        .unwrap_or(version_raw);
    let version_string = String::from_utf8_lossy(version_trimmed).to_string();
    let stream_header_offset =
        dotnet_align4(version_end).context(".NET metadata version string alignment overflow")?;
    if stream_header_offset
        .checked_add(4)
        .is_none_or(|end| end > bytes.len())
    {
        anyhow::bail!(".NET metadata stream header is truncated");
    }
    let flags =
        read_le_u16(bytes, stream_header_offset).context("missing .NET metadata stream flags")?;
    let declared_stream_count = read_le_u16(bytes, stream_header_offset + 2)
        .context("missing .NET metadata stream count")?;
    let mut cursor = stream_header_offset + 4;
    let mut streams = Vec::new();
    for stream_index in 0..(declared_stream_count as usize).min(DOTNET_STREAM_LIMIT) {
        if cursor.checked_add(8).is_none_or(|end| end > bytes.len()) {
            warnings.push(format!(
                ".NET metadata stream header scan stopped at stream {stream_index}"
            ));
            break;
        }
        let offset = read_le_u32(bytes, cursor).unwrap_or(0);
        let size = read_le_u32(bytes, cursor + 4).unwrap_or(0);
        let name_offset = cursor + 8;
        let name_scan_end = bytes
            .len()
            .min(name_offset.saturating_add(DOTNET_STREAM_NAME_LIMIT));
        let Some(name_len) = bytes[name_offset..name_scan_end]
            .iter()
            .position(|byte| *byte == 0)
        else {
            warnings.push(format!(
                ".NET metadata stream {stream_index} name is not NUL terminated"
            ));
            break;
        };
        let name = String::from_utf8_lossy(&bytes[name_offset..name_offset + name_len]).to_string();
        let file_offset = metadata_offset
            .checked_add(offset as usize)
            .context(".NET metadata stream file offset overflow")?;
        let within_metadata = offset
            .checked_add(size)
            .is_some_and(|end| end <= metadata_size);
        if !within_metadata {
            warnings.push(format!(
                ".NET metadata stream {name} extends beyond declared metadata size"
            ));
        }
        if file_offset
            .checked_add(size as usize)
            .is_none_or(|end| end > bytes.len())
        {
            warnings.push(format!(
                ".NET metadata stream {name} extends beyond object bounds"
            ));
        }
        streams.push(DotnetMetadataStream {
            name,
            offset,
            size,
            file_offset,
            within_metadata,
        });
        cursor = dotnet_align4(name_offset + name_len + 1)
            .context(".NET metadata stream name alignment overflow")?;
    }
    if declared_stream_count as usize > DOTNET_STREAM_LIMIT {
        warnings.push(format!(
            ".NET metadata stream listing truncated at {DOTNET_STREAM_LIMIT} of {declared_stream_count}"
        ));
    }
    Ok(DotnetMetadataRoot {
        major_version,
        minor_version,
        reserved,
        version_string,
        flags,
        declared_stream_count,
        streams,
    })
}

fn parse_dotnet_tables_stream(
    bytes: &[u8],
    stream: &DotnetMetadataStream,
    strings_heap: &[u8],
    warnings: &mut Vec<String>,
) -> Result<DotnetTablesAnalysis> {
    let stream_end = stream
        .file_offset
        .checked_add(stream.size as usize)
        .context(".NET tables stream size overflow")?
        .min(bytes.len());
    if stream
        .file_offset
        .checked_add(24)
        .is_none_or(|end| end > stream_end)
    {
        anyhow::bail!(".NET metadata tables stream is truncated");
    }
    let major_version = *bytes.get(stream.file_offset + 4).unwrap_or(&0);
    let minor_version = *bytes.get(stream.file_offset + 5).unwrap_or(&0);
    let heap_sizes = *bytes.get(stream.file_offset + 6).unwrap_or(&0);
    let valid_mask =
        read_le_u64(bytes, stream.file_offset + 8).context("missing .NET valid table mask")?;
    let sorted_mask =
        read_le_u64(bytes, stream.file_offset + 16).context("missing .NET sorted table mask")?;
    let mut cursor = stream.file_offset + 24;
    let mut row_counts = [0u32; 64];
    let mut row_count_values = Vec::new();
    for (table_id, row_count) in row_counts.iter_mut().enumerate() {
        if valid_mask & (1u64 << table_id) == 0 {
            continue;
        }
        if cursor.checked_add(4).is_none_or(|end| end > stream_end) {
            anyhow::bail!(".NET metadata table row count list is truncated");
        }
        *row_count = read_le_u32(bytes, cursor).unwrap_or(0);
        cursor += 4;
        row_count_values.push(serde_json::json!({
            "id": table_id,
            "name": dotnet_metadata_table_name(table_id as u8),
            "rows": *row_count,
        }));
    }

    let mut table_offsets = [None::<usize>; 64];
    let mut truncated = false;
    for table_id in 0..64 {
        let row_count = row_counts[table_id] as usize;
        if row_count == 0 {
            continue;
        }
        let Some(row_size) = dotnet_table_row_size(table_id as u8, &row_counts, heap_sizes) else {
            warnings.push(format!(
                ".NET metadata table {} row size is not supported",
                dotnet_metadata_table_name(table_id as u8)
            ));
            truncated = true;
            break;
        };
        table_offsets[table_id] = Some(cursor);
        let Some(byte_len) = row_size.checked_mul(row_count) else {
            warnings.push(format!(
                ".NET metadata table {} size overflows",
                dotnet_metadata_table_name(table_id as u8)
            ));
            truncated = true;
            break;
        };
        let Some(next_cursor) = cursor.checked_add(byte_len) else {
            warnings.push(format!(
                ".NET metadata table {} offset overflows",
                dotnet_metadata_table_name(table_id as u8)
            ));
            truncated = true;
            break;
        };
        if next_cursor > stream_end {
            warnings.push(format!(
                ".NET metadata table {} extends beyond the tables stream",
                dotnet_metadata_table_name(table_id as u8)
            ));
            truncated = true;
            break;
        }
        cursor = next_cursor;
    }

    let type_refs = parse_dotnet_type_refs(
        bytes,
        &table_offsets,
        &row_counts,
        heap_sizes,
        strings_heap,
        warnings,
    )?;
    let type_defs = parse_dotnet_type_defs(
        bytes,
        &table_offsets,
        &row_counts,
        heap_sizes,
        strings_heap,
        warnings,
    )?;
    let mut method_defs = parse_dotnet_method_defs(
        bytes,
        &table_offsets,
        &row_counts,
        heap_sizes,
        strings_heap,
        warnings,
    )?;
    dotnet_assign_method_owners(&type_defs, &mut method_defs, row_counts[6]);
    let member_refs = parse_dotnet_member_refs(
        bytes,
        &table_offsets,
        &row_counts,
        heap_sizes,
        strings_heap,
        &type_defs,
        &type_refs,
        &method_defs,
        warnings,
    )?;
    let assemblies = parse_dotnet_assemblies(
        bytes,
        &table_offsets,
        &row_counts,
        heap_sizes,
        strings_heap,
        32,
        DOTNET_ASSEMBLY_LIMIT,
        warnings,
    )?;
    let assembly_refs = parse_dotnet_assemblies(
        bytes,
        &table_offsets,
        &row_counts,
        heap_sizes,
        strings_heap,
        35,
        DOTNET_ASSEMBLY_REF_LIMIT,
        warnings,
    )?;
    let manifest_resources = parse_dotnet_manifest_resources(
        bytes,
        &table_offsets,
        &row_counts,
        heap_sizes,
        strings_heap,
        warnings,
    )?;
    let module_refs = parse_dotnet_module_refs(
        bytes,
        &table_offsets,
        &row_counts,
        heap_sizes,
        strings_heap,
        warnings,
    )?;
    let impl_maps = parse_dotnet_impl_maps(
        bytes,
        &table_offsets,
        &row_counts,
        heap_sizes,
        strings_heap,
        &module_refs,
        &method_defs,
        warnings,
    )?;

    Ok(DotnetTablesAnalysis {
        stream_name: stream.name.clone(),
        major_version,
        minor_version,
        heap_sizes,
        valid_mask,
        sorted_mask,
        row_counts,
        row_count_values,
        type_refs,
        type_defs,
        method_defs,
        member_refs,
        assemblies,
        assembly_refs,
        manifest_resources,
        module_refs,
        impl_maps,
        truncated,
    })
}

fn parse_dotnet_type_refs(
    bytes: &[u8],
    table_offsets: &[Option<usize>; 64],
    row_counts: &[u32; 64],
    heap_sizes: u8,
    strings_heap: &[u8],
    warnings: &mut Vec<String>,
) -> Result<Vec<DotnetTypeRefRecord>> {
    let Some(base_offset) = table_offsets[1] else {
        return Ok(Vec::new());
    };
    let row_size = dotnet_table_row_size(1, row_counts, heap_sizes).unwrap_or(0);
    let string_index_size = dotnet_heap_index_size(heap_sizes, 0x01);
    let scope_size = dotnet_coded_index_size(DotnetCodedIndexKind::ResolutionScope, row_counts);
    let declared_rows = row_counts[1] as usize;
    let mut records = Vec::new();
    for row in 1..=declared_rows.min(DOTNET_TYPE_REF_LIMIT) {
        let mut cursor = DotnetTableCursor::new(bytes, base_offset + (row - 1) * row_size);
        let scope_raw = cursor.read_index(scope_size, "TypeRef.ResolutionScope")?;
        let name_index = cursor.read_index(string_index_size, "TypeRef.TypeName")?;
        let namespace_index = cursor.read_index(string_index_size, "TypeRef.TypeNamespace")?;
        let name = dotnet_string_or_placeholder(strings_heap, name_index);
        let namespace = dotnet_string_or_placeholder(strings_heap, namespace_index);
        records.push(DotnetTypeRefRecord {
            row: row as u32,
            qualified_name: dotnet_qualified_type_name(&namespace, &name),
            name,
            namespace,
            resolution_scope: dotnet_decode_coded_index(
                scope_raw,
                DotnetCodedIndexKind::ResolutionScope,
            ),
        });
    }
    if declared_rows > DOTNET_TYPE_REF_LIMIT {
        warnings.push(format!(
            ".NET TypeRef table listing truncated at {DOTNET_TYPE_REF_LIMIT} of {declared_rows} rows"
        ));
    }
    Ok(records)
}

fn parse_dotnet_type_defs(
    bytes: &[u8],
    table_offsets: &[Option<usize>; 64],
    row_counts: &[u32; 64],
    heap_sizes: u8,
    strings_heap: &[u8],
    warnings: &mut Vec<String>,
) -> Result<Vec<DotnetTypeDefRecord>> {
    let Some(base_offset) = table_offsets[2] else {
        return Ok(Vec::new());
    };
    let row_size = dotnet_table_row_size(2, row_counts, heap_sizes).unwrap_or(0);
    let string_index_size = dotnet_heap_index_size(heap_sizes, 0x01);
    let extends_size = dotnet_coded_index_size(DotnetCodedIndexKind::TypeDefOrRef, row_counts);
    let field_index_size = dotnet_table_index_size(row_counts, 4);
    let method_index_size = dotnet_table_index_size(row_counts, 6);
    let declared_rows = row_counts[2] as usize;
    let mut records = Vec::new();
    for row in 1..=declared_rows.min(DOTNET_TYPE_DEF_LIMIT) {
        let mut cursor = DotnetTableCursor::new(bytes, base_offset + (row - 1) * row_size);
        let flags = cursor.read_u32("TypeDef.Flags")?;
        let name_index = cursor.read_index(string_index_size, "TypeDef.TypeName")?;
        let namespace_index = cursor.read_index(string_index_size, "TypeDef.TypeNamespace")?;
        let extends_raw = cursor.read_index(extends_size, "TypeDef.Extends")?;
        let field_list = cursor.read_index(field_index_size, "TypeDef.FieldList")?;
        let method_list = cursor.read_index(method_index_size, "TypeDef.MethodList")?;
        let name = dotnet_string_or_placeholder(strings_heap, name_index);
        let namespace = dotnet_string_or_placeholder(strings_heap, namespace_index);
        records.push(DotnetTypeDefRecord {
            row: row as u32,
            flags,
            qualified_name: dotnet_qualified_type_name(&namespace, &name),
            name,
            namespace,
            extends: dotnet_decode_coded_index(extends_raw, DotnetCodedIndexKind::TypeDefOrRef),
            field_list,
            method_list,
        });
    }
    if declared_rows > DOTNET_TYPE_DEF_LIMIT {
        warnings.push(format!(
            ".NET TypeDef table listing truncated at {DOTNET_TYPE_DEF_LIMIT} of {declared_rows} rows"
        ));
    }
    Ok(records)
}

fn parse_dotnet_method_defs(
    bytes: &[u8],
    table_offsets: &[Option<usize>; 64],
    row_counts: &[u32; 64],
    heap_sizes: u8,
    strings_heap: &[u8],
    warnings: &mut Vec<String>,
) -> Result<Vec<DotnetMethodDefRecord>> {
    let Some(base_offset) = table_offsets[6] else {
        return Ok(Vec::new());
    };
    let row_size = dotnet_table_row_size(6, row_counts, heap_sizes).unwrap_or(0);
    let string_index_size = dotnet_heap_index_size(heap_sizes, 0x01);
    let blob_index_size = dotnet_heap_index_size(heap_sizes, 0x04);
    let param_index_size = dotnet_table_index_size(row_counts, 8);
    let declared_rows = row_counts[6] as usize;
    let mut records = Vec::new();
    for row in 1..=declared_rows.min(DOTNET_METHOD_DEF_LIMIT) {
        let mut cursor = DotnetTableCursor::new(bytes, base_offset + (row - 1) * row_size);
        let rva = cursor.read_u32("MethodDef.RVA")?;
        let impl_flags = cursor.read_u16("MethodDef.ImplFlags")?;
        let flags = cursor.read_u16("MethodDef.Flags")?;
        let name_index = cursor.read_index(string_index_size, "MethodDef.Name")?;
        let signature = cursor.read_index(blob_index_size, "MethodDef.Signature")?;
        let param_list = cursor.read_index(param_index_size, "MethodDef.ParamList")?;
        let name = dotnet_string_or_placeholder(strings_heap, name_index);
        records.push(DotnetMethodDefRecord {
            row: row as u32,
            rva,
            impl_flags,
            flags,
            qualified_name: name.clone(),
            name,
            signature,
            param_list,
            declaring_type: None,
        });
    }
    if declared_rows > DOTNET_METHOD_DEF_LIMIT {
        warnings.push(format!(
            ".NET MethodDef table listing truncated at {DOTNET_METHOD_DEF_LIMIT} of {declared_rows} rows"
        ));
    }
    Ok(records)
}

fn parse_dotnet_member_refs(
    bytes: &[u8],
    table_offsets: &[Option<usize>; 64],
    row_counts: &[u32; 64],
    heap_sizes: u8,
    strings_heap: &[u8],
    type_defs: &[DotnetTypeDefRecord],
    type_refs: &[DotnetTypeRefRecord],
    method_defs: &[DotnetMethodDefRecord],
    warnings: &mut Vec<String>,
) -> Result<Vec<DotnetMemberRefRecord>> {
    let Some(base_offset) = table_offsets[10] else {
        return Ok(Vec::new());
    };
    let row_size = dotnet_table_row_size(10, row_counts, heap_sizes).unwrap_or(0);
    let parent_size = dotnet_coded_index_size(DotnetCodedIndexKind::MemberRefParent, row_counts);
    let string_index_size = dotnet_heap_index_size(heap_sizes, 0x01);
    let blob_index_size = dotnet_heap_index_size(heap_sizes, 0x04);
    let declared_rows = row_counts[10] as usize;
    let mut records = Vec::new();
    for row in 1..=declared_rows.min(DOTNET_MEMBER_REF_LIMIT) {
        let mut cursor = DotnetTableCursor::new(bytes, base_offset + (row - 1) * row_size);
        let class_raw = cursor.read_index(parent_size, "MemberRef.Class")?;
        let name_index = cursor.read_index(string_index_size, "MemberRef.Name")?;
        let signature = cursor.read_index(blob_index_size, "MemberRef.Signature")?;
        let class = dotnet_decode_coded_index(class_raw, DotnetCodedIndexKind::MemberRefParent);
        let name = dotnet_string_or_placeholder(strings_heap, name_index);
        let parent = dotnet_resolve_member_parent(&class, type_defs, type_refs, method_defs);
        let qualified_name = parent
            .as_ref()
            .map(|parent| format!("{parent}.{name}"))
            .unwrap_or_else(|| name.clone());
        records.push(DotnetMemberRefRecord {
            row: row as u32,
            class,
            parent,
            name,
            signature,
            qualified_name,
        });
    }
    if declared_rows > DOTNET_MEMBER_REF_LIMIT {
        warnings.push(format!(
            ".NET MemberRef table listing truncated at {DOTNET_MEMBER_REF_LIMIT} of {declared_rows} rows"
        ));
    }
    Ok(records)
}

fn parse_dotnet_assemblies(
    bytes: &[u8],
    table_offsets: &[Option<usize>; 64],
    row_counts: &[u32; 64],
    heap_sizes: u8,
    strings_heap: &[u8],
    table_id: usize,
    limit: usize,
    warnings: &mut Vec<String>,
) -> Result<Vec<DotnetAssemblyRecord>> {
    let Some(base_offset) = table_offsets[table_id] else {
        return Ok(Vec::new());
    };
    let row_size = dotnet_table_row_size(table_id as u8, row_counts, heap_sizes).unwrap_or(0);
    let string_index_size = dotnet_heap_index_size(heap_sizes, 0x01);
    let blob_index_size = dotnet_heap_index_size(heap_sizes, 0x04);
    let declared_rows = row_counts[table_id] as usize;
    let mut records = Vec::new();
    for row in 1..=declared_rows.min(limit) {
        let mut cursor = DotnetTableCursor::new(bytes, base_offset + (row - 1) * row_size);
        if table_id == 32 {
            let hash_alg_id = cursor.read_u32("Assembly.HashAlgId")?;
            let major_version = cursor.read_u16("Assembly.MajorVersion")?;
            let minor_version = cursor.read_u16("Assembly.MinorVersion")?;
            let build_number = cursor.read_u16("Assembly.BuildNumber")?;
            let revision_number = cursor.read_u16("Assembly.RevisionNumber")?;
            let flags = cursor.read_u32("Assembly.Flags")?;
            let public_key = cursor.read_index(blob_index_size, "Assembly.PublicKey")?;
            let name_index = cursor.read_index(string_index_size, "Assembly.Name")?;
            let culture_index = cursor.read_index(string_index_size, "Assembly.Culture")?;
            let name = dotnet_string_or_placeholder(strings_heap, name_index);
            records.push(DotnetAssemblyRecord {
                row: row as u32,
                name,
                culture: dotnet_get_string(strings_heap, culture_index),
                hash_alg_id: Some(hash_alg_id),
                major_version,
                minor_version,
                build_number,
                revision_number,
                flags,
                public_key_or_token: public_key,
                hash_value: None,
            });
        } else {
            let major_version = cursor.read_u16("AssemblyRef.MajorVersion")?;
            let minor_version = cursor.read_u16("AssemblyRef.MinorVersion")?;
            let build_number = cursor.read_u16("AssemblyRef.BuildNumber")?;
            let revision_number = cursor.read_u16("AssemblyRef.RevisionNumber")?;
            let flags = cursor.read_u32("AssemblyRef.Flags")?;
            let public_key_or_token =
                cursor.read_index(blob_index_size, "AssemblyRef.PublicKeyOrToken")?;
            let name_index = cursor.read_index(string_index_size, "AssemblyRef.Name")?;
            let culture_index = cursor.read_index(string_index_size, "AssemblyRef.Culture")?;
            let hash_value = cursor.read_index(blob_index_size, "AssemblyRef.HashValue")?;
            let name = dotnet_string_or_placeholder(strings_heap, name_index);
            records.push(DotnetAssemblyRecord {
                row: row as u32,
                name,
                culture: dotnet_get_string(strings_heap, culture_index),
                hash_alg_id: None,
                major_version,
                minor_version,
                build_number,
                revision_number,
                flags,
                public_key_or_token,
                hash_value: Some(hash_value),
            });
        }
    }
    if declared_rows > limit {
        warnings.push(format!(
            ".NET {} table listing truncated at {limit} of {declared_rows} rows",
            dotnet_metadata_table_name(table_id as u8)
        ));
    }
    Ok(records)
}

fn parse_dotnet_manifest_resources(
    bytes: &[u8],
    table_offsets: &[Option<usize>; 64],
    row_counts: &[u32; 64],
    heap_sizes: u8,
    strings_heap: &[u8],
    warnings: &mut Vec<String>,
) -> Result<Vec<DotnetManifestResourceRecord>> {
    let Some(base_offset) = table_offsets[40] else {
        return Ok(Vec::new());
    };
    let row_size = dotnet_table_row_size(40, row_counts, heap_sizes).unwrap_or(0);
    let string_index_size = dotnet_heap_index_size(heap_sizes, 0x01);
    let impl_size = dotnet_coded_index_size(DotnetCodedIndexKind::Implementation, row_counts);
    let declared_rows = row_counts[40] as usize;
    let mut records = Vec::new();
    for row in 1..=declared_rows.min(DOTNET_MANIFEST_RESOURCE_LIMIT) {
        let mut cursor = DotnetTableCursor::new(bytes, base_offset + (row - 1) * row_size);
        let offset = cursor.read_u32("ManifestResource.Offset")?;
        let flags = cursor.read_u32("ManifestResource.Flags")?;
        let name_index = cursor.read_index(string_index_size, "ManifestResource.Name")?;
        let implementation_raw =
            cursor.read_index(impl_size, "ManifestResource.Implementation")?;
        let implementation =
            dotnet_decode_coded_index(implementation_raw, DotnetCodedIndexKind::Implementation);
        let name = dotnet_string_or_placeholder(strings_heap, name_index);
        let is_embedded = implementation.index == 0 || implementation.raw == 0;
        records.push(DotnetManifestResourceRecord {
            row: row as u32,
            offset,
            flags,
            name,
            implementation,
            is_embedded,
        });
    }
    if declared_rows > DOTNET_MANIFEST_RESOURCE_LIMIT {
        warnings.push(format!(
            ".NET ManifestResource table listing truncated at {DOTNET_MANIFEST_RESOURCE_LIMIT} of {declared_rows} rows"
        ));
    }
    Ok(records)
}

